// ── A. Pivot detection (fractal highs/lows) ──
function detectPivotLevels(candles, left = STRUCTURE_CONFIG.pivotLookbackLeft, right = STRUCTURE_CONFIG.pivotLookbackRight) {
  const highs = [];
  const lows  = [];
  if (!candles || candles.length < left + right + 1) return { pivotHighs: highs, pivotLows: lows };
  const slice = candles.slice(-STRUCTURE_CONFIG.pivotLookbackCandles);
  for (let i = left; i < slice.length - right; i++) {
    const c = slice[i];
    let isPH = true, isPL = true;
    for (let k = 1; k <= left && (isPH || isPL); k++) {
      if (slice[i - k].high >= c.high) isPH = false;
      if (slice[i - k].low  <= c.low)  isPL = false;
    }
    for (let k = 1; k <= right && (isPH || isPL); k++) {
      if (slice[i + k].high >= c.high) isPH = false;
      if (slice[i + k].low  <= c.low)  isPL = false;
    }
    if (isPH) highs.push({ price: c.high, idx: i });
    if (isPL) lows.push({  price: c.low,  idx: i });
  }
  return { pivotHighs: highs, pivotLows: lows };
}

// ── B. Cluster nearby pivots into zones (not lines) ──
function clusterZones(pivots, type, refPrice, atrValue) {
  if (!pivots || pivots.length === 0) return [];
  const threshold = STRUCTURE_CONFIG.useATRZoneWidth
    ? (atrValue || 1) * STRUCTURE_CONFIG.zoneATRMultiplier
    : refPrice * STRUCTURE_CONFIG.zoneMergeThresholdPct;
  const sorted = [...pivots].sort((a, b) => a.price - b.price);
  const zones = [];
  let cur = { low: sorted[0].price, high: sorted[0].price, touches: 1, lastIdx: sorted[0].idx };
  for (let i = 1; i < sorted.length; i++) {
    const p = sorted[i];
    if (p.price - cur.high <= threshold) {
      cur.high    = Math.max(cur.high, p.price);
      cur.touches += 1;
      cur.lastIdx = Math.max(cur.lastIdx, p.idx);
    } else {
      zones.push(cur);
      cur = { low: p.price, high: p.price, touches: 1, lastIdx: p.idx };
    }
  }
  zones.push(cur);
  return zones.map(z => ({
    type,
    zoneLow:  +z.low.toFixed(2),
    zoneHigh: +z.high.toFixed(2),
    mid:      +((z.low + z.high) / 2).toFixed(2),
    touches:  z.touches,
    lastTouchIdx: z.lastIdx,
  }));
}

// ── C. Score zones (touches + recency + rejection strength) ──
function scoreZones(zones, candles, type) {
  const maxIdx = candles.length - 1;
  return zones.map(z => {
    const ageCandles  = Math.max(0, maxIdx - z.lastTouchIdx);
    const recencyScore = Math.max(0, 1 - (ageCandles / 60));
    let rejections = 0;
    for (const c of candles) {
      if (type === 'resistance') {
        if (c.high >= z.zoneLow && c.close < z.zoneLow) rejections++;
      } else {
        if (c.low  <= z.zoneHigh && c.close > z.zoneHigh) rejections++;
      }
    }
    const strengthScore = +(z.touches * 1.5 + recencyScore * 3 + rejections * 0.5).toFixed(2);
    let strengthLabel = 'LOW';
    if (strengthScore >= 6)       strengthLabel = 'HIGH';
    else if (strengthScore >= 3.5) strengthLabel = 'MEDIUM';
    return { ...z, rejections, recencyScore: +recencyScore.toFixed(2), strengthScore, strengthLabel };
  });
}

// ── D. Session VWAP (intraday, last trading day only) ──
function computeSessionVWAP(candles) {
  if (!candles || candles.length === 0) return null;
  const last = candles[candles.length - 1];
  const lastDate = (last.date instanceof Date ? last.date : new Date(last.date)).toISOString().split('T')[0];
  const today = candles.filter(c => {
    const d = (c.date instanceof Date ? c.date : new Date(c.date)).toISOString().split('T')[0];
    return d === lastDate;
  });
  if (today.length === 0) return null;
  let cumPV = 0, cumV = 0;
  const vwaps = [];
  for (const c of today) {
    const tp = (c.high + c.low + c.close) / 3;
    const v  = c.volume || 1;
    cumPV += tp * v;
    cumV  += v;
    vwaps.push(cumPV / cumV);
  }
  const current = vwaps[vwaps.length - 1];
  const slope   = vwaps.length > 5 ? current - vwaps[vwaps.length - 5] : 0;
  return { current: +current.toFixed(2), slope: +slope.toFixed(3) };
}

// ── E. Previous day levels (PDH/PDL/PDC) derived from 5-min intraday history ──
function computePreviousDayLevels(candles) {
  if (!candles || candles.length < 2) return null;
  const byDate = {};
  for (const c of candles) {
    const d = (c.date instanceof Date ? c.date : new Date(c.date)).toISOString().split('T')[0];
    if (!byDate[d]) byDate[d] = { high: c.high, low: c.low, close: c.close };
    else {
      byDate[d].high  = Math.max(byDate[d].high, c.high);
      byDate[d].low   = Math.min(byDate[d].low,  c.low);
      byDate[d].close = c.close; // last seen
    }
  }
  const dates = Object.keys(byDate).sort();
  if (dates.length < 2) return null;
  const prev = byDate[dates[dates.length - 2]];
  return { pdh: +prev.high.toFixed(2), pdl: +prev.low.toFixed(2), pdc: +prev.close.toFixed(2) };
}

// ── F. Full per-candidate structure analysis ──
function analyzeCandidateStructure(symbol, candles, entryPrice, atrValue) {
  if (!candles || candles.length < 20) return null;

  const { pivotHighs, pivotLows } = detectPivotLevels(candles);
  const resZonesRaw = clusterZones(pivotHighs, 'resistance', entryPrice, atrValue);
  const supZonesRaw = clusterZones(pivotLows,  'support',    entryPrice, atrValue);
  const resZones = scoreZones(resZonesRaw, candles, 'resistance')
    .sort((a, b) => b.strengthScore - a.strengthScore)
    .slice(0, STRUCTURE_CONFIG.maxZonesPerSide);
  const supZones = scoreZones(supZonesRaw, candles, 'support')
    .sort((a, b) => b.strengthScore - a.strengthScore)
    .slice(0, STRUCTURE_CONFIG.maxZonesPerSide);

  // Nearest resistance ABOVE entry; nearest support BELOW entry
  const nearestResistance = resZones
    .filter(z => z.zoneHigh > entryPrice)
    .sort((a, b) => (a.zoneLow - entryPrice) - (b.zoneLow - entryPrice))[0] || null;
  const nearestSupport = supZones
    .filter(z => z.zoneLow < entryPrice)
    .sort((a, b) => (entryPrice - b.zoneHigh) - (entryPrice - a.zoneHigh))[0] || null;

  const distToRPct = nearestResistance
    ? +(((nearestResistance.zoneLow - entryPrice) / entryPrice) * 100).toFixed(2)
    : null;
  const distToSPct = nearestSupport
    ? +(((entryPrice - nearestSupport.zoneHigh) / entryPrice) * 100).toFixed(2)
    : null;

  // VWAP
  const vwapData = computeSessionVWAP(candles);
  const priceAboveVWAP = vwapData ? entryPrice > vwapData.current : null;
  const distFromVWAPPct = vwapData
    ? +(((entryPrice - vwapData.current) / vwapData.current) * 100).toFixed(2)
    : null;
  const vwapBias = vwapData
    ? (priceAboveVWAP ? 'SUPPORT' : 'RESISTANCE')
    : 'NEUTRAL';

  // Previous day levels
  const pd = computePreviousDayLevels(candles);
  const nearPDH = pd ? Math.abs((entryPrice - pd.pdh) / entryPrice) * 100 < 0.5 : false;
  const nearPDL = pd ? Math.abs((entryPrice - pd.pdl) / entryPrice) * 100 < 0.5 : false;
  const nearPDC = pd ? Math.abs((entryPrice - pd.pdc) / entryPrice) * 100 < 0.5 : false;
  const abovePDH = pd ? entryPrice > pd.pdh : false;

  // Volume ratio (last candle vs 20-avg)
  const last = candles[candles.length - 1];
  const vols = candles.slice(-20).map(c => c.volume || 0);
  const avgVol = vols.reduce((a, b) => a + b, 0) / (vols.length || 1);
  const volumeRatio = avgVol > 0 ? +((last.volume || 0) / avgVol).toFixed(2) : 1;

  // Derived flags
  const nearResistance = !!(nearestResistance
    && distToRPct !== null
    && distToRPct < STRUCTURE_CONFIG.nearZoneThresholdPct
    && (nearestResistance.strengthLabel === 'HIGH' || nearestResistance.strengthLabel === 'MEDIUM'));

  const nearSupport = !!(nearestSupport
    && distToSPct !== null
    && distToSPct < STRUCTURE_CONFIG.nearZoneThresholdPct
    && (nearestSupport.strengthLabel === 'HIGH' || nearestSupport.strengthLabel === 'MEDIUM'));

  const breakoutAboveResistance = !!(nearestResistance && entryPrice > nearestResistance.zoneHigh);

  // Breakout INTO resistance: entry price sits inside a strong overhead zone
  const breakoutIntoResistance = !!(nearestResistance
    && entryPrice >= nearestResistance.zoneLow
    && entryPrice <= nearestResistance.zoneHigh
    && (nearestResistance.strengthLabel === 'HIGH' || nearestResistance.strengthLabel === 'MEDIUM'));

  // Trapped: both a near resistance and a near support simultaneously
  const trappedBetweenZones = !!(nearestResistance && nearestSupport
    && distToRPct !== null && distToSPct !== null
    && distToRPct < 1.5 && distToSPct < 1.5
    && !breakoutAboveResistance);

  // Stacked resistance: ≥2 resistance zones within 2% overhead
  const stackedResistance = resZones.filter(z =>
    z.zoneLow > entryPrice && ((z.zoneLow - entryPrice) / entryPrice) * 100 < 2.0
  ).length >= 2;

  return {
    symbol,
    entryPrice: +entryPrice.toFixed(2),
    nearestResistance: nearestResistance ? {
      zoneLow:       nearestResistance.zoneLow,
      zoneHigh:      nearestResistance.zoneHigh,
      touches:       nearestResistance.touches,
      strengthScore: nearestResistance.strengthScore,
      strengthLabel: nearestResistance.strengthLabel,
      distancePct:   distToRPct,
    } : null,
    nearestSupport: nearestSupport ? {
      zoneLow:       nearestSupport.zoneLow,
      zoneHigh:      nearestSupport.zoneHigh,
      touches:       nearestSupport.touches,
      strengthScore: nearestSupport.strengthScore,
      strengthLabel: nearestSupport.strengthLabel,
      distancePct:   distToSPct,
    } : null,
    vwap:            vwapData ? { current: vwapData.current, slope: vwapData.slope, bias: vwapBias } : null,
    pdLevels:        pd,
    volumeRatio,
    allResistanceZones: resZones,
    allSupportZones:    supZones,
    flags: {
      nearResistance,
      nearSupport,
      breakoutAboveResistance,
      breakoutIntoResistance,
      trappedBetweenZones,
      stackedResistance,
      priceAboveVWAP: !!priceAboveVWAP,
      distanceFromVWAPPct: distFromVWAPPct,
      nearPDH, nearPDL, nearPDC, abovePDH,
    },
  };
}

// ── G. Score adjustment + hard reject rules ──
function adjustCandidateScoreFromStructure(candidate, structure) {
  const baseScore = candidate.result.score;
  if (!structure) {
    return { rejected: false, reason: null, scoreBefore: baseScore, scoreAfter: baseScore, adjustments: ['no_structure_data'] };
  }
  const f = structure.flags;
  const regime = candidate.result.regime;
  const adjustments = [];
  let score = baseScore;

  // ── Hard reject rules ──
  const resLabel = structure.nearestResistance?.strengthLabel;
  if (structure.nearestResistance
      && structure.nearestResistance.distancePct !== null
      && structure.nearestResistance.distancePct < STRUCTURE_CONFIG.rejectIfResistanceWithinPct
      && (resLabel === 'HIGH' || resLabel === 'MEDIUM')
      && !f.breakoutAboveResistance) {
    return { rejected: true, reason: `R ${structure.nearestResistance.distancePct}% overhead (${resLabel})`, scoreBefore: baseScore, scoreAfter: baseScore, adjustments: [] };
  }
  if (f.breakoutIntoResistance) {
    return { rejected: true, reason: 'entry inside resistance zone', scoreBefore: baseScore, scoreAfter: baseScore, adjustments: [] };
  }
  if (f.trappedBetweenZones) {
    return { rejected: true, reason: 'trapped between S/R', scoreBefore: baseScore, scoreAfter: baseScore, adjustments: [] };
  }
  if (!f.priceAboveVWAP && (regime === 'MOMENTUM' || regime === 'BREAKOUT')) {
    return { rejected: true, reason: `below VWAP in ${regime}`, scoreBefore: baseScore, scoreAfter: baseScore, adjustments: [] };
  }
  if (f.nearPDH && !f.abovePDH) {
    return { rejected: true, reason: 'at PDH w/o breakout', scoreBefore: baseScore, scoreAfter: baseScore, adjustments: [] };
  }
  if (f.stackedResistance && !f.breakoutAboveResistance) {
    return { rejected: true, reason: 'stacked resistance overhead', scoreBefore: baseScore, scoreAfter: baseScore, adjustments: [] };
  }

  // ── Score boosts ──
  if (f.breakoutAboveResistance && structure.volumeRatio >= 1.5 && STRUCTURE_CONFIG.boostIfBreakoutAboveResistance) {
    score += 0.8; adjustments.push('+0.8 breakout+vol');
  }
  if (f.nearSupport && !f.nearResistance && STRUCTURE_CONFIG.boostIfSupportBounce) {
    score += 0.5; adjustments.push('+0.5 support bounce');
  }
  if (f.priceAboveVWAP && structure.vwap && structure.vwap.slope > 0) {
    score += 0.3; adjustments.push('+0.3 VWAP slope up');
  }
  if (f.abovePDH && structure.volumeRatio >= 1.5) {
    score += 0.5; adjustments.push('+0.5 above PDH w/ vol');
  }

  // ── Score reductions ──
  if (f.nearResistance) {
    score -= 0.5; adjustments.push('-0.5 near R');
  }
  if (!structure.nearestSupport) {
    score -= 0.3; adjustments.push('-0.3 no visible S');
  }
  if (STRUCTURE_CONFIG.reduceIfFarFromVWAP
      && f.distanceFromVWAPPct !== null
      && Math.abs(f.distanceFromVWAPPct) > STRUCTURE_CONFIG.farFromVWAPPct) {
    score -= 0.4; adjustments.push('-0.4 stretched from VWAP');
  }
  if (structure.nearestResistance && structure.nearestSupport) {
    const dR = structure.nearestResistance.distancePct || 0;
    const dS = structure.nearestSupport.distancePct || 0;
    if (Math.abs(dR - dS) < 0.3 && dR > 0.5 && dS > 0.5) {
      score -= 0.3; adjustments.push('-0.3 middle of range');
    }
  }

  return { rejected: false, reason: null, scoreBefore: +baseScore.toFixed(2), scoreAfter: +score.toFixed(2), adjustments };
}

// ── H. LLM shortlist: only top N with adjusted score ≥ threshold ──
function shortlistCandidatesForLLM(candidates) {
  return candidates
    .filter(c => !c.rejected && (c.adjustedScore ?? c.result.score) >= STRUCTURE_CONFIG.llmMinScoreThreshold)
    .sort((a, b) => (b.adjustedScore ?? b.result.score) - (a.adjustedScore ?? a.result.score))
    .slice(0, STRUCTURE_CONFIG.llmTopCandidatesPerScan);
}

// ── I. LLM reviewer (OpenAI-compatible chat completions) ──
const _llmDecisionCache = new Map();
// Small in-module helper — fetch a few recent headlines from the existing
// RSS-based /api/news pipeline. Used only when llmNewsEnabled=true. Never
// throws — returns [] on any failure.
const _newsCache = new Map(); // sym -> { expires, items }
// ─── Phase 3 · Part 5 — News quality filter ──────────────────────────────
// Applied after /api/news returns raw items and before they go to the LLM.
// Removes duplicates, stale items, off-symbol noise, and non-whitelisted
// sources. Degrades gracefully if any metadata is missing.
// ──────────────────────────────────────────────────────────────────────────
function _normalizeHeadline(s) {
  return (s || '').toLowerCase().replace(/[^a-z0-9 ]/g, ' ').replace(/\s+/g, ' ').trim();
}
function _itemAgeHours(it) {
  // Prefer explicit timestamp; fall back to timeAgo string like "3h ago"
  if (it.publishedAt) {
    const t = new Date(it.publishedAt).getTime();
    if (Number.isFinite(t)) return (Date.now() - t) / 3600000;
  }
  const m = /(\d+)\s*(m|h|d)/i.exec(it.timeAgo || '');
  if (!m) return null;
  const n = +m[1];
  if (m[2].toLowerCase() === 'm') return n / 60;
  if (m[2].toLowerCase() === 'h') return n;
  if (m[2].toLowerCase() === 'd') return n * 24;
  return null;
}
function _sourceOk(it, whitelist) {
  if (!whitelist || !whitelist.length) return true;
  const src = (it.source || it.provider || it.domain || '').toLowerCase();
  if (!src) return true; // unknown source — don't drop blindly
  return whitelist.some(w => src.includes(w));
}
function _symbolMatches(it, sym, name) {
  const h = _normalizeHeadline(it.headline);
  if (!h) return false;
  const s = (sym || '').toLowerCase();
  if (s && h.includes(s)) return true;
  // Relax to first word of company name ("Reliance", "Infosys", ...)
  const firstWord = (name || '').split(/\s+/)[0];
  if (firstWord && firstWord.length >= 4 && h.includes(firstWord.toLowerCase())) return true;
  return false;
}
function filterHeadlinesForQuality(items, sym, name) {
  if (!STRUCTURE_CONFIG.newsQualityFilterEnabled) return items;
  const freshH  = +STRUCTURE_CONFIG.newsFreshnessHours || 24;
  const wl      = STRUCTURE_CONFIG.newsSourceWhitelist || [];
  const seen    = new Set();
  const out     = [];
  for (const raw of items || []) {
    if (!raw || !raw.headline) continue;
    const key = _normalizeHeadline(raw.headline);
    if (!key || seen.has(key)) continue;       // dedup
    const age = _itemAgeHours(raw);
    if (age != null && age > freshH) continue;  // freshness
    if (!_sourceOk(raw, wl)) continue;          // source whitelist
    if (!_symbolMatches(raw, sym, name)) continue; // symbol relevance
    seen.add(key);
    out.push(raw);
  }
  return out;
}

async function fetchHeadlinesForSymbol(sym, limit, stockMeta) {
  const now = Date.now();
  const cached = _newsCache.get(sym);
  if (cached && cached.expires > now) return cached.items.slice(0, limit);
  try {
    const port = process.env.PORT || 3001;
    const base = process.env.INTERNAL_BASE_URL || `http://127.0.0.1:${port}`;
    const r = await fetch(`${base}/api/news?sym=${encodeURIComponent(sym)}`).catch(() => null);
    if (!r || !r.ok) return [];
    const raw = await r.json().catch(() => []);
    const rawArr = Array.isArray(raw) ? raw : [];
    // Apply quality filter (dedup/freshness/source/symbol match)
    const filtered = filterHeadlinesForQuality(rawArr, sym, stockMeta?.n || stockMeta?.name);
    const slim = filtered
      .slice(0, 10)
      .map(it => ({
        headline:  (it.headline || '').slice(0, 140),
        sentiment: it.sentiment || 'neutral',
        source:    it.source || it.provider || '',
        timeAgo:   it.timeAgo || '',
      }));
    _newsCache.set(sym, { expires: now + 10 * 60 * 1000, items: slim });
    return slim.slice(0, limit);
  } catch (e) {
    return [];
  }
}

async function reviewCandidateWithLLM(candidate, structure) {
  if (!STRUCTURE_CONFIG.llmFilterEnabled) {
    return { decision: 'APPROVE', confidence: 1, setupQuality: 'N/A', riskFlag: 'LOW', positionSizeMultiplier: 1, comment: 'LLM disabled', skipped: true };
  }
  const sym = candidate.stock.sym;
  const cached = _llmDecisionCache.get(sym);
  if (cached && cached.expires > Date.now()) {
    return { ...cached.decision, cached: true };
  }
  const apiKey = process.env.LLM_FILTER_API_KEY || process.env.OPENAI_API_KEY;
  const model  = process.env.LLM_FILTER_MODEL   || 'gpt-4o-mini';
  const url    = process.env.LLM_FILTER_URL     || 'https://api.openai.com/v1/chat/completions';
  if (!apiKey) {
    return { decision: 'APPROVE', confidence: 1, setupQuality: 'N/A', riskFlag: 'LOW', positionSizeMultiplier: 1, comment: 'no LLM key', skipped: true };
  }

  // Optionally attach recent headlines for headline-risk awareness
  let newsItems = [];
  if (STRUCTURE_CONFIG.llmNewsEnabled) {
    try {
      newsItems = await fetchHeadlinesForSymbol(
        sym,
        STRUCTURE_CONFIG.llmNewsHeadlineCount || 4,
        candidate.stock
      );
    } catch(e) { newsItems = []; }
  }

  const compactInput = {
    symbol:               sym,
    strategy:             candidate.result.strategy,
    regime:               candidate.result.regime,
    entryPrice:           structure.entryPrice,
    score:                candidate.adjustedScore ?? candidate.result.score,
    volumeRatio:          structure.volumeRatio,
    priceAboveVWAP:       structure.flags.priceAboveVWAP,
    distanceFromVWAPPct:  structure.flags.distanceFromVWAPPct,
    nearestResistance:    structure.nearestResistance,
    nearestSupport:       structure.nearestSupport,
    pdLevels:             structure.pdLevels,
    flags: {
      breakoutAboveResistance: structure.flags.breakoutAboveResistance,
      breakoutIntoResistance:  structure.flags.breakoutIntoResistance,
      trappedBetweenZones:     structure.flags.trappedBetweenZones,
      nearPDH:                 structure.flags.nearPDH,
      abovePDH:                structure.flags.abovePDH,
      stackedResistance:       structure.flags.stackedResistance,
    },
    news:  STRUCTURE_CONFIG.llmNewsEnabled ? newsItems.map(n => n.headline) : undefined,
  };

  const baseSystemPrompt = 'You are a trading setup reviewer. A rules-based engine has already found a candidate. You do not invent trades. You only review quality and reject weak or extended setups. Return valid JSON only with keys: decision (APPROVE|REJECT|CAUTION), confidence (0..1), setupQuality (STRONG|MEDIUM|WEAK), riskFlag (LOW|MEDIUM|HIGH), positionSizeMultiplier (0.5..1.0), comment (short). Prefer rejecting weak trades over forcing approval.';
  const newsSystemAddition = ' You are also given up to 5 recent news headlines for the stock. Also return newsRisk (LOW|MEDIUM|HIGH): HIGH if headlines contradict the technical setup or indicate material risk (regulatory, fraud, earnings miss, downgrade, lawsuit, governance issue), MEDIUM if mixed or uncertain, LOW otherwise. If newsRisk is HIGH, set decision=REJECT.';
  const systemPrompt = STRUCTURE_CONFIG.llmNewsEnabled
    ? baseSystemPrompt + newsSystemAddition
    : baseSystemPrompt;

  try {
    const controller = new AbortController();
    const timeoutId  = setTimeout(() => controller.abort(), 8000);
    const resp = await fetch(url, {
      method: 'POST',
      headers: {
        'Content-Type':  'application/json',
        'Authorization': `Bearer ${apiKey}`,
      },
      body: JSON.stringify({
        model,
        messages: [
          { role: 'system', content: systemPrompt },
          { role: 'user',   content: JSON.stringify(compactInput) },
        ],
        temperature: 0.2,
        response_format: { type: 'json_object' },
      }),
      signal: controller.signal,
    });
    clearTimeout(timeoutId);
    if (!resp.ok) throw new Error(`LLM HTTP ${resp.status}`);
    const data = await resp.json();
    const content = data.choices?.[0]?.message?.content || '{}';
    const parsed = JSON.parse(content);
    const decision = {
      decision:               ['APPROVE','REJECT','CAUTION'].includes(parsed.decision) ? parsed.decision : 'CAUTION',
      confidence:             typeof parsed.confidence === 'number' ? Math.max(0, Math.min(1, parsed.confidence)) : 0.5,
      setupQuality:           ['STRONG','MEDIUM','WEAK'].includes(parsed.setupQuality) ? parsed.setupQuality : 'MEDIUM',
      riskFlag:               ['LOW','MEDIUM','HIGH'].includes(parsed.riskFlag) ? parsed.riskFlag : 'MEDIUM',
      newsRisk:               STRUCTURE_CONFIG.llmNewsEnabled && ['LOW','MEDIUM','HIGH'].includes(parsed.newsRisk)
                                ? parsed.newsRisk
                                : null,
      positionSizeMultiplier: typeof parsed.positionSizeMultiplier === 'number'
        ? Math.min(1, Math.max(0.5, parsed.positionSizeMultiplier))
        : 1,
      comment:                (parsed.comment || '').toString().slice(0, 200),
      newsCount:              STRUCTURE_CONFIG.llmNewsEnabled ? newsItems.length : 0,
    };
    _llmDecisionCache.set(sym, {
      decision,
      expires: Date.now() + STRUCTURE_CONFIG.llmDecisionCacheMinutes * 60 * 1000,
    });
    return decision;
  } catch(e) {
    console.log(`  ⚠ LLM filter error ${sym}: ${e.message}`);
    return { decision: 'APPROVE', confidence: 0.5, setupQuality: 'UNKNOWN', riskFlag: 'MEDIUM', positionSizeMultiplier: 1, comment: `err: ${e.message}`, error: true };
  }
}

// ── J. Final decision assembly (structure + LLM → final) ──
//
// Produces a unified decision object on the candidate in this shape:
//   {
//     symbol, originalScore, adjustedScore,
//     structureDecision: 'APPROVE'|'REJECT',
//     llmDecision:       'APPROVE'|'REJECT'|'CAUTION'|null,
//     finalDecision:     'APPROVED'|'REJECTED',
//     rejectReason:      string|null,
//     confidence:        0..1
//   }
//
// Rule: hard risk rules (structure reject, near strong resistance, trapped)
// always win — the LLM can only reject or downgrade, never promote a
// rules-rejected candidate into approved.
function applyFinalCandidateDecision(candidate) {
  const origScore = +(+candidate.result.score).toFixed(2);
  const adjScore  = +(+(candidate.adjustedScore ?? candidate.result.score)).toFixed(2);
  const struct    = candidate.structure || null;
  const llm       = candidate.llmDecision || null;

  // Structure decision always primary
  const structureDecision = candidate.rejected ? 'REJECT' : 'APPROVE';

  // Confidence blend: start from normalized score, boost/cut from structure +
  // LLM signals. Stays in [0,1].
  const baseConf = Math.min(1, Math.max(0, (adjScore - 1.5) / 4.0));
  let confidence = baseConf;
  if (struct) {
    if (struct.flags?.breakoutAboveResistance)       confidence += 0.10;
    if (struct.flags?.nearSupport)                   confidence += 0.05;
    if (struct.flags?.abovePDH)                      confidence += 0.05;
    if (struct.flags?.priceAboveVWAP)                confidence += 0.03;
    if (struct.flags?.trappedBetweenZones)           confidence -= 0.15;
    if (struct.flags?.stackedResistance)             confidence -= 0.10;
    if (struct.flags?.nearResistance)                confidence -= 0.05;
  }
  if (llm && !llm.skipped) {
    if      (llm.decision === 'APPROVE') confidence += 0.15 * (llm.confidence ?? 0.5);
    else if (llm.decision === 'CAUTION') confidence -= 0.10;
    else if (llm.decision === 'REJECT')  confidence -= 0.30;
  }
  if (llm?.newsRisk === 'HIGH')   confidence -= 0.15;
  if (llm?.newsRisk === 'MEDIUM') confidence -= 0.05;
  confidence = +Math.min(1, Math.max(0, confidence)).toFixed(2);

  // 1) Structure reject — hard rule, LLM can never override
  if (candidate.rejected) {
    candidate.finalDecision = 'REJECTED';
    candidate.finalReason   = candidate.rejectReason || 'structure filter';
    candidate.decisionObject = {
      symbol:            candidate.stock.sym,
      originalScore:     origScore,
      adjustedScore:     adjScore,
      structureDecision: 'REJECT',
      llmDecision:       llm?.decision || null,
      finalDecision:     'REJECTED',
      rejectReason:      candidate.rejectReason || 'structure filter',
      confidence,
    };
    return candidate;
  }

  // 2) LLM REJECT — allowed (can only reject, never promote)
  if (llm && llm.decision === 'REJECT') {
    candidate.finalDecision = 'REJECTED';
    candidate.finalReason   = `LLM: ${llm.comment || 'rejected'}`;
    candidate.rejected      = true;
    candidate.rejectReason  = candidate.rejectReason || `LLM_${(llm.comment || 'reject').slice(0, 30)}`;
    candidate.decisionObject = {
      symbol:            candidate.stock.sym,
      originalScore:     origScore,
      adjustedScore:     adjScore,
      structureDecision: 'APPROVE',
      llmDecision:       'REJECT',
      finalDecision:     'REJECTED',
      rejectReason:      candidate.rejectReason,
      confidence,
    };
    return candidate;
  }

  // 3) News risk HIGH — reject if configured (Part 2)
  if (STRUCTURE_CONFIG.llmNewsEnabled && llm?.newsRisk === 'HIGH') {
    candidate.finalDecision = 'REJECTED';
    candidate.finalReason   = `NEWS_HIGH_RISK`;
    candidate.rejected      = true;
    candidate.rejectReason  = 'NEWS_HIGH_RISK';
    candidate.decisionObject = {
      symbol:            candidate.stock.sym,
      originalScore:     origScore,
      adjustedScore:     adjScore,
      structureDecision: 'APPROVE',
      llmDecision:       llm.decision,
      finalDecision:     'REJECTED',
      rejectReason:      'NEWS_HIGH_RISK',
      confidence,
    };
    return candidate;
  }

  // 4) LLM CAUTION — mild score reduction but still allowed
  if (llm && llm.decision === 'CAUTION') {
    candidate.adjustedScore = +((candidate.adjustedScore ?? candidate.result.score) - 0.3).toFixed(2);
  }

  candidate.finalDecision = 'APPROVED';
  candidate.finalReason   = null;
  candidate.decisionObject = {
    symbol:            candidate.stock.sym,
    originalScore:     origScore,
    adjustedScore:     +(+candidate.adjustedScore || adjScore).toFixed(2),
    structureDecision: 'APPROVE',
    llmDecision:       llm?.decision || null,
    finalDecision:     'APPROVED',
    rejectReason:      null,
    confidence,
  };
  return candidate;
}

async function scanAndTrade() {
  if (!process.env.KITE_ACCESS_TOKEN||!kite){console.log("No token");return;}
  if (!isMarketOpen()){console.log("Market closed");return;}

  // Phase 3 · Part 8 — scan latency monitoring
  const _scanStartedAt = Date.now();
  let   _scanDataWarnings = 0;
  const _scanApiFailures  = [];

  const scanTime = new Date().toLocaleTimeString("en-IN");
  console.log(`\n⟳ Smart scan at ${scanTime}...`);

  // Refresh live account equity from Kite (cached 5min)
  await getLiveAccountEquity();

  const { rows: openTrades } = await pool.query("SELECT * FROM paper_trades WHERE status='OPEN'");
  let signalCount=0, dominantRegime="UNKNOWN", dominantStrategy="NONE";
  const regimeCounts={};

  // Phase 3: Check drawdown circuit breaker before scanning
  const ddStatus = await checkDrawdownCircuitBreaker();
  if (ddStatus.action === 'HALT') {
    console.log(`🛑 Trading halted — drawdown ${(ddStatus.drawdown*100).toFixed(1)}% exceeds ${CONFIG.DD_HALT_PCT*100}% limit`);
    return;
  }
  const sizeMult = ddStatus.action === 'REDUCE_SIZE' ? 0.5 : 1.0;
  const canEnterNew = ddStatus.action !== 'PAUSE' && ddStatus.action !== 'HALT';

  // Phase 3: Kelly-based risk sizing
  const kellyRisk = await computeKelly();

  // ╔══════════════════════════════════════════════════════════════════════╗
  // ║  PASS 1: Scan ALL stocks — manage exits immediately, collect BUY   ║
  // ║  candidates into a ranked queue. No entries happen in this pass.    ║
  // ╚══════════════════════════════════════════════════════════════════════╝
  const buyCandidates = []; // { stock, result, candles, last }

  for (const stock of UNIVERSE) {
    try {
      const token = validTokens[stock.sym] || INSTRUMENTS[stock.sym];
      if (!token){await delay(200);continue;}

      const today   = new Date().toISOString().split("T")[0];
      const weekAgo = new Date(Date.now()-7*24*60*60*1000).toISOString().split("T")[0];
      const candles = await kite.getHistoricalData(token,"5minute",weekAgo,today);
      if (!candles||candles.length<30){await delay(350);continue;}

      // Update live price cache
      const last = candles[candles.length-1];
      livePrices[stock.sym] = { price:last.close, open:last.open, high:last.high, low:last.low, volume:last.volume };

      // Daily candles for multi-timeframe confirmation
      const dailyF = stockFundamentals[stock.sym];
      const dailyTrend = dailyF ? (last.close > (dailyF.dma200||0) ? 'bullish' : 'bearish') : 'unknown';

      // Run smart strategy selection
      const result = selectAndRunStrategy(candles);

      // Multi-timeframe conviction adjustment — Varsity M2 Ch 18
      if (dailyTrend === 'bearish' && result.signal === 'BUY') {
        result.score = result.score * 0.7;
        result.detail = (result.detail||'') + ' [MTF: bearish daily trend reduces conviction]';
      }
      if (dailyTrend === 'bullish' && result.signal === 'BUY') {
        result.detail = (result.detail||'') + ' [MTF: daily bullish confirms]';
      }

      // Track dominant regime across all stocks
      regimeCounts[result.regime]=(regimeCounts[result.regime]||0)+1;

      const openPos = openTrades.find(t=>t.symbol===stock.sym&&t.status==='OPEN');

      // ── EXIT MANAGEMENT (immediate — can't wait for pass 2) ──
      if (openPos) {
        const cmp = last.close;
        const sl  = parseFloat(openPos.stop_loss);
        const tgt = parseFloat(openPos.target);
        const entryPrice = parseFloat(openPos.price);

        // Trailing stop — once 1 ATR in profit, trail at 1.5 ATR from high
        const highs = candles.slice(-14).map(c=>c.high);
        const lows  = candles.slice(-14).map(c=>c.low);
        const trs   = highs.map((h,i)=>h-lows[i]);
        const atr   = trs.reduce((a,b)=>a+b,0)/trs.length;
        const profit = cmp - entryPrice;
        let trailSL = sl;
        if (profit > atr) {
          const trailLevel = cmp - (atr * 1.5);
          if (trailLevel > sl) {
            trailSL = +trailLevel.toFixed(2);
            await pool.query('UPDATE paper_trades SET stop_loss=$1 WHERE id=$2', [trailSL, openPos.id]);
          }
        }

        const hitSL  = cmp <= Math.max(sl, trailSL);
        const hitTgt = cmp >= tgt;
        const exitSig = result.sellVotes >= CONFIG.CONSENSUS_NEEDED;

        if (hitSL||hitTgt||exitSig) {
          // Phase 3 · Part 2 — slippage + brokerage-adjusted exit pricing
          const realistic = computeRealisticExitPnL(entryPrice, cmp, openPos.quantity);
          const exitFill  = realistic.exitPrice;
          const pnl       = realistic.pnl;
          const pnlPct    = realistic.pnlPct;
          const grossPnL  = realistic.grossPnL;
          const costs     = realistic.costs;
          const reason = hitSL?"Stop Loss (trailing)":hitTgt?"Target Hit":`Strategy Exit (${result.sellVotes}/3 SELL)`;
          await pool.query(
            `UPDATE paper_trades
                SET status='CLOSED', exit_price=$1, exit_time=NOW(),
                    pnl=$2, pnl_pct=$3, exit_reason=$4, gross_pnl=$5, costs=$6
              WHERE id=$7`,
            [exitFill,pnl,pnlPct,reason,grossPnL,costs,openPos.id]
          );

          if (LIVE_TRADING && kite) {
            try {
              const order = await placeOrderViaProxy('regular', {
                exchange: 'NSE', tradingsymbol: stock.sym, transaction_type: 'SELL',
                quantity: openPos.quantity, product: 'CNC', order_type: 'MARKET', validity: 'DAY',
              });
              const orderId = order.order_id || order.orderId || '';
              await pool.query(
                `UPDATE live_trades SET status='CLOSED',exit_price=$1,exit_time=NOW(),pnl=$2,pnl_pct=$3,exit_reason=$4,exit_order_id=$5 WHERE symbol=$6 AND status='OPEN'`,
                [cmp,pnl,pnlPct,reason,orderId,stock.sym]
              );
              console.log(`  🔴 LIVE SELL ${stock.sym} @ ₹${cmp} | Order ID: ${orderId} | ${reason}`);
            } catch(liveErr) {
              console.error(`  ✗ LIVE SELL FAILED ${stock.sym}: ${liveErr.message}`);
            }
          }

          // Update openTrades array so freed slot is available for pass 2
          openPos.status = 'CLOSED';
          console.log(`  ▼ EXIT ${stock.sym} @ ₹${cmp} | ${reason} | ${pnl>=0?"+":""}₹${pnl} | ${result.regime} ${LIVE_TRADING?'[LIVE]':'[PAPER]'}`);
          signalCount++;
        }

      // ── COLLECT BUY CANDIDATES (don't enter yet — rank first) ──
      } else if (canEnterNew
                 && result.signal==="BUY"
                 && result.buyVotes >= CONFIG.CONSENSUS_NEEDED
                 && result.score >= CONFIG.BUY_SCORE) {
        buyCandidates.push({ stock, result, candles, last });
      }

      await delay(CONFIG.SCAN_DELAY_MS);
    } catch(e) {
      console.error(`  ✗ ${stock.sym}: ${e.message}`);
      if (e.message && e.message.includes('api_key')) tokenValid = false;
      await delay(500);
    }
  }

  // ╔══════════════════════════════════════════════════════════════════════╗
  // ║  PASS 1.5: STRUCTURE FILTER + OPTIONAL LLM REVIEW                   ║
  // ║  Runs S/R + VWAP + PDH/PDL analysis on every candidate.             ║
  // ║  Hard-rejects bad setups. Adjusts score for the rest.               ║
  // ║  Optional LLM reviewer runs on top N shortlist only.                ║
  // ╚══════════════════════════════════════════════════════════════════════╝
  const filterStats = {
    total:               buyCandidates.length,
    rejectedByStructure: 0,
    rejectedByLLM:       0,
    approved:            0,
    rejectReasons:       {},
    llmCalls:            0,
    llmApprove:          0,
    llmCaution:          0,
    llmReject:           0,
  };

  if (STRUCTURE_CONFIG.structureFilterEnabled && buyCandidates.length > 0) {
    for (const c of buyCandidates) {
      try {
        const highs14 = c.candles.slice(-14).map(x => x.high);
        const lows14  = c.candles.slice(-14).map(x => x.low);
        const atrVal  = highs14.map((h, i) => h - lows14[i]).reduce((a, b) => a + b, 0) / 14;
        const structure = analyzeCandidateStructure(c.stock.sym, c.candles, c.last.close, atrVal);
        c.structure = structure;

        const adj = adjustCandidateScoreFromStructure(c, structure);
        c.adjustments    = adj.adjustments;
        c.adjustedScore  = adj.scoreAfter;
        if (adj.rejected) {
          c.rejected     = true;
          c.rejectReason = adj.reason;
          filterStats.rejectedByStructure += 1;
          filterStats.rejectReasons[adj.reason] = (filterStats.rejectReasons[adj.reason] || 0) + 1;
        }
      } catch(e) {
        console.log(`  ⚠ structure analysis error ${c.stock.sym}: ${e.message}`);
        c.adjustedScore = c.result.score;
      }
    }

    // LLM review — only top N non-rejected candidates above threshold
    if (STRUCTURE_CONFIG.llmFilterEnabled) {
      const shortlist = shortlistCandidatesForLLM(buyCandidates);
      for (const c of shortlist) {
        try {
          const decision = await reviewCandidateWithLLM(c, c.structure);
          c.llmDecision = decision;
          filterStats.llmCalls += 1;
          if (decision.decision === 'APPROVE')  filterStats.llmApprove += 1;
          if (decision.decision === 'CAUTION')  filterStats.llmCaution += 1;
          if (decision.decision === 'REJECT') {
            filterStats.llmReject += 1;
            filterStats.rejectedByLLM += 1;
            filterStats.rejectReasons['LLM_' + (decision.comment || 'reject').slice(0,30)] =
              (filterStats.rejectReasons['LLM_' + (decision.comment || 'reject').slice(0,30)] || 0) + 1;
          }
        } catch(e) {
          console.log(`  ⚠ LLM review error ${c.stock.sym}: ${e.message}`);
        }
      }
    }

    // Finalize
    for (const c of buyCandidates) applyFinalCandidateDecision(c);
    filterStats.approved = buyCandidates.filter(c => !c.rejected).length;

    // Store for /api/candidates/latest
    _latestCandidateAnalyses = buyCandidates.map(c => ({
      symbol:          c.stock.sym,
      name:            c.stock.n,
      strategy:        c.result.strategy,
      regime:          c.result.regime,
      originalScore:   +c.result.score.toFixed(2),
      adjustedScore:   c.adjustedScore ?? c.result.score,
      adjustments:     c.adjustments || [],
      structure:       c.structure || null,
      llmDecision:     c.llmDecision || null,
      finalDecision:   c.finalDecision || (c.rejected ? 'REJECTED' : 'APPROVED'),
      rejectReason:    c.rejectReason || null,
      confidence:      c.decisionObject?.confidence ?? null,
      decisionObject:  c.decisionObject || null,
      entryPrice:      c.last.close,
      scannedAt:       new Date().toISOString(),
    }));
    _latestFilterStats = filterStats;

    console.log(`  🧱 Structure filter: ${filterStats.total} → ${filterStats.approved} approved, ${filterStats.rejectedByStructure} rejected (S), ${filterStats.rejectedByLLM} rejected (LLM)`);
    if (Object.keys(filterStats.rejectReasons).length > 0) {
      const topReasons = Object.entries(filterStats.rejectReasons)
        .sort((a, b) => b[1] - a[1]).slice(0, 3)
        .map(([r, n]) => `${r}×${n}`).join(', ');
      console.log(`     top reject reasons: ${topReasons}`);
    }
  } else {
    // Structure filter disabled — passthrough
    for (const c of buyCandidates) { c.adjustedScore = c.result.score; c.finalDecision = 'APPROVED'; }
    _latestCandidateAnalyses = [];
    _latestFilterStats = filterStats;
  }

  // ╔══════════════════════════════════════════════════════════════════════╗
  // ║  PASS 2: Rank BUY candidates (Phase 4 multi-factor score) and        ║
  // ║  enter top signals respecting position limits + correlation guards.  ║
  // ║  This eliminates large-cap bias from sequential scanning.            ║
  // ╚══════════════════════════════════════════════════════════════════════╝

  // Phase 4 · Part 3 — confidence hard-reject (only on non-already-rejected)
  if (STRUCTURE_CONFIG.confidenceSelectionEnabled) {
    const minConf = +STRUCTURE_CONFIG.confidenceRejectBelow || 0;
    for (const c of buyCandidates) {
      if (c.rejected) continue;
      const conf = c.decisionObject?.confidence;
      if (conf != null && +conf < minConf) {
        c.rejected     = true;
        c.rejectReason = `confidence ${(+conf).toFixed(2)} < ${minConf}`;
        filterStats.rejectedByStructure += 1;  // count as pre-entry reject
        filterStats.rejectReasons['low_confidence'] = (filterStats.rejectReasons['low_confidence'] || 0) + 1;
      }
    }
  }

  // Phase 4 · Parts 4+5 — regime/strategy soft tuning filter
  if (STRUCTURE_CONFIG.regimeTuningEnabled || STRUCTURE_CONFIG.strategyTuningEnabled) {
    for (const c of buyCandidates) {
      if (c.rejected) continue;
      const tune = applyRegimeStrategyTuning(c);
      if (tune.blocked) {
        c.rejected     = true;
        c.rejectReason = tune.reason;
        filterStats.rejectedByStructure += 1;
        filterStats.rejectReasons[tune.reason] = (filterStats.rejectReasons[tune.reason] || 0) + 1;
      }
      if (tune.adjustments && tune.adjustments.length) {
        c.adjustments = (c.adjustments || []).concat(tune.adjustments);
      }
    }
  }

  // Phase 4 · Part 6 — portfolio context (regime diversity of currently-open positions)
  const _portfolioCtx = (() => {
    const regimesOpen = {};
    for (const t of openTrades.filter(x => x.status === 'OPEN')) {
      const r = (t.regime || 'UNKNOWN').toUpperCase();
      regimesOpen[r] = (regimesOpen[r] || 0) + 1;
    }
    return { regimesOpen };
  })();

  // Phase 4 · Part 2 — compute rankingScore per candidate with lightweight
  // ATR-based stop/target estimate for pre-sort RR. Final ranking is recomputed
  // with the real sizing output inside the loop (and persisted to ranking_json).
  for (const c of buyCandidates) {
    try {
      const cl = c.candles;
      if (!cl || cl.length < 15) continue;
      const highs14 = cl.slice(-14).map(x => x.high);
      const lows14  = cl.slice(-14).map(x => x.low);
      const atrVal  = highs14.map((h, i) => h - lows14[i]).reduce((a, b) => a + b, 0) / 14;
      const px = c.last.close;
      // Rough ATR estimate: stop = px − 1.2*ATR, target = px + 2.4*ATR
      const estStop = px - 1.2 * atrVal;
      const estTgt  = px + 2.4 * atrVal;
      const rk = computeRankingScore(c, px, estStop, estTgt, _portfolioCtx);
      c.rankingScore    = rk.rankingScore;
      c.rankingBreakdown = rk.breakdown;
    } catch (_) {
      c.rankingScore = +(c.adjustedScore ?? c.result.score);
    }
  }

  // Primary sort: rankingScore DESC (falls back to adjustedScore when flag off)
  buyCandidates.sort((a, b) => {
    const ra = +(a.rankingScore ?? a.adjustedScore ?? a.result.score) || 0;
    const rb = +(b.rankingScore ?? b.adjustedScore ?? b.result.score) || 0;
    if (rb !== ra) return rb - ra;
    // Tiebreak on adjustedScore (preserves legacy behavior when scores tie)
    return (+(b.adjustedScore ?? b.result.score)) - (+(a.adjustedScore ?? a.result.score));
  });

  // Reset Pass 2 debug for this scan
  _latestPass2Debug = {
    scannedAt:         new Date().toISOString(),
    ranked:            [],
    entered:           0,
    skippedSlots:      0,
    skippedCorr:       0,
    skippedDup:        0,
    skippedFilter:     0,
    rejectedStructure: filterStats.rejectedByStructure || 0,
    rejectedLLM:       filterStats.rejectedByLLM || 0,
  };

  if (buyCandidates.length > 0) {
    const live = buyCandidates.filter(c => !c.rejected);
    console.log(`  📊 Ranked ${live.length} live BUY candidates: ${live.slice(0,10).map(c=>`${c.stock.sym}(${(c.adjustedScore ?? c.result.score).toFixed(1)})`).join(' > ')}`);
  }

  // Helper to record Pass 2 outcome per candidate
  const recordPass2 = (candidate, status, skipReason = null) => {
    const idx = _latestPass2Debug.ranked.length;
    _latestPass2Debug.ranked.push({
      rank:         idx + 1,
      symbol:       candidate.stock.sym,
      strategy:     candidate.result.strategy,
      regime:       candidate.result.regime,
      score:        +candidate.result.score.toFixed(2),
      adjScore:     +(+(candidate.adjustedScore ?? candidate.result.score)).toFixed(2),
      rankingScore: +(+(candidate.rankingScore ?? 0)).toFixed(4),
      confidence:   candidate.decisionObject?.confidence ?? null,
      confidenceBand: confidenceBand(candidate.decisionObject?.confidence),
      status,        // ENTERED | SKIPPED
      skipReason,    // 'structure'|'slots'|'correlation'|'dedup'|'llm'|null
    });
    // Phase 4 · Part 9 — persist rejected rows for post-rejection price tracking
    if (status === 'SKIPPED' && STRUCTURE_CONFIG.rejectedTradeAnalysisEnabled) {
      // Fire-and-forget
      persistRejectedCandidate(candidate, skipReason, skipReason);
    }
  };

  for (const candidate of buyCandidates) {
    const { stock, result, candles, last } = candidate;

    // Skip candidates rejected by structure filter or LLM
    if (candidate.rejected) {
      console.log(`  ⊘ SKIP ${stock.sym} (score:${(candidate.adjustedScore ?? result.score).toFixed(1)}) — ${candidate.rejectReason || 'structure filter'}`);
      _latestPass2Debug.skippedFilter += 1;
      recordPass2(candidate, 'SKIPPED', candidate.rejectReason || 'structure filter');
      continue;
    }

    // Re-check slot availability (exits in pass 1 may have freed slots)
    const currentOpen = openTrades.filter(t=>t.status==="OPEN").length;
    if (currentOpen >= CONFIG.MAX_POSITIONS) {
      console.log(`  ⊘ SKIP ${stock.sym} (score:${(candidate.adjustedScore ?? result.score).toFixed(1)}) — all ${CONFIG.MAX_POSITIONS} slots full`);
      _latestPass2Debug.skippedSlots += 1;
      recordPass2(candidate, 'SKIPPED', 'max_positions');
      // Record the rest as slot-capped without the break, so the UI can see
      // the whole ranked list with reasons:
      for (const rest of buyCandidates.slice(buyCandidates.indexOf(candidate) + 1)) {
        if (rest.rejected) continue;
        recordPass2(rest, 'SKIPPED', 'max_positions');
        _latestPass2Debug.skippedSlots += 1;
      }
      break;
    }

    // Correlation guard — Phase 3 real Pearson w/ sector fallback
    const corrCheck = await checkCorrelationBlock(stock.sym, openTrades.filter(t=>t.status==='OPEN'));
    if (corrCheck.blocked) {
      console.log(`  ⊘ SKIP ${stock.sym} (score:${result.score}) — ${corrCheck.reason}`);
      _latestPass2Debug.skippedCorr += 1;
      recordPass2(candidate, 'SKIPPED', corrCheck.reason || 'correlation');
      continue;
    }
    // Stash for decision object / analytics audit
    candidate.correlation = {
      maxCorr: corrCheck.maxCorr,
      maxSym:  corrCheck.maxSym,
    };

    // ATR-based position sizing + S/R-anchored SL + Kelly
    const price   = last.close;
    const highs14 = candles.slice(-14).map(c=>c.high);
    const lows14  = candles.slice(-14).map(c=>c.low);
    const atrVal  = highs14.map((h,i)=>h-lows14[i]).reduce((a,b)=>a+b,0)/14;
    const posSize = computePositionSize(
      price, atrVal, result.regime,
      ddStatus.equity * sizeMult,
      kellyRisk,
      candles
    );
    const sl  = posSize.stopLoss;
    const tgt = posSize.target;
    const qty = posSize.shares;
    if (posSize.slSource === 'swing_low') {
      result.detail = (result.detail||'') + ` [SL:swing_low@${sl}]`;
    }

    // ── Dedup guard — skip if same symbol bought within last 60 seconds ──
    const { rows: recentDup } = await pool.query(
      `SELECT id FROM paper_trades WHERE symbol=$1 AND status='OPEN' AND entry_time > NOW() - INTERVAL '60 seconds' LIMIT 1`,
      [stock.sym]
    );
    if (recentDup.length > 0) {
      console.log(`  ⊘ SKIP ${stock.sym} — duplicate (already bought within 60s)`);
      _latestPass2Debug.skippedDup += 1;
      recordPass2(candidate, 'SKIPPED', 'dedup');
      continue;
    }

    // Append structure + LLM detail to indicators string for audit trail
    let enrichedDetail = result.detail || '';
    if (candidate.structure) {
      const s = candidate.structure;
      const bits = [];
      if (s.nearestResistance) bits.push(`R:${s.nearestResistance.zoneLow}-${s.nearestResistance.zoneHigh}(${s.nearestResistance.strengthLabel},${s.nearestResistance.distancePct}%)`);
      if (s.nearestSupport)    bits.push(`S:${s.nearestSupport.zoneLow}-${s.nearestSupport.zoneHigh}(${s.nearestSupport.strengthLabel},${s.nearestSupport.distancePct}%)`);
      if (s.vwap)              bits.push(`VWAP:${s.vwap.current}(${s.flags.priceAboveVWAP?'above':'below'})`);
      if (s.pdLevels)          bits.push(`PDH:${s.pdLevels.pdh}/PDL:${s.pdLevels.pdl}`);
      if (bits.length > 0)     enrichedDetail += ` [STRUCT: ${bits.join(' ')}]`;
    }
    if (candidate.adjustments && candidate.adjustments.length > 0) {
      enrichedDetail += ` [ADJ: ${candidate.adjustments.join(' ')}]`;
    }
    if (candidate.llmDecision && !candidate.llmDecision.skipped) {
      enrichedDetail += ` [LLM: ${candidate.llmDecision.decision}/${candidate.llmDecision.setupQuality}/${(candidate.llmDecision.confidence||0).toFixed(2)}]`;
    }

    const finalScore = candidate.adjustedScore ?? result.score;

    // Build structured JSON payloads for analytics / future ML
    const structureJson = candidate.structure ? {
      nearestResistance: candidate.structure.nearestResistance || null,
      nearestSupport:    candidate.structure.nearestSupport    || null,
      vwap:              candidate.structure.vwap              || null,
      pdLevels:          candidate.structure.pdLevels          || null,
      volumeRatio:       candidate.structure.volumeRatio       || null,
      flags:             candidate.structure.flags             || null,
      adjustments:       candidate.adjustments                 || [],
    } : null;
    const llmJson = candidate.llmDecision && !candidate.llmDecision.skipped
      ? {
          decision:     candidate.llmDecision.decision,
          confidence:   candidate.llmDecision.confidence,
          setupQuality: candidate.llmDecision.setupQuality,
          riskFlag:     candidate.llmDecision.riskFlag,
          newsRisk:     candidate.llmDecision.newsRisk || null,
          comment:      candidate.llmDecision.comment,
        }
      : null;
    const decisionJson = candidate.decisionObject || null;
    const confVal      = candidate.decisionObject?.confidence ?? null;

    // Phase 3 · Part 2 — apply entry slippage to the recorded fill price
    const entryFill = applyEntrySlippage(price);

    // Phase 3 · Part 4 — A/B experiment tagging (what filters were in effect)
    const experimentJson = STRUCTURE_CONFIG.abTestingEnabled ? {
      structure: !!STRUCTURE_CONFIG.structureFilterEnabled,
      llm:       !!STRUCTURE_CONFIG.llmFilterEnabled,
      news:      !!STRUCTURE_CONFIG.llmNewsEnabled,
      correlation: !!STRUCTURE_CONFIG.correlationFilterEnabled,
      slippage:  !!STRUCTURE_CONFIG.slippageSimulationEnabled,
      // Phase 4 flags for A/B slicing
      rankingUpgrade:  !!STRUCTURE_CONFIG.rankingUpgradeEnabled,
      confSelection:   !!STRUCTURE_CONFIG.confidenceSelectionEnabled,
      regimeTuning:    !!STRUCTURE_CONFIG.regimeTuningEnabled,
      strategyTuning:  !!STRUCTURE_CONFIG.strategyTuningEnabled,
      portfolioAlloc:  !!STRUCTURE_CONFIG.portfolioAllocationEnabled,
    } : null;

    // Phase 4 · Part 2 — recompute rankingScore with real sizing output and
    // persist the full breakdown for analytics + Pass 2 audit trail.
    const rkFinal = computeRankingScore(candidate, price, +sl, +tgt, _portfolioCtx);
    const rankingJson = rkFinal.breakdown ? {
      rankingScore: rkFinal.rankingScore,
      ...rkFinal.breakdown,
    } : null;

    // Paper trade
    await pool.query(
      `INSERT INTO paper_trades (symbol,name,type,price,quantity,capital,entry_time,stop_loss,target,signal_score,strategy,regime,indicators,status,structure_json,llm_json,decision_json,confidence,experiment,ranking_json)
       VALUES ($1,$2,'BUY',$3,$4,$5,NOW(),$6,$7,$8,$9,$10,$11,'OPEN',$12,$13,$14,$15,$16,$17)`,
      [stock.sym,stock.n,entryFill,qty,+(qty*entryFill).toFixed(2),+sl.toFixed(2),+tgt.toFixed(2),
       +(finalScore*10).toFixed(0),result.strategy,result.regime,enrichedDetail,
       structureJson ? JSON.stringify(structureJson) : null,
       llmJson       ? JSON.stringify(llmJson)       : null,
       decisionJson  ? JSON.stringify(decisionJson)  : null,
       confVal,
       experimentJson ? JSON.stringify(experimentJson) : null,
       rankingJson    ? JSON.stringify(rankingJson)    : null]
    );

    // Live order
    if (LIVE_TRADING && kite) {
      try {
        const order = await placeOrderViaProxy('regular', {
          exchange: 'NSE', tradingsymbol: stock.sym, transaction_type: 'BUY',
          quantity: qty, product: 'CNC', order_type: 'LIMIT', price: price, validity: 'DAY',
        });
        const orderId = order.order_id || order.orderId || '';
        await pool.query(
          `INSERT INTO live_trades (symbol,name,type,price,quantity,capital,entry_time,stop_loss,target,signal_score,strategy,regime,indicators,status,order_id)
           VALUES ($1,$2,'BUY',$3,$4,$5,NOW(),$6,$7,$8,$9,$10,$11,'OPEN',$12)`,
          [stock.sym,stock.n,price,qty,+(qty*price).toFixed(2),+sl.toFixed(2),+tgt.toFixed(2),
           +(result.score*10).toFixed(0),result.strategy,result.regime,result.detail,orderId]
        );
        console.log(`  🔴 LIVE BUY ${stock.sym} @ ₹${price} | Order ID: ${orderId}`);
      } catch(liveErr) {
        console.error(`  ✗ LIVE BUY FAILED ${stock.sym}: ${liveErr.message}`);
      }
    }

    openTrades.push({symbol:stock.sym,status:"OPEN"});
    dominantStrategy=result.strategy;
    const scoreStr = candidate.adjustedScore != null && candidate.adjustedScore !== result.score
      ? `Score:${result.score}→${candidate.adjustedScore.toFixed(2)}`
      : `Score:${result.score}`;
    console.log(`  ▲ BUY  ${stock.sym} @ ₹${price} | ${result.regime} | ${result.strategy} | ${scoreStr} | Rank:${buyCandidates.indexOf(candidate)+1}/${buyCandidates.length} | SL:${sl}(${posSize.slSource}) | TGT:${tgt} | Qty:${qty} ${LIVE_TRADING?'[LIVE]':'[PAPER]'}`);
    _latestPass2Debug.entered += 1;
    recordPass2(candidate, 'ENTERED', null);
    signalCount++;
  }

  // Dominant regime across this scan
  dominantRegime = Object.entries(regimeCounts).sort((a,b)=>b[1]-a[1])[0]?.[0]||"UNKNOWN";

  broadcast({ type:"tick", prices:livePrices });

  // Build scan_log message — include structure filter stats when available
  let scanMsg = `Market: ${dominantRegime} | ${signalCount} signals | ${Object.entries(regimeCounts).map(([k,v])=>`${k}:${v}`).join(" ")}`;
  if (_latestFilterStats && _latestFilterStats.total > 0) {
    const fs = _latestFilterStats;
    scanMsg += ` | Filter: ${fs.total}→${fs.approved} (S-rej:${fs.rejectedByStructure}${fs.rejectedByLLM?`, LLM-rej:${fs.rejectedByLLM}`:''})`;
  }

  // Phase 3 · Part 8 — record scan latency + warn if it exceeded threshold
  const _scanDurationMs  = Date.now() - _scanStartedAt;
  const _scanDurationSec = +(_scanDurationMs / 1000).toFixed(1);
  const _scanWarnSec     = STRUCTURE_CONFIG.scanLatencyWarnSec || 180;
  _latestScanHealth = {
    scannedAt:       new Date().toISOString(),
    durationSec:     _scanDurationSec,
    lagging:         _scanDurationSec > _scanWarnSec,
    warnThresholdSec:_scanWarnSec,
    dataWarnings:    _scanDataWarnings,
    apiFailures:     _scanApiFailures.slice(0, 20),
    universeSize:    UNIVERSE.length,
    signalCount,
  };
  if (_scanDurationSec > _scanWarnSec) {
    console.warn(`⚠ Scan latency ${_scanDurationSec}s > ${_scanWarnSec}s threshold`);
  }
  scanMsg += ` | ${_scanDurationSec}s`;

  // Phase 4 · Part 9 — update post-rejection forward-price snapshots for
  // previously rejected candidates using the latest livePrices from this scan.
  try { await updateRejectedTracking(livePrices); } catch (_) { /* non-fatal */ }

  await pool.query(
    "INSERT INTO scan_log (stocks,signals,regime,strategy,message) VALUES ($1,$2,$3,$4,$5)",
    [UNIVERSE.length, signalCount, dominantRegime, dominantStrategy, scanMsg]
  );
  console.log(`✓ Scan done | Market regime: ${dominantRegime} | ${signalCount} signals | ${_scanDurationSec}s\n`);
}

