// -- Fetch MAX daily candles from Kite (full history) --------------------------
async function fetchKiteDaily(sym) {
  if (!kite || !process.env.KITE_ACCESS_TOKEN) { return null; }
  const token = validTokens[sym] || INSTRUMENTS[sym];
  if (!token) { return null; }
  try {
    const to   = new Date();
    const from = new Date(Date.now() - 5*365*24*60*60*1000); // 5 years back (safe range)
    const toStr = to.toISOString().split('T')[0];
    const fromStr = from.toISOString().split('T')[0];
    const candles = await Promise.race([
      kite.getHistoricalData(token,'day',fromStr,toStr),
      new Promise((_,rej)=>setTimeout(()=>rej(new Error('timeout')),15000))
    ]);
    if (sym === 'RELIANCE' || sym === 'TCS' || sym === 'HDFCBANK') {
      console.log(`📈 fetchKiteDaily(${sym}): token=${token}, range=${fromStr}→${toStr}, got ${candles?.length||0} candles`);
    }
    return (candles && candles.length >= 50) ? candles : null;
  } catch(e) {
    // Log first few failures to diagnose
    if (!fetchKiteDaily._logCount) fetchKiteDaily._logCount = 0;
    if (fetchKiteDaily._logCount < 5) {
      console.error(`❌ fetchKiteDaily(${sym}) FAILED: ${e.message}`);
      fetchKiteDaily._logCount++;
    }
    return null;
  }
}

// -- NIFTY50 1-min candle ingest (for ML outcome calculation) -----------------
// Called at the end of every unified-pipeline cycle. Fetches the last ~10 min
// of 1-min candles for every NIFTY50 stock and batch-inserts them into
// candles_1m (ON CONFLICT DO NOTHING). Small Kite footprint: 50 req per run
// every 5 min = ~0.17 req/sec, well under the 3 req/sec ceiling.
//
// The outcome engine (commit 4) consumes this table strictly via ts > T so
// there is no lookahead risk — we're always filling the past, not the future.
let _nifty1mRunning = false;
async function ingestNifty50OneMinCandles() {
  if (_nifty1mRunning) return { skipped: true };
  if (!kite || !process.env.KITE_ACCESS_TOKEN) return { skipped: true, reason: 'no_kite' };
  _nifty1mRunning = true;

  const n50 = (UNIVERSE || []).filter(s => (s.grp || '').toUpperCase() === 'NIFTY50');
  if (n50.length === 0) { _nifty1mRunning = false; return { symbols: 0 }; }

  const now = new Date();
  // Pull last 15 minutes — generous overlap so replays are handled by ON CONFLICT.
  const from = new Date(now.getTime() - 15 * 60 * 1000);
  const fromStr = from.toISOString().slice(0, 19).replace('T', ' ');
  const toStr   = now.toISOString().slice(0, 19).replace('T', ' ');

  let symsOk = 0, symsFail = 0, barsWritten = 0;
  const BATCH = 5;
  for (let i = 0; i < n50.length; i += BATCH) {
    const batch = n50.slice(i, i + BATCH);
    await Promise.all(batch.map(async (stock) => {
      const token = validTokens[stock.sym] || INSTRUMENTS[stock.sym];
      if (!token) { symsFail++; return; }
      try {
        const candles = await Promise.race([
          kite.getHistoricalData(token, 'minute', fromStr, toStr),
          new Promise((_, rej) => setTimeout(() => rej(new Error('timeout')), 5000))
        ]).catch(() => null);
        if (!candles || candles.length === 0) { symsFail++; return; }
        const bars = candles.map(c => ({
          sym: stock.sym,
          ts: c.date instanceof Date ? c.date : new Date(c.date),
          open: c.open, high: c.high, low: c.low, close: c.close, volume: c.volume || 0,
        }));
        const n = await mlLogger.logCandlesBatch('candles_1m', bars);
        barsWritten += n;
        symsOk++;
      } catch (e) {
        symsFail++;
      }
    }));
    // Light throttle between batches to respect Kite's 3 req/sec cap
    if (i + BATCH < n50.length) await new Promise(r => setTimeout(r, 400));
  }

  _nifty1mRunning = false;
  return { symbols: n50.length, ok: symsOk, fail: symsFail, barsWritten };
}

// -- Compute technicals from daily candles ------------------------------------
function computeRSIDivergence(C, period=20) {
  const n = C.length;
  if (n < period + 14) return { rsiTrend: null, bullishDiv: false, bearishDiv: false };
  // Compute RSI series (simplified, last 'period' values)
  const rsiSeries = [];
  for (let i = n - period; i < n; i++) {
    let g=0, l=0;
    for (let j=i-13; j<i; j++) { const d=C[j+1]-C[j]; if(d>0)g+=d; else l-=d; }
    rsiSeries.push(l===0 ? 100 : 100 - 100/(1+(g/13)/(l/13)));
  }
  const priceNow  = C[n-1], priceBack  = C[n-period];
  const rsiNow    = rsiSeries[rsiSeries.length-1];
  const rsiBack   = rsiSeries[0];
  const rsiTrend  = rsiNow > rsiBack ? 'rising' : 'falling';
  // Bullish div: price lower but RSI higher (hidden strength)
  const bullishDiv = priceNow < priceBack && rsiNow > rsiBack && rsiNow < 50;
  // Bearish div: price higher but RSI lower (hidden weakness)
  const bearishDiv = priceNow > priceBack && rsiNow < rsiBack && rsiNow > 50;
  return { rsiTrend, bullishDiv, bearishDiv };
}

// ═══════════════════════════════════════════════════════════════════════════════
// DAY TRADE SCORING + SCANNING ENGINE (5-min intraday setups)
// ═══════════════════════════════════════════════════════════════════════════════

let _dayTradeCache    = [];      // scored picks — refreshed every 5 min
let _dayTradeCacheTs  = 0;
let _dayTradeScanning = false;
let _pipelineLastRun  = null;   // diagnostic: last pipeline run result

// ═══════════════════════════════════════════════════════════════════════════════
// VARSITY M2 CANDLESTICK PATTERN DETECTION (Chapters 5-10)
// ═══════════════════════════════════════════════════════════════════════════════
// Returns the strongest bullish / bearish reversal or continuation pattern on the
// LATEST candle (with look-back up to 2 prior candles for multi-candle patterns).
// Each pattern has its own Varsity identification rules — see chapter comments.

function _candleMetrics(c) {
  const body      = Math.abs(c.close - c.open);
  const range     = Math.max(c.high - c.low, 1e-9);
  const bullish   = c.close > c.open;
  const bearish   = c.close < c.open;
  const upperWick = c.high - Math.max(c.open, c.close);
  const lowerWick = Math.min(c.open, c.close) - c.low;
  const bodyPct   = body / range;        // 0..1 — how much of range is body
  const rangePct  = range / Math.max(c.close, 1e-9); // range as % of price
  return { body, range, bullish, bearish, upperWick, lowerWick, bodyPct, rangePct };
}

// Varsity M2 Ch 5-10: canonical bullish-reversal patterns + their M2 weights.
// Returns { name, bull, weight, description } for the strongest pattern detected
// in the last 1-3 candles, or null. Weight is in Varsity "conviction points"
// where 20 = strongest (Engulfing, Morning Star), 10 = medium (Hammer, Piercing),
// 5 = weak/confirming (Doji, Spinning Top at S/R).
function detectBullishCandlePattern(candles) {
  const n = candles.length;
  if (n < 1) return null;
  const c0 = candles[n - 1];                           // current candle
  const c1 = n >= 2 ? candles[n - 2] : null;           // prior
  const c2 = n >= 3 ? candles[n - 3] : null;           // 2 ago
  const m0 = _candleMetrics(c0);
  const m1 = c1 ? _candleMetrics(c1) : null;
  const m2 = c2 ? _candleMetrics(c2) : null;

  // ── Bullish Marubozu (Ch 5) — no wicks, full body, strong momentum ──
  // Varsity: open ≈ low, close ≈ high, body ≥ 90% of range.
  if (m0.bullish && m0.bodyPct >= 0.90 && m0.upperWick / m0.range < 0.05 && m0.lowerWick / m0.range < 0.05 && m0.rangePct > 0.003) {
    return { name: 'Bullish Marubozu', bull: true, weight: 18, description: 'Full-body bullish — no wicks, strong buying' };
  }

  // ── Bullish Engulfing (Ch 8) — STRONGEST 2-candle reversal ──
  // Varsity: prior bearish + current bullish body that fully engulfs prior body.
  if (c1 && m1.bearish && m0.bullish && c0.close > c1.open && c0.open < c1.close && m0.body > m1.body * 1.05) {
    return { name: 'Bullish Engulfing', bull: true, weight: 20, description: 'Prior bearish body fully engulfed by bullish body' };
  }

  // ── Piercing Pattern (Ch 8) — 2-candle bullish reversal ──
  // Varsity: prior bearish + current bullish opening below prior low, closing above prior midpoint.
  if (c1 && m1.bearish && m0.bullish && c0.open < c1.low && c0.close > (c1.open + c1.close) / 2 && c0.close < c1.open) {
    return { name: 'Piercing Pattern', bull: true, weight: 12, description: 'Gap-down open, close above prior midpoint' };
  }

  // ── Morning Star (Ch 10) — 3-candle reversal, very high conviction ──
  // Varsity: bearish → small-body (star) → bullish closing above first candle's midpoint.
  if (c2 && c1 && m2.bearish && m1.bodyPct < 0.30 && m0.bullish && c0.close > (c2.open + c2.close) / 2) {
    return { name: 'Morning Star', bull: true, weight: 20, description: 'Bearish → indecision star → strong bullish close' };
  }

  // ── Bullish Harami (Ch 9) — 2-candle reversal, medium conviction ──
  // Varsity: prior bearish + current small bullish body INSIDE prior body.
  if (c1 && m1.bearish && m0.bullish && c0.open > c1.close && c0.close < c1.open && m0.body < m1.body * 0.6) {
    return { name: 'Bullish Harami', bull: true, weight: 10, description: 'Small bullish body inside prior bearish body' };
  }

  // ── Hammer / Paper Umbrella (Ch 7) — 1-candle reversal at support ──
  // Varsity: small body near top, lower wick ≥ 2× body, minimal upper wick.
  if (m0.lowerWick >= m0.body * 2 && m0.upperWick < m0.body * 0.5 && m0.bodyPct < 0.35 && m0.rangePct > 0.004) {
    return { name: 'Hammer', bull: true, weight: 12, description: 'Small body, long lower wick — buyers rejected lows' };
  }

  // ── Inverted Hammer (Ch 7) — 1-candle reversal, needs confirmation ──
  if (m0.upperWick >= m0.body * 2 && m0.lowerWick < m0.body * 0.5 && m0.bodyPct < 0.35 && m0.bullish && m0.rangePct > 0.004) {
    return { name: 'Inverted Hammer', bull: true, weight: 6, description: 'Long upper wick reversal — needs next-bar confirmation' };
  }

  // ── Dragonfly Doji (Ch 6) — bullish indecision at support ──
  if (m0.bodyPct < 0.05 && m0.lowerWick > m0.range * 0.6 && m0.upperWick < m0.range * 0.1) {
    return { name: 'Dragonfly Doji', bull: true, weight: 8, description: 'Open ≈ close ≈ high, long lower wick — bullish indecision' };
  }

  // ── Doji (Ch 6) — indecision, weak signal alone, strong at S/R ──
  if (m0.bodyPct < 0.07) {
    return { name: 'Doji', bull: true, weight: 4, description: 'Open ≈ close — indecision, reversal signal at key level' };
  }

  return null;
}

// Bearish counterpart — used for Breakout/Gap setups to detect exhaustion at highs.
function detectBearishCandlePattern(candles) {
  const n = candles.length;
  if (n < 1) return null;
  const c0 = candles[n - 1];
  const c1 = n >= 2 ? candles[n - 2] : null;
  const c2 = n >= 3 ? candles[n - 3] : null;
  const m0 = _candleMetrics(c0);
  const m1 = c1 ? _candleMetrics(c1) : null;
  const m2 = c2 ? _candleMetrics(c2) : null;

  // Bearish Marubozu (Ch 5)
  if (m0.bearish && m0.bodyPct >= 0.90 && m0.upperWick / m0.range < 0.05 && m0.lowerWick / m0.range < 0.05 && m0.rangePct > 0.003) {
    return { name: 'Bearish Marubozu', bull: false, weight: 18, description: 'Full-body bearish — strong selling' };
  }
  // Bearish Engulfing (Ch 8)
  if (c1 && m1.bullish && m0.bearish && c0.open > c1.close && c0.close < c1.open && m0.body > m1.body * 1.05) {
    return { name: 'Bearish Engulfing', bull: false, weight: 20, description: 'Prior bullish body engulfed by bearish body' };
  }
  // Dark Cloud Cover (Ch 8)
  if (c1 && m1.bullish && m0.bearish && c0.open > c1.high && c0.close < (c1.open + c1.close) / 2 && c0.close > c1.open) {
    return { name: 'Dark Cloud Cover', bull: false, weight: 12, description: 'Gap-up open, close below prior midpoint' };
  }
  // Evening Star (Ch 10)
  if (c2 && c1 && m2.bullish && m1.bodyPct < 0.30 && m0.bearish && c0.close < (c2.open + c2.close) / 2) {
    return { name: 'Evening Star', bull: false, weight: 20, description: 'Bullish → star → strong bearish close — top reversal' };
  }
  // Shooting Star (Ch 7)
  if (m0.upperWick >= m0.body * 2 && m0.lowerWick < m0.body * 0.5 && m0.bodyPct < 0.35 && m0.rangePct > 0.004) {
    return { name: 'Shooting Star', bull: false, weight: 12, description: 'Small body, long upper wick — sellers rejected highs' };
  }
  // Hanging Man (Ch 7) — like Hammer but at uptrend top
  if (m0.lowerWick >= m0.body * 2 && m0.upperWick < m0.body * 0.5 && m0.bodyPct < 0.35 && m0.bearish && m0.rangePct > 0.004) {
    return { name: 'Hanging Man', bull: false, weight: 8, description: 'Hammer shape in uptrend — potential reversal' };
  }
  // Gravestone Doji (Ch 6)
  if (m0.bodyPct < 0.05 && m0.upperWick > m0.range * 0.6 && m0.lowerWick < m0.range * 0.1) {
    return { name: 'Gravestone Doji', bull: false, weight: 8, description: 'Open ≈ close ≈ low, long upper wick — bearish indecision' };
  }
  return null;
}

// ═══════════════════════════════════════════════════════════════════════════════
// VARSITY M2 CH 22 — CENTRAL PIVOT RANGE (CPR)
// ═══════════════════════════════════════════════════════════════════════════════
// CPR = three intraday levels (Pivot Point, Bottom Central, Top Central) computed
// from the PREVIOUS day's H/L/C. Price respects these levels intraday.
// Width narrower than 0.5% of price → trending day expected (breakout bias).
// Width wider than 1.0% → sideways/choppy day (range-bound bias).
// R1-R3 / S1-S3 are standard pivot resistance/support levels.

function computeCPR(prevDayCandles, refPrice) {
  if (!prevDayCandles || prevDayCandles.length === 0) return null;
  const H = Math.max(...prevDayCandles.map(c => c.high));
  const L = Math.min(...prevDayCandles.map(c => c.low));
  const C = prevDayCandles[prevDayCandles.length - 1].close;
  const PP = (H + L + C) / 3;
  const BC = (H + L) / 2;
  const TC = 2 * PP - BC;
  const cprHi = Math.max(TC, BC);
  const cprLo = Math.min(TC, BC);
  const width = cprHi - cprLo;
  const widthPct = refPrice > 0 ? (width / refPrice) * 100 : 0;
  // Varsity M2 Ch 22: narrow CPR (< 0.5%) = directional day, wide (> 1%) = range
  const type = widthPct < 0.5 ? 'NARROW' : widthPct > 1.0 ? 'WIDE' : 'NORMAL';
  return {
    PP, BC, TC, cprHi, cprLo, width, widthPct, type,
    R1: 2 * PP - L,
    S1: 2 * PP - H,
    R2: PP + (H - L),
    S2: PP - (H - L),
    R3: H + 2 * (PP - L),
    S3: L - 2 * (H - PP),
  };
}

// ═══════════════════════════════════════════════════════════════════════════════
// VARSITY M9: SECTOR CORRELATION CAP (diversification)
// ═══════════════════════════════════════════════════════════════════════════════
// "Never take N correlated positions" — stocks in the same sector are
// effectively one trade. After sorting picks by dayTradeScore, interleave
// them so no sector exceeds `maxPerSector` within the top 10. Picks beyond
// the cap are demoted (not dropped) to positions 11+ so the admin can still
// see them if they scroll.

function applySectorCap(sortedPicks, maxPerSector = 2) {
  if (!Array.isArray(sortedPicks) || sortedPicks.length <= maxPerSector) return sortedPicks;
  const topCandidate = [];
  const tail = [];
  const sectorCount = Object.create(null);
  for (const p of sortedPicks) {
    const sect = (p.sector || 'Other').toString();
    if (topCandidate.length < 10 && (sectorCount[sect] || 0) < maxPerSector) {
      topCandidate.push(p);
      sectorCount[sect] = (sectorCount[sect] || 0) + 1;
    } else {
      tail.push(p);
    }
  }
  // Fill top 10 if under (should only happen with very few picks total)
  while (topCandidate.length < 10 && tail.length > 0) topCandidate.push(tail.shift());
  return topCandidate.concat(tail);
}

// Module-level Nifty snapshot set by runUnifiedKitePipeline on each run so
// scoreDayTrade can compute relative strength (stock vs index) without
// needing Kite index fetches inside the per-stock scoring loop.
let _niftyDailyChangePct = null;

function scoreDayTrade(candles, sym, ctx) {
  ctx = ctx || {};
  // Prefer per-scan injection via ctx, otherwise fall back to module snapshot.
  const _niftyChange = typeof ctx.niftyDailyChange === 'number' ? ctx.niftyDailyChange : _niftyDailyChangePct;
  const n = candles.length;
  if (n < 30) return null;

  const C = candles.map(c => c.close);
  const H = candles.map(c => c.high || c.close);
  const L = candles.map(c => c.low  || c.close);
  const V = candles.map(c => c.volume || 0);
  const last = candles[n - 1];
  const px = last.close;
  if (!px || px <= 0) return null;

  // ── Light quality gate ────────────────────────────────────────────────
  const f = stockFundamentals[sym];
  if (px < 20) return null;                                // no penny stocks
  if (f && f.score != null && f.score < 20) return null;   // junk fundamentals
  const avg20Vol = V.slice(-20).reduce((a, b) => a + b, 0) / 20;
  if (avg20Vol < 5000) return null;                        // illiquid

  // Varsity M2: skip if latest 5-min candle range is extreme (>3% on a single bar = abnormal)
  const lastCandleRange = last.high > 0 ? (last.high - last.low) / last.close * 100 : 0;
  if (lastCandleRange > 3) return null;

  // Varsity M9: avoid new entries in last 30 min before market close (3:00-3:30 PM IST)
  const now = new Date();
  const istHour = (now.getUTCHours() + 5) % 24 + (now.getUTCMinutes() + 30 >= 60 ? 1 : 0);
  const istMin = (now.getUTCMinutes() + 30) % 60;
  const isLateTrade = (istHour === 15 && istMin >= 0) || istHour > 15;

  // ── Session phase classification (Varsity M9 Ch 9 + market microstructure) ──
  // Intraday isn't uniform — each phase has different volatility, volume, and
  // reliability characteristics. Setups have phase affinity:
  //   OPENING   (9:15-10:00)  — high vol, gap/breakout favored, bounce risky
  //   MORNING   (10:00-12:00) — trends establish, all setups viable
  //   MIDDAY    (12:00-14:00) — low vol chop, mean-reversion favored
  //   AFTERNOON (14:00-15:00) — trends resume, breakouts decent
  //   LATE      (15:00-15:30) — avoid new entries (already penalized)
  const minsSinceOpen = (istHour - 9) * 60 + istMin - 15;
  let sessionPhase = 'UNKNOWN';
  if (minsSinceOpen < 0 || minsSinceOpen > 375) sessionPhase = 'CLOSED';
  else if (minsSinceOpen < 45)  sessionPhase = 'OPENING';
  else if (minsSinceOpen < 165) sessionPhase = 'MORNING';
  else if (minsSinceOpen < 285) sessionPhase = 'MIDDAY';
  else if (minsSinceOpen < 345) sessionPhase = 'AFTERNOON';
  else sessionPhase = 'LATE';

  // Score explanation tracker
  const _track = [];
  function _gain(bucket, pts, reason) { _track.push({bucket, pts, reason, type:'gain'}); return pts; }
  function _penalty(bucket, pts, reason) { _track.push({bucket, pts: -Math.abs(pts), reason, type:'penalty'}); return -Math.abs(pts); }

  // ── Isolate today's candles vs previous day (Varsity M2: intraday = session-only) ──
  // Kite returns Date objects — use toISOString() for reliable date comparison.
  const _candleDateStr = (d) => d instanceof Date ? d.toISOString().split('T')[0] : String(d).slice(0, 10);
  let todayStart = new Date().toISOString().split('T')[0];
  let todayCandles = candles.filter(c => {
    const d = c.date || c.timestamp;
    return d && _candleDateStr(d) === todayStart;
  });
  // Fallback: if no candles for today (weekend/holiday/after-hours), use the last trading day
  if (todayCandles.length < 3) {
    const lastCandle = candles[candles.length - 1];
    const lastDate = lastCandle.date || lastCandle.timestamp;
    if (lastDate) {
      todayStart = _candleDateStr(lastDate);
      todayCandles = candles.filter(c => {
        const d = c.date || c.timestamp;
        return d && _candleDateStr(d) === todayStart;
      });
    }
  }
  const prevDayCandles = candles.filter(c => {
    const d = c.date || c.timestamp;
    return d && _candleDateStr(d) !== todayStart;
  });
  if (todayCandles.length < 3) return null; // need at least 15 min of session data

  // ── Shared indicators ─────────────────────────────────────────────────

  // VWAP: Varsity M2 Ch13 — VWAP resets at session open. It is a SAME-DAY indicator.
  // Using only today's candles ensures VWAP is pure session VWAP.
  const todayVWAPs = vwap(todayCandles);
  const lastVWAP   = todayVWAPs[todayVWAPs.length - 1];
  const pctVWAP    = ((px - lastVWAP) / lastVWAP * 100);
  // Varsity M2 Ch 13: VWAP ±σ bands (anchored VWAP extensions).
  // Standard deviation of today's closes around VWAP defines overbought
  // / oversold statistical bands. Price outside ±2σ = 95% statistical
  // extreme = strong mean-reversion signal per Ch 13.
  let vwapSigma = 0, vwapUpper1 = lastVWAP, vwapLower1 = lastVWAP, vwapUpper2 = lastVWAP, vwapLower2 = lastVWAP;
  if (todayCandles.length >= 5) {
    const tc = todayCandles;
    const variance = tc.reduce((acc, c, i) => acc + Math.pow(c.close - todayVWAPs[i], 2), 0) / tc.length;
    vwapSigma = Math.sqrt(variance);
    vwapUpper1 = lastVWAP + vwapSigma;
    vwapLower1 = lastVWAP - vwapSigma;
    vwapUpper2 = lastVWAP + 2 * vwapSigma;
    vwapLower2 = lastVWAP - 2 * vwapSigma;
  }
  const below2Sigma = vwapSigma > 0 && px < vwapLower2;
  const below1Sigma = vwapSigma > 0 && px < vwapLower1 && px >= vwapLower2;
  const above2Sigma = vwapSigma > 0 && px > vwapUpper2;

  // Track if price was recently below VWAP (for VWAP Reclaim detection)
  // Varsity M2 Ch13: reclaim = price was below VWAP, then crossed back above
  const recentVWAPBelow = todayVWAPs.length >= 4 &&
    todayVWAPs.slice(-6, -1).some((v, i) => {
      const idx = todayCandles.length - 6 + i;
      return idx >= 0 && todayCandles[idx] && todayCandles[idx].close < v;
    });

  const rsiArr   = rsi(C, 14);
  const lastRSI  = rsiArr[n - 1];
  const lastVol  = V[n - 1] || 0;
  const volRatio = lastVol / (avg20Vol || 1);

  // EMA 9 / 20 for trend
  const calcEma = (arr, p) => { const k = 2 / (p + 1); let e = arr[0]; return arr.map(v => { e = v * k + e * (1 - k); return e; }); };
  const ema9  = calcEma(C, 9);
  const ema20 = calcEma(C, 20);

  // MACD on 5-min
  const e12 = calcEma(C, 12), e26 = calcEma(C, 26);
  const macdLine  = e12.map((v, i) => v - e26[i]);
  const sigLine   = calcEma(macdLine, 9);
  const macdBull  = macdLine[n - 1] > sigLine[n - 1];
  const macdCross = macdLine[n - 2] < sigLine[n - 2] && macdBull; // fresh bull cross
  // Varsity M2 Ch 15: MACD histogram analysis (distinct from line-vs-signal cross)
  // Histogram = macdLine - sigLine. Rising histogram = momentum accelerating.
  // Histogram crossing 0 upward = bull momentum starting (earlier than line cross).
  const macdHist      = macdLine[n - 1] - sigLine[n - 1];
  const macdHistPrev  = macdLine[n - 2] - sigLine[n - 2];
  const macdHistPrev2 = n >= 3 ? macdLine[n - 3] - sigLine[n - 3] : macdHistPrev;
  const macdHistRising = macdHist > macdHistPrev && macdHistPrev >= macdHistPrev2; // 3-bar acceleration
  const macdHistZeroUp = macdHistPrev <= 0 && macdHist > 0;                         // fresh zero-line cross up

  // ── Varsity M2 Ch 14: RSI 50 midline (bull/bear demarcation) ──
  // Varsity: "Above 50 = bull zone, below 50 = bear zone. RSI crossing 50
  // from below = momentum flipping bullish." Complements the 30/70 extremes.
  const rsiAboveMidline = lastRSI > 50;
  const rsiCrossedMidlineUp = rsiArr.length >= 2 && rsiArr[n - 2] <= 50 && lastRSI > 50;

  // ── Varsity M2 Ch 14 + Ch 15: RSI & MACD Divergence ──
  // "Divergence is the single most reliable reversal signal in TA" (Varsity M2 Ch 14).
  //   Bullish divergence: price makes a lower low, RSI makes a HIGHER low → reversal up
  //   Bearish divergence: price makes a higher high, RSI makes a LOWER high → reversal down
  // Same logic applies to MACD line. We look over the last 20 bars for the
  // prior extreme (by price) and compare to the current extreme.
  function _findPivot(arr, extremeFn, window) {
    // Return the index of the extreme (min or max) in last `window` bars, excluding last 2.
    const start = Math.max(0, arr.length - window);
    const end   = arr.length - 3;
    let idx = start;
    for (let i = start; i <= end; i++) if (extremeFn(arr[i], arr[idx])) idx = i;
    return idx;
  }
  let rsiBullDiv = false, rsiBearDiv = false, macdBullDiv = false, macdBearDiv = false;
  if (n >= 25) {
    // Bullish: current close < prior-pivot close but current RSI > prior-pivot RSI
    const loIdx = _findPivot(C, (a, b) => a < b, 20);
    if (C[n - 1] < C[loIdx] * 1.001 && rsiArr[n - 1] > rsiArr[loIdx] + 2) rsiBullDiv = true;
    if (C[n - 1] < C[loIdx] * 1.001 && macdLine[n - 1] > macdLine[loIdx]) macdBullDiv = true;
    // Bearish: current close > prior-pivot high but current RSI < prior-pivot RSI
    const hiIdx = _findPivot(C, (a, b) => a > b, 20);
    if (C[n - 1] > C[hiIdx] * 0.999 && rsiArr[n - 1] < rsiArr[hiIdx] - 2) rsiBearDiv = true;
    if (C[n - 1] > C[hiIdx] * 0.999 && macdLine[n - 1] < macdLine[hiIdx]) macdBearDiv = true;
  }

  // Bollinger %B
  const dma20 = C.slice(n - 20).reduce((a, b) => a + b, 0) / 20;
  const bbStd = Math.sqrt(C.slice(n - 20).reduce((a, v) => a + (v - dma20) ** 2, 0) / 20);
  const bbUpper = dma20 + 2 * bbStd;
  const bbLower = dma20 - 2 * bbStd;
  const bbPct   = bbUpper > bbLower ? (px - bbLower) / (bbUpper - bbLower) : 0.5;

  // Stochastic K/D on 5-min (Varsity M2 Ch18: stochastic confirms oversold/overbought)
  const stochPeriod = 14;
  const stochSlice  = C.slice(-stochPeriod);
  const stochHSlice = H.slice(-stochPeriod);
  const stochLSlice = L.slice(-stochPeriod);
  const stochHH     = Math.max(...stochHSlice);
  const stochLL     = Math.min(...stochLSlice);
  const stochK      = stochHH > stochLL ? ((px - stochLL) / (stochHH - stochLL)) * 100 : 50;

  // Opening Range — Varsity M2 Ch7: uses first 15-30 min candles OF TODAY
  // First 6 five-min candles = 9:15–9:45 IST (first 30 min of today)
  const todayFirst6 = todayCandles.slice(0, Math.min(6, todayCandles.length));
  const orHigh = Math.max(...todayFirst6.map(c => c.high));
  const orLow  = Math.min(...todayFirst6.map(c => c.low));
  const orRange = orHigh - orLow;

  // Day's high/low from today's candles
  const dayHigh = Math.max(...todayCandles.map(c => c.high));
  const dayLow  = Math.min(...todayCandles.map(c => c.low));

  // Previous close (last candle of previous day) — for gap calculation
  const prevClose = prevDayCandles.length ? prevDayCandles[prevDayCandles.length - 1].close : C[0];
  const gapPct    = prevClose > 0 ? ((todayCandles[0].open || C[0]) - prevClose) / prevClose * 100 : 0;

  // Previous day high/low — Varsity M2 Ch7: PDH/PDL are key S/R levels for intraday
  const pdHigh = prevDayCandles.length ? Math.max(...prevDayCandles.map(c => c.high)) : dayHigh;
  const pdLow  = prevDayCandles.length ? Math.min(...prevDayCandles.map(c => c.low))  : dayLow;

  // ── Varsity M2 Ch 7: Gap classification ──
  // Varsity distinguishes 4 gap types based on context. Previously we treated
  // every 1-6% gap identically; this classifier gives each its Varsity label
  // and a conviction multiplier used as a Gap & Go score bonus.
  //   COMMON      — small gap in range-bound stock (low conviction)
  //   BREAKAWAY   — gap out of consolidation with volume (highest conviction)
  //   CONTINUATION — mid-trend gap, trend-aligned (medium-high)
  //   EXHAUSTION  — gap after extended trend, often reverses (contrarian)
  let gapClass = 'NONE';
  let gapClassBonus = 0;
  if (Math.abs(gapPct) >= 1.0) {
    const _df = stockFundamentals[sym];   // daily fundamentals (may be undefined)
    const priorHi = prevDayCandles.length ? Math.max(...prevDayCandles.map(c => c.high)) : pdHigh;
    const priorLo = prevDayCandles.length ? Math.min(...prevDayCandles.map(c => c.low))  : pdLow;
    const priorRange = priorHi - priorLo;
    const priorRangePct = priorLo > 0 ? (priorRange / priorLo) * 100 : 0;
    // Breakaway: gap emerging from a tight prior range (range < 2.5%) with volume
    if (priorRangePct < 2.5 && volRatio > 2.0 && Math.abs(gapPct) >= 1.5) {
      gapClass = 'BREAKAWAY'; gapClassBonus = 12;
    }
    // Exhaustion: large gap (>= 4%) after stock already trending same direction on daily
    else if (Math.abs(gapPct) >= 4.0 && _df && _df.dowTheoryTrend === (gapPct > 0 ? 'UPTREND' : 'DOWNTREND')) {
      gapClass = 'EXHAUSTION'; gapClassBonus = -10;
    }
    // Continuation: trend-aligned gap of moderate size on elevated volume
    else if (Math.abs(gapPct) >= 1.5 && volRatio > 1.5 && _df && ((gapPct > 0 && _df.dowTheoryTrend === 'UPTREND') || (gapPct < 0 && _df.dowTheoryTrend === 'DOWNTREND'))) {
      gapClass = 'CONTINUATION'; gapClassBonus = 8;
    }
    // Everything else = Common gap (minimal conviction)
    else {
      gapClass = 'COMMON'; gapClassBonus = 0;
    }
  }

  // ── Varsity M2 Ch 22: Central Pivot Range (CPR) ──
  // Computed from prior day H/L/C. BC/TC act as intraday S/R; width predicts regime.
  const cpr = computeCPR(prevDayCandles, px);
  const nearCpr = cpr && px >= cpr.cprLo * 0.998 && px <= cpr.cprHi * 1.002;  // within 0.2% of CPR band
  const aboveCpr = cpr && px > cpr.cprHi;
  const belowCpr = cpr && px < cpr.cprLo;

  // ── Varsity M2 Ch 5-10: Candlestick pattern detection on 5-min ──
  // Use today's candles so pattern reflects the current session's psychology.
  // Declared with `let` because Ch 4 prior-trend filter below may demote weight.
  let bullPattern = detectBullishCandlePattern(todayCandles);
  let bearPattern = detectBearishCandlePattern(todayCandles);

  // ── Varsity M2 Ch 5-12 confluence: Candlestick + Volume multiplier ──
  // "A Hammer on 3x volume is meaningfully stronger than a Hammer on 0.5x
  // volume." Varsity: confluence of price action + volume = highest-conviction
  // entry. We modulate the pattern's weight by the volume environment of the
  // bar that printed the pattern. Multiplier range: 0.7x (weak vol) to 1.3x
  // (strong vol), applied BEFORE the Ch 4 prior-trend filter so the trend
  // context still demotes a high-vol continuation pattern.
  function _candleVolumeConfluence(pattern, vr) {
    if (!pattern) return pattern;
    let mult = 1.0;
    if (vr >= 3.0)      mult = 1.3;
    else if (vr >= 2.0) mult = 1.2;
    else if (vr >= 1.5) mult = 1.1;
    else if (vr >= 1.0) mult = 1.0;
    else if (vr >= 0.7) mult = 0.85;
    else                mult = 0.7;
    if (mult === 1.0) return pattern;
    return { ...pattern, weight: Math.round(pattern.weight * mult), description: pattern.description + ` (vol ${vr.toFixed(1)}x ${mult > 1 ? 'boost' : 'weak'})` };
  }
  if (bullPattern) bullPattern = _candleVolumeConfluence(bullPattern, volRatio);
  if (bearPattern) bearPattern = _candleVolumeConfluence(bearPattern, volRatio);

  // ── Varsity M2 Ch 4: Prior-trend filter for reversal patterns ──
  // Varsity: "A Bullish Engulfing is meaningful AFTER a downtrend. In an
  // uptrend it's just continuation." Compute session trend over the last
  // ~10 bars so reversal patterns in the WRONG trend context get demoted.
  let sessionTrend = 'RANGE';
  if (todayCandles.length >= 10) {
    const tcRecent = todayCandles.slice(-10);
    const slope = (tcRecent[tcRecent.length - 1].close - tcRecent[0].close) / tcRecent[0].close;
    if (slope > 0.003) sessionTrend = 'UP';
    else if (slope < -0.003) sessionTrend = 'DOWN';
  }
  // Bullish reversal patterns need a prior DOWN or RANGE context to have full weight.
  const bullReversalPatterns = ['Bullish Marubozu','Bullish Engulfing','Piercing Pattern','Morning Star','Bullish Harami','Hammer','Inverted Hammer','Dragonfly Doji'];
  if (bullPattern && sessionTrend === 'UP' && bullReversalPatterns.includes(bullPattern.name)) {
    bullPattern = { ...bullPattern, weight: Math.round(bullPattern.weight * 0.4), description: bullPattern.description + ' (uptrend context — continuation, not reversal)' };
  }
  // Bearish reversal patterns symmetric: only full-weight in UP or RANGE context.
  const bearReversalPatterns = ['Bearish Marubozu','Bearish Engulfing','Dark Cloud Cover','Evening Star','Shooting Star','Hanging Man','Gravestone Doji'];
  if (bearPattern && sessionTrend === 'DOWN' && bearReversalPatterns.includes(bearPattern.name)) {
    bearPattern = { ...bearPattern, weight: Math.round(bearPattern.weight * 0.4), description: bearPattern.description + ' (downtrend context — continuation, not reversal)' };
  }

  // ── Varsity M2 Ch 4: Risk-averse entry confirmation ──
  // "Risk-taker enters on the pattern candle; risk-averse waits for the NEXT
  // candle to confirm direction." A pattern that formed 1-2 bars ago AND
  // whose direction is still holding is a confirmed pattern — higher conviction.
  let bullPatternConfirmed = false, bearPatternConfirmed = false;
  if (todayCandles.length >= 3) {
    const priorBars = todayCandles.slice(0, todayCandles.length - 1);
    const priorBull = detectBullishCandlePattern(priorBars);
    const priorBear = detectBearishCandlePattern(priorBars);
    // Confirmed bull: pattern existed 1 bar ago + current candle closed higher
    if (priorBull && todayCandles[todayCandles.length - 1].close > todayCandles[todayCandles.length - 2].close) bullPatternConfirmed = true;
    if (priorBear && todayCandles[todayCandles.length - 1].close < todayCandles[todayCandles.length - 2].close) bearPatternConfirmed = true;
  }

  // ── Varsity M2 Ch 22: Virgin CPR detection ──
  // A previous-day CPR band that wasn't touched today yet stays "virgin" —
  // Varsity: virgin CPR acts as extra-strong S/R when price finally approaches
  // it. Iterate today's candles; if none intersect the CPR band, flag virgin.
  let cprVirgin = false;
  if (cpr) {
    const cprTouched = todayCandles.some(c => c.high >= cpr.cprLo && c.low <= cpr.cprHi);
    cprVirgin = !cprTouched;
  }

  // ── Varsity M2 Ch 12: Volume EXPANSION trend ──
  // "Expanding volume precedes sustained moves." Not just current vs avg,
  // but the LAST 3 BARS must show volume increasing. Distinguishes a
  // genuine breakout (vol ramping) from a late-stage move (one-bar spike
  // fading). Requires strictly or nearly-strictly monotonic increase AND
  // current bar above 1.5x avg to qualify.
  const vol3 = [V[n - 3] || 0, V[n - 2] || 0, V[n - 1] || 0];
  const volExpanding = vol3[2] > vol3[1] && vol3[1] >= vol3[0] * 0.8 && vol3[2] > avg20Vol * 1.5;
  const volContracting = vol3[2] < vol3[1] && vol3[1] < vol3[0]; // opposite: ramp fading

  // ── Varsity M2 Ch 12: Volume-Price Action 2x2 matrix ──
  // Price Δ vs Volume Δ — the four quadrants predict next-bar bias:
  //   price up + vol up   → CONFIRM BULL  (already rewarded in setups)
  //   price up + vol down → WEAK RALLY    (penalize bullish setups)
  //   price down + vol up → CONFIRM BEAR  (used in bear-pattern penalties)
  //   price down + vol down → WEAK DECLINE (potential exhaustion / bounce setup)
  const lastPriceUp   = last.close > last.open;
  const lastPriceDown = last.close < last.open;
  const vpaWeakRally    = lastPriceUp && volRatio < 0.8;
  const vpaWeakDecline  = lastPriceDown && volRatio < 0.8;
  const vpaConfirmBull  = lastPriceUp && volRatio >= 1.5;
  const vpaConfirmBear  = lastPriceDown && volRatio >= 1.5;

  // ── Varsity M2 Ch 11: Round-number (psychological) S/R ──
  // Price often hesitates at ₹100, ₹500, ₹1000 etc. Pick the step size by
  // magnitude, then flag when current price is within 0.3% of a round number.
  function _nearestRoundNumber(p) {
    let step;
    if (p < 100) step = 10;
    else if (p < 500) step = 50;
    else if (p < 1000) step = 100;
    else if (p < 5000) step = 500;
    else step = 1000;
    const nearest = Math.round(p / step) * step;
    return { level: nearest, step, distPct: Math.abs(p - nearest) / p * 100 };
  }
  const round = _nearestRoundNumber(px);
  const atRoundNumber = round.distPct < 0.3;

  // ── Varsity M2 Ch 16: Fibonacci retracement levels ──
  // Compute from the session swing (dayHigh → dayLow). In an uptrend that's
  // pulled back, the 38.2/50/61.8% levels act as support; 61.8% is the
  // "golden ratio" bounce zone Varsity highlights as highest-probability.
  const fibRange = dayHigh - dayLow;
  const fib = {
    lvl236: dayHigh - fibRange * 0.236,
    lvl382: dayHigh - fibRange * 0.382,
    lvl500: dayHigh - fibRange * 0.500,
    lvl618: dayHigh - fibRange * 0.618,
    lvl786: dayHigh - fibRange * 0.786,
  };
  // Tag the Fib level the price is currently nearest to (within 0.5% of it)
  let nearFib = null;
  if (fibRange > 0) {
    const fibEntries = [
      { name: '61.8% (golden ratio)', level: fib.lvl618, strength: 10 },
      { name: '50%',                   level: fib.lvl500, strength: 7 },
      { name: '38.2%',                 level: fib.lvl382, strength: 6 },
      { name: '78.6%',                 level: fib.lvl786, strength: 5 },
      { name: '23.6%',                 level: fib.lvl236, strength: 3 },
    ];
    for (const fe of fibEntries) {
      if (Math.abs(px - fe.level) / px < 0.005) { nearFib = fe; break; }
    }
  }

  // ── Varsity M2 Ch 11: S/R touch count ──
  // "A level tested 3+ times is strong; once is weak." Count how many 5-min
  // candles intersected each key level (within 0.15% tolerance). Used as a
  // breakout strength multiplier in the Breakout setup.
  function _touches(level) {
    if (!level || !isFinite(level)) return 0;
    const tol = level * 0.0015;
    return todayCandles.reduce((acc, c) => (c.high >= level - tol && c.low <= level + tol ? acc + 1 : acc), 0);
  }
  const dayHighTouches = _touches(dayHigh);
  const orHighTouches  = _touches(orHigh);
  const pdHighTouches  = _touches(pdHigh);
  const pdLowTouches   = _touches(pdLow);

  // ── Varsity M2 Ch 12: On-Balance Volume (OBV) + divergence ──
  // OBV adds volume on up-closes, subtracts on down-closes, accumulates as a
  // directional running total. Ch 12: "OBV often leads price — when OBV makes
  // a new high before price does, accumulation is underway."
  // Bullish div: price makes lower low, OBV makes higher low -> reversal up.
  // Bearish div: price makes higher high, OBV makes lower high -> reversal down.
  const obv = [0];
  for (let i = 1; i < n; i++) {
    const prev = obv[obv.length - 1];
    if (C[i] > C[i - 1]) obv.push(prev + V[i]);
    else if (C[i] < C[i - 1]) obv.push(prev - V[i]);
    else obv.push(prev);
  }
  let obvBullDiv = false, obvBearDiv = false;
  if (n >= 25) {
    const loIdx = _findPivot(C, (a, b) => a < b, 20);
    if (C[n - 1] < C[loIdx] * 1.001 && obv[n - 1] > obv[loIdx]) obvBullDiv = true;
    const hiIdx = _findPivot(C, (a, b) => a > b, 20);
    if (C[n - 1] > C[hiIdx] * 0.999 && obv[n - 1] < obv[hiIdx]) obvBearDiv = true;
  }

  // ── Relative Strength vs Nifty (Dow Theory implicit: averages must confirm) ──
  // Stock's daily % change compared to Nifty's. A stock up 1% when Nifty is
  // down 1% has +2% relative strength — strong bullish signal. Inversely,
  // -2% relative = weak stock, favors mean-reversion (bounce) setup.
  const stockDailyChange = prevClose > 0 ? ((px - prevClose) / prevClose) * 100 : 0;
  const relStrength = (_niftyChange !== null && typeof _niftyChange === 'number')
    ? +(stockDailyChange - _niftyChange).toFixed(2)
    : null;

  // ── Varsity M9 intraday rule: ADR (Average Daily Range) used % ──
  // "If stock has already consumed X% of its typical daily range, the
  // remaining move is limited." Compute ADR from prior-day ranges in the
  // candle history (excluding today), then express today's range as % of ADR.
  //   ADR used > 80%  -> likely exhausted, avoid new long entries
  //   ADR used < 30%  -> lots of room, favorable for trend continuation
  let adrUsedPct = 0, adrAvg = 0;
  {
    const seenDates = new Map(); // dateStr -> {hi, lo}
    for (const c of candles) {
      const d = _candleDateStr(c.date || c.timestamp);
      if (!d || d === todayStart) continue;
      const cur = seenDates.get(d);
      if (!cur) seenDates.set(d, { hi: c.high, lo: c.low });
      else { if (c.high > cur.hi) cur.hi = c.high; if (c.low < cur.lo) cur.lo = c.low; }
    }
    const ranges = [...seenDates.values()]
      .map(r => r.lo > 0 ? ((r.hi - r.lo) / r.lo) * 100 : 0)
      .filter(r => r > 0);
    if (ranges.length >= 2) {
      adrAvg = +(ranges.reduce((a, b) => a + b, 0) / ranges.length).toFixed(2);
      const todayRangePct = dayLow > 0 ? ((dayHigh - dayLow) / dayLow) * 100 : 0;
      adrUsedPct = adrAvg > 0 ? +((todayRangePct / adrAvg) * 100).toFixed(0) : 0;
    }
  }

  // ── Varsity M2 Ch 11: Role reversal (broken resistance becomes support) ──
  // "A level that was resistance becomes support once decisively broken."
  // Check today's candles: did we break above the level AND later retest it
  // from above without breaking back down? That's role-reversal in action.
  function _roleReversalSupport(level) {
    if (!level || todayCandles.length < 4) return false;
    const broke = todayCandles.some(c => c.high > level * 1.005);        // broke by 0.5%+
    const retest = todayCandles.slice(-5).some(c => c.low <= level * 1.002 && c.close > level);  // pulled back to touch
    return broke && retest && px > level;                                // and still holding above
  }
  const pdhRoleSupport  = _roleReversalSupport(pdHigh);
  const orHighRoleSupport = _roleReversalSupport(orHigh);

  // ── Varsity M2 Ch 7: Failed-breakout / Bull-trap detection ──
  // "A breakout that reverses within 3 bars is a failed breakout — the
  // ORIGINAL level has reasserted itself." Check if any of the last 3
  // bars' HIGH exceeded the level but current close is back BELOW it.
  function _failedBreak(level) {
    if (!level || todayCandles.length < 4) return false;
    const recent = todayCandles.slice(-4, -1); // 3 prior bars (not current)
    const brokeAbove = recent.some(c => c.high > level);
    const closedBelow = px < level * 0.999;   // back inside with ~0.1% buffer
    return brokeAbove && closedBelow;
  }
  const orFailedBreak  = _failedBreak(orHigh);
  const pdhFailedBreak = _failedBreak(pdHigh);

  // ── Varsity M2 Ch 11: Equal highs / equal lows detection ──
  // "Multiple matched highs form coiled resistance; matched lows form coiled
  // support." Distinct from touch-count: equal highs mean two+ candles
  // printed the exact same high (within 0.1% tolerance), signaling price
  // memory — a failed-breakout cluster ripe for a decisive break.
  function _equalExtremes(values, tol) {
    // Count how many of the last ~15 bars' values are within `tol` of the max/min
    const window = values.slice(-15);
    if (window.length < 3) return { equalHi: 0, equalLo: 0 };
    const mx = Math.max(...window);
    const mn = Math.min(...window);
    const equalHi = window.filter(v => mx - v <= mx * tol).length;
    const equalLo = window.filter(v => v - mn <= mn * tol).length;
    return { equalHi, equalLo };
  }
  const eqExtremes = _equalExtremes(todayCandles.map(c => c.high), 0.001);
  const eqLowExtremes = _equalExtremes(todayCandles.map(c => c.low), 0.001);
  const hasEqualHighs = eqExtremes.equalHi >= 2;  // 2+ matched highs = coiled resistance
  const hasEqualLows  = eqLowExtremes.equalLo >= 2; // 2+ matched lows = coiled support

  // ── Varsity M2 Ch 16: Bollinger Squeeze (width contraction precedes expansion) ──
  // Compute BB width for each of the last ~30 bars and check whether current
  // width is in the bottom 30% of that window. A squeeze that resolves with
  // price closing above the upper band = textbook breakout trigger.
  let bbSqueeze = false, bbSqueezeReleaseUp = false;
  try {
    const widths = [];
    for (let i = Math.max(20, n - 30); i <= n; i++) {
      const win = C.slice(i - 20, i);
      if (win.length < 20) continue;
      const mean = win.reduce((a, b) => a + b, 0) / 20;
      const variance = win.reduce((a, v) => a + (v - mean) ** 2, 0) / 20;
      const sd = Math.sqrt(variance);
      widths.push(sd * 4 / (mean || 1)); // width-normalized-by-mean
    }
    if (widths.length >= 10) {
      const curW = widths[widths.length - 1];
      const sorted = [...widths].sort((a, b) => a - b);
      const p30 = sorted[Math.floor(sorted.length * 0.3)];
      bbSqueeze = curW <= p30;
      bbSqueezeReleaseUp = bbSqueeze && px > bbUpper; // fresh release above upper
    }
  } catch (e) { /* ok */ }

  // Supertrend on 5-min
  let stBull = false;
  try {
    const atrArr = candles.slice(1).map((c, i) => Math.max(c.high - c.low, Math.abs(c.high - candles[i].close), Math.abs(c.low - candles[i].close)));
    const atr14 = atrArr.slice(-14).reduce((a, b) => a + b, 0) / 14;
    let st = C[0], trend = 1;
    for (let i = 1; i < n; i++) {
      const mid = (H[i] + L[i]) / 2;
      const up = mid + 3 * (atrArr[i - 1] || atr14), dn = mid - 3 * (atrArr[i - 1] || atr14);
      if (trend === 1) st = Math.max(st, dn); else st = Math.min(st, up);
      if (C[i] < st && trend === 1) { trend = -1; st = up; } else if (C[i] > st && trend === -1) { trend = 1; st = dn; }
    }
    stBull = trend === 1;
  } catch (e) { /* ok */ }

  // ADX on 5-min
  const adxVal = adx(candles, 14);

  // ── SETUP 1: VWAP RECLAIM (Varsity M2 Ch13: institutional reference price) ──
  // Price was below VWAP recently and is now reclaiming it from below with volume.
  // Varsity: VWAP is THE institutional benchmark; reclaim = institutions defending the level.
  let vwapScore = 0, vwapDetail = [];
  // Core requirement: price must have been below VWAP recently (last 5 bars) and now at/above
  if (recentVWAPBelow && pctVWAP > -0.3 && pctVWAP < 2.0) {
    // Actual reclaim pattern detected
    if (pctVWAP > 0.1 && pctVWAP < 2.0) {
      vwapScore += _gain('VWAP', 30, `Reclaimed VWAP (+${pctVWAP.toFixed(1)}%)`);  // just crossed above — the sweet spot
      vwapDetail.push(`Reclaimed VWAP (+${pctVWAP.toFixed(1)}%)`);
    } else if (pctVWAP >= -0.3 && pctVWAP <= 0.1) {
      vwapScore += _gain('VWAP', 20, 'Testing VWAP from below'); // approaching VWAP from below — potential reclaim in progress
      vwapDetail.push('Testing VWAP from below');
    }
  } else if (!recentVWAPBelow && pctVWAP > 0 && pctVWAP < 0.5) {
    vwapScore += _gain('VWAP', 10, 'At VWAP (no recent break)'); // sitting at VWAP but no reclaim pattern — weak signal
    vwapDetail.push('At VWAP (no recent break)');
  }
  // Volume confirmation — Varsity M2: volume validates the move
  if (volRatio > 2.0) { vwapScore += _gain('VWAP', 15, `Vol ${volRatio.toFixed(1)}x surge`); vwapDetail.push(`Vol ${volRatio.toFixed(1)}x surge`); }
  else if (volRatio > 1.5) { vwapScore += _gain('VWAP', 10, `Vol ${volRatio.toFixed(1)}x`); vwapDetail.push(`Vol ${volRatio.toFixed(1)}x`); }
  if (lastRSI > 40 && lastRSI < 60) { vwapScore += _gain('VWAP', 8, 'RSI neutral zone'); vwapDetail.push('RSI neutral zone'); }
  if (ema9[n - 1] > ema20[n - 1]) { vwapScore += _gain('VWAP', 8, 'EMA9>20 bullish'); vwapDetail.push('EMA9>20 bullish'); }
  if (macdBull) { vwapScore += _gain('VWAP', 8, 'MACD bull'); vwapDetail.push('MACD bull'); }
  if (macdCross) { vwapScore += _gain('VWAP', 6, 'Fresh MACD cross'); vwapDetail.push('Fresh MACD cross'); }
  if (stBull) { vwapScore += _gain('VWAP', 5, 'ST bull'); vwapDetail.push('ST bull'); }
  // Stochastic confirmation (Varsity M2 Ch18)
  if (stochK > 20 && stochK < 80) { vwapScore += _gain('VWAP', 4, 'Stoch healthy'); vwapDetail.push('Stoch healthy'); }
  // PDH/PDL context — Varsity M2: reclaim near PDL = institutional support level
  if (Math.abs(px - pdLow) / pdLow < 0.01) { vwapScore += _gain('VWAP', 5, 'Near PDL support'); vwapDetail.push('Near PDL support'); }
  // Penalty: too far above VWAP = chasing, not reclaim
  if (pctVWAP > 2.0) { vwapScore += _penalty('VWAP', 20, 'Extended from VWAP — chasing'); vwapDetail.push('Extended from VWAP — chasing'); }
  if (pctVWAP < -1.5) { vwapScore += _penalty('VWAP', 25, 'Still well below VWAP'); vwapDetail.push('Still well below VWAP'); }
  // Varsity M2 Ch 5-10: bullish candle pattern confirming the reclaim
  if (bullPattern && vwapScore > 0) {
    const bonus = Math.round(bullPattern.weight * 0.6);
    vwapScore += _gain('VWAP', bonus, `${bullPattern.name} at reclaim`);
    vwapDetail.push(`${bullPattern.name} at reclaim`);
  }
  // Varsity M2 Ch 22: reclaim happening at/above Central Pivot = institutional confluence
  if (cpr && nearCpr) { vwapScore += _gain('VWAP', 6, 'At CPR — institutional level'); vwapDetail.push('At CPR'); }
  else if (cpr && aboveCpr && px - cpr.cprHi < px * 0.005) { vwapScore += _gain('VWAP', 4, 'Just cleared CPR'); vwapDetail.push('Just cleared CPR'); }
  // Varsity M2 Ch 14+15: bullish divergence strengthens any reclaim setup
  if (rsiBullDiv && vwapScore > 0) { vwapScore += _gain('VWAP', 8, 'RSI bullish divergence'); vwapDetail.push('RSI bull div'); }
  if (macdBullDiv && vwapScore > 0) { vwapScore += _gain('VWAP', 5, 'MACD bullish divergence'); vwapDetail.push('MACD bull div'); }
  // Varsity M2 Ch 4: risk-averse confirmed pattern
  if (bullPatternConfirmed && vwapScore > 0) { vwapScore += _gain('VWAP', 5, 'Pattern confirmed next bar'); vwapDetail.push('Confirmed'); }
  // Varsity M2 Ch 11: reclaim at round number (e.g., price crossing back above ₹500)
  if (atRoundNumber && lastPriceUp) { vwapScore += _gain('VWAP', 4, `At ₹${round.level} support`); vwapDetail.push(`At ₹${round.level}`); }
  // Varsity M2 Ch 12: weak rally check — reclaim on shrinking volume = suspect
  if (vpaWeakRally && vwapScore >= 40) { vwapScore += _penalty('VWAP', 8, 'Weak rally (vol declining)'); vwapDetail.push('Weak rally'); }
  // Relative strength: reclaiming VWAP while outperforming Nifty = institutional interest
  if (relStrength !== null && relStrength > 1.0 && vwapScore > 0) { vwapScore += _gain('VWAP', 5, `Outperforming Nifty by ${relStrength.toFixed(1)}%`); vwapDetail.push(`RS +${relStrength.toFixed(1)}%`); }
  // OBV bullish div supports reclaim (smart-money accumulation)
  if (obvBullDiv && vwapScore > 0) { vwapScore += _gain('VWAP', 5, 'OBV bullish divergence'); vwapDetail.push('OBV bull div'); }
  vwapScore = Math.max(0, Math.min(100, vwapScore));

  // ── SETUP 2: GAP & GO (Varsity M2 Ch7: gap theory + follow-through) ──
  // Varsity: unfilled gaps with volume confirmation signal strong directional conviction.
  // "Gap up + hold above gap fill level = bullish continuation." Must NOT have filled the gap.
  let gapScore = 0, gapDetail = [];
  const absGap = Math.abs(gapPct);
  const gapFillLevel = prevClose; // the level the gap would "fill" to
  const gapUnfilled  = gapPct > 0 ? (dayLow > gapFillLevel) : (gapPct < 0 ? (dayHigh < gapFillLevel) : false);
  if (absGap >= 1.0 && absGap <= 6.0) {
    gapScore += _gain('GAP', 20, `Gap ${gapPct > 0 ? '+' : ''}${gapPct.toFixed(1)}%`);
    gapDetail.push(`Gap ${gapPct > 0 ? '+' : ''}${gapPct.toFixed(1)}%`);
  }
  // Varsity M2 Ch7: unfilled gap = much stronger signal than a partially filled one
  if (gapUnfilled && absGap >= 1.0) {
    gapScore += _gain('GAP', 15, 'Gap unfilled — strong conviction');
    gapDetail.push('Gap unfilled — strong conviction');
  }
  // Follow-through: price at/above gap high (bullish) or at/below gap low (bearish)
  if (gapPct > 0.5 && px > orHigh) {
    gapScore += _gain('GAP', 20, 'Follow-through above OR');  // bullish gap with follow-through above OR high
    gapDetail.push('Follow-through above OR');
  } else if (gapPct < -0.5 && px < orLow) {
    gapScore += _gain('GAP', 20, 'Gap-down break below OR');  // bearish gap with break below OR
    gapDetail.push('Gap-down break below OR');
  }
  // Volume — Varsity M2: gap must be backed by volume to distinguish from noise
  if (volRatio > 2.5) { gapScore += _gain('GAP', 20, `Vol spike ${volRatio.toFixed(1)}x`); gapDetail.push(`Vol spike ${volRatio.toFixed(1)}x`); }
  else if (volRatio > 2.0) { gapScore += _gain('GAP', 15, `Vol ${volRatio.toFixed(1)}x`); gapDetail.push(`Vol ${volRatio.toFixed(1)}x`); }
  else if (volRatio > 1.5) { gapScore += _gain('GAP', 8, `Vol ${volRatio.toFixed(1)}x`); gapDetail.push(`Vol ${volRatio.toFixed(1)}x`); }
  if (adxVal > 25) { gapScore += _gain('GAP', 8, `ADX ${adxVal.toFixed(0)} trending`); gapDetail.push(`ADX ${adxVal.toFixed(0)} trending`); }
  if (macdCross) { gapScore += _gain('GAP', 8, 'Fresh MACD cross'); gapDetail.push('Fresh MACD cross'); }
  // RSI in momentum zone (50-75) — not exhausted but not dead (Varsity M2 Ch14)
  if (gapPct > 0 && lastRSI > 50 && lastRSI < 75) { gapScore += _gain('GAP', 6, 'RSI momentum zone'); gapDetail.push('RSI momentum zone'); }
  // EMA alignment — trend confirming the gap direction
  if (gapPct > 0 && ema9[n - 1] > ema20[n - 1]) { gapScore += _gain('GAP', 5, 'EMA aligned bullish'); gapDetail.push('EMA aligned bullish'); }
  // Penalty: gap too large = likely to fade (Varsity: >5% gaps often see partial retracement)
  if (absGap > 6) { gapScore += _penalty('GAP', 20, 'Gap too wide — fade risk'); gapDetail.push('Gap too wide — fade risk'); }
  else if (absGap > 4) { gapScore += _penalty('GAP', 5, 'Wide gap — partial fade risk'); gapDetail.push('Wide gap — partial fade risk'); }
  // Penalty: gap filled = the thesis is invalidated
  if (!gapUnfilled && absGap >= 1.0) { gapScore += _penalty('GAP', 15, 'Gap filled — weak'); gapDetail.push('Gap filled — weak'); }
  if (absGap < 0.5) { gapScore = 0; gapDetail = ['No gap']; } // no gap = no setup
  // Varsity M2 Ch 22: narrow CPR day = directional bias, perfect for gap-and-go
  if (cpr && cpr.type === 'NARROW' && gapScore > 0) { gapScore += _gain('GAP', 8, `Narrow CPR (${cpr.widthPct.toFixed(2)}%) — trending day`); gapDetail.push('Narrow CPR — trending day'); }
  else if (cpr && cpr.type === 'WIDE') { gapScore += _penalty('GAP', 5, `Wide CPR (${cpr.widthPct.toFixed(2)}%) — range day, gaps fade`); gapDetail.push('Wide CPR — fade risk'); }
  // Bullish gap above R1 (Ch 22) = directional breakout above pivot resistance
  if (cpr && gapPct > 0 && px > cpr.R1) { gapScore += _gain('GAP', 7, 'Price above R1 — pivot breakout'); gapDetail.push('Above R1'); }
  // Bullish candle pattern confirming the gap direction
  if (bullPattern && gapPct > 0 && gapScore > 0) {
    const bonus = Math.round(bullPattern.weight * 0.5);
    gapScore += _gain('GAP', bonus, `${bullPattern.name} confirming gap-up`);
    gapDetail.push(`${bullPattern.name} confirm`);
  }
  // Bearish pattern on a gap-up = exhaustion / fade risk
  if (bearPattern && gapPct > 0 && bearPattern.weight >= 12) { gapScore += _penalty('GAP', 10, `${bearPattern.name} — exhaustion on gap`); gapDetail.push(`${bearPattern.name} exhaustion`); }
  // Varsity M2 Ch 14+15: divergence warnings on gap-ups (bearish div = fade)
  if (rsiBearDiv && gapPct > 0) { gapScore += _penalty('GAP', 8, 'RSI bearish divergence on gap-up'); gapDetail.push('RSI bear div'); }
  if (macdBearDiv && gapPct > 0) { gapScore += _penalty('GAP', 4, 'MACD bearish divergence'); gapDetail.push('MACD bear div'); }
  // Varsity M2 Ch 22: virgin R1/R2 = extra conviction when gap clears them
  if (cpr && cprVirgin && aboveCpr && gapPct > 0) { gapScore += _gain('GAP', 6, 'Gap cleared virgin CPR'); gapDetail.push('Virgin CPR cleared'); }
  // Varsity M2 Ch 4: confirmed gap direction via next-bar pattern
  if (bullPatternConfirmed && gapPct > 0) { gapScore += _gain('GAP', 5, 'Pattern confirmed'); gapDetail.push('Confirmed'); }
  // Varsity M2 Ch 11: gap clearing a round number = psychological breakout
  if (atRoundNumber && gapPct > 0 && lastPriceUp) { gapScore += _gain('GAP', 5, `Gap cleared ₹${round.level}`); gapDetail.push(`Above ₹${round.level}`); }
  // Varsity M2 Ch 12: gap-up needs vol confirmation. Weak rally = fade warning.
  if (vpaWeakRally && gapPct > 0 && gapScore >= 40) { gapScore += _penalty('GAP', 8, 'Gap fading on weak volume'); gapDetail.push('Weak rally'); }
  // Varsity M2 Ch 7: gap classification (Breakaway / Continuation / Exhaustion / Common)
  if (gapClass === 'BREAKAWAY') { gapScore += _gain('GAP', gapClassBonus, 'Breakaway gap (from tight range + vol)'); gapDetail.push('Breakaway'); }
  else if (gapClass === 'CONTINUATION') { gapScore += _gain('GAP', gapClassBonus, 'Continuation gap (trend-aligned)'); gapDetail.push('Continuation'); }
  else if (gapClass === 'EXHAUSTION') { gapScore += _penalty('GAP', Math.abs(gapClassBonus), 'Exhaustion gap (after extended trend)'); gapDetail.push('Exhaustion'); }
  // Relative strength vs Nifty during gap-up
  if (relStrength !== null && gapPct > 0 && relStrength > 1.5) { gapScore += _gain('GAP', 5, `Outperforming Nifty (${relStrength.toFixed(1)}%)`); gapDetail.push(`RS +${relStrength.toFixed(1)}%`); }
  // ADR exhaustion: if today's range is already at ADR, gap-and-go has no room
  if (adrUsedPct > 80 && gapPct > 0) { gapScore += _penalty('GAP', 8, `ADR ${adrUsedPct}% used — gap already spent the move`); gapDetail.push(`ADR ${adrUsedPct}%`); }
  gapScore = Math.max(0, Math.min(100, gapScore));

  // ── SETUP 3: BREAKOUT (Varsity M2 Ch7+16: S/R breakout + volume expansion) ──
  // Varsity M2 Ch7: "A breakout accompanied by volume surge validates the move."
  // Ch16: "Range contraction leads to range expansion" — Bollinger Squeeze precedes breakout.
  // Price breaking above OR high, day high, or PDH with volume surge.
  let breakoutScore = 0, breakoutDetail = [];
  const nearDayHigh = px >= dayHigh * 0.998;  // within 0.2% of day high
  const aboveOR     = px > orHigh;
  const abovePDH    = px > pdHigh;  // Varsity M2: PDH is a key intraday resistance
  if (nearDayHigh) { breakoutScore += _gain('BRK', 20, 'At day high'); breakoutDetail.push('At day high'); }
  if (aboveOR) { breakoutScore += _gain('BRK', 15, 'Above OR'); breakoutDetail.push('Above OR'); }
  if (abovePDH) { breakoutScore += _gain('BRK', 10, 'Above PDH — strong'); breakoutDetail.push('Above PDH — strong'); }
  // Varsity M2 Ch7: volume MUST confirm the breakout — this is non-negotiable
  if (volRatio > 2.5) { breakoutScore += _gain('BRK', 20, `Vol ${volRatio.toFixed(1)}x surge`); breakoutDetail.push(`Vol ${volRatio.toFixed(1)}x surge`); }
  else if (volRatio > 2.0) { breakoutScore += _gain('BRK', 15, `Vol ${volRatio.toFixed(1)}x`); breakoutDetail.push(`Vol ${volRatio.toFixed(1)}x`); }
  else if (volRatio > 1.5) { breakoutScore += _gain('BRK', 8, `Vol ${volRatio.toFixed(1)}x`); breakoutDetail.push(`Vol ${volRatio.toFixed(1)}x`); }
  // Varsity M2 Ch16: Bollinger squeeze preceding breakout = compressed energy releasing
  if (bbPct > 0.95) { breakoutScore += _gain('BRK', 10, 'BB upper breakout'); breakoutDetail.push('BB upper breakout'); }
  // ADX > 25 = trend forming (Varsity M2: ADX measures trend STRENGTH)
  if (adxVal > 30) { breakoutScore += _gain('BRK', 10, `ADX ${adxVal.toFixed(0)} strong trend`); breakoutDetail.push(`ADX ${adxVal.toFixed(0)} strong trend`); }
  else if (adxVal > 25) { breakoutScore += _gain('BRK', 6, `ADX ${adxVal.toFixed(0)} trending`); breakoutDetail.push(`ADX ${adxVal.toFixed(0)} trending`); }
  if (ema9[n - 1] > ema20[n - 1]) { breakoutScore += _gain('BRK', 5, 'EMA aligned'); breakoutDetail.push('EMA aligned'); }
  if (stBull) { breakoutScore += _gain('BRK', 5, 'ST bull'); breakoutDetail.push('ST bull'); }
  if (macdBull) { breakoutScore += _gain('BRK', 5, 'MACD bull'); breakoutDetail.push('MACD bull'); }
  // Varsity M2 Ch18: Stochastic > 50 during breakout = momentum confirming
  if (stochK > 50 && stochK < 85) { breakoutScore += _gain('BRK', 4, 'Stoch confirming'); breakoutDetail.push('Stoch confirming'); }
  // OR range target: Varsity M2 Ch7: measure the OR range, project it above breakout
  // This is implicit in the TGT calc but helps score — narrow OR = tight setup
  if (orRange > 0 && orRange / px < 0.015) { breakoutScore += _gain('BRK', 3, 'Tight OR range'); breakoutDetail.push('Tight OR range'); }
  // Penalty: breakout with weak volume = fake-out (Varsity M2 Ch7: "volume is the litmus test")
  if (nearDayHigh && volRatio < 1.0) { breakoutScore += _penalty('BRK', 25, 'Low vol — likely fake-out'); breakoutDetail.push('Low vol — likely fake-out'); }
  // Penalty: RSI overbought = exhaustion breakout
  if (lastRSI > 80) { breakoutScore += _penalty('BRK', 15, 'RSI exhaustion zone'); breakoutDetail.push('RSI exhaustion zone'); }
  else if (lastRSI > 75) { breakoutScore += _penalty('BRK', 8, 'RSI overbought'); breakoutDetail.push('RSI overbought'); }
  // Varsity M2 Ch 22: CPR pivot resistance breakouts (R1, R2 are stronger than day-high alone)
  if (cpr && px > cpr.R2) { breakoutScore += _gain('BRK', 10, 'Above R2 — strong pivot breakout'); breakoutDetail.push('Above R2'); }
  else if (cpr && px > cpr.R1) { breakoutScore += _gain('BRK', 6, 'Above R1 — pivot breakout'); breakoutDetail.push('Above R1'); }
  // Narrow CPR confirms trending-day breakout bias
  if (cpr && cpr.type === 'NARROW' && breakoutScore >= 30) { breakoutScore += _gain('BRK', 6, `Narrow CPR (${cpr.widthPct.toFixed(2)}%) — trending day`); breakoutDetail.push('Narrow CPR'); }
  else if (cpr && cpr.type === 'WIDE') { breakoutScore += _penalty('BRK', 8, `Wide CPR (${cpr.widthPct.toFixed(2)}%) — range day fade risk`); breakoutDetail.push('Wide CPR range day'); }
  // Varsity M2 Ch 5-10: bullish pattern confirming the breakout
  if (bullPattern && bullPattern.weight >= 12 && breakoutScore >= 30) {
    const bonus = Math.round(bullPattern.weight * 0.5);
    breakoutScore += _gain('BRK', bonus, `${bullPattern.name} confirming breakout`);
    breakoutDetail.push(`${bullPattern.name}`);
  }
  // Bearish reversal pattern at day high = classic fake-out signal (Varsity M2 Ch 7+10)
  if (bearPattern && bearPattern.weight >= 12 && nearDayHigh) {
    breakoutScore += _penalty('BRK', bearPattern.weight, `${bearPattern.name} at highs — fake-out risk`);
    breakoutDetail.push(`${bearPattern.name} at highs`);
  }
  // Varsity M2 Ch 11: S/R touch count — a level tested 3+ times is "strong".
  // Breaking a 3+ touched level is more significant than breaking a 1-touch level.
  if (aboveOR && orHighTouches >= 3) { breakoutScore += _gain('BRK', 8, `OR tested ${orHighTouches}x — strong break`); breakoutDetail.push(`OR ${orHighTouches}x`); }
  else if (aboveOR && orHighTouches >= 2) { breakoutScore += _gain('BRK', 4, `OR tested ${orHighTouches}x`); breakoutDetail.push(`OR ${orHighTouches}x`); }
  if (abovePDH && pdHighTouches >= 3) { breakoutScore += _gain('BRK', 6, `PDH tested ${pdHighTouches}x`); breakoutDetail.push(`PDH ${pdHighTouches}x`); }
  if (nearDayHigh && dayHighTouches >= 4) { breakoutScore += _gain('BRK', 6, `Day high tested ${dayHighTouches}x — coiled`); breakoutDetail.push(`DH ${dayHighTouches}x coiled`); }
  // Varsity M2 Ch 16: Bollinger Squeeze release — compressed energy unleashing.
  if (bbSqueezeReleaseUp) { breakoutScore += _gain('BRK', 12, 'BB squeeze release — compressed → expansion'); breakoutDetail.push('BB squeeze release'); }
  else if (bbSqueeze) { breakoutScore += _gain('BRK', 4, 'BB squeeze — coiled, pending release'); breakoutDetail.push('BB squeeze'); }
  // Varsity M2 Ch 14+15: bearish divergence at breakout = classic fake-out
  // warning — price made new high but momentum didn't confirm.
  if (rsiBearDiv) { breakoutScore += _penalty('BRK', 12, 'RSI bearish divergence — fake-out risk'); breakoutDetail.push('RSI bear div'); }
  if (macdBearDiv) { breakoutScore += _penalty('BRK', 6, 'MACD bearish divergence'); breakoutDetail.push('MACD bear div'); }
  // Varsity M2 Ch 22: breakout above a VIRGIN pivot level = extra-strong move.
  if (cpr && cprVirgin && aboveCpr) { breakoutScore += _gain('BRK', 8, 'Broke virgin CPR — untested resistance'); breakoutDetail.push('Virgin CPR break'); }
  // Varsity M2 Ch 11: breaking above a round number = psychological breakout
  if (atRoundNumber && lastPriceUp) { breakoutScore += _gain('BRK', 5, `Clearing ₹${round.level} — psychological resistance`); breakoutDetail.push(`Above ₹${round.level}`); }
  // Varsity M2 Ch 4: confirmed pattern (2-bar) adds conviction
  if (bullPatternConfirmed) { breakoutScore += _gain('BRK', 5, 'Pattern confirmed next bar'); breakoutDetail.push('Confirmed'); }
  // Varsity M2 Ch 12: weak rally penalty — price up on shrinking volume = fade risk
  if (vpaWeakRally && breakoutScore >= 40) { breakoutScore += _penalty('BRK', 10, 'Weak rally (vol declining) — fade risk'); breakoutDetail.push('Weak rally'); }
  // Varsity M2 Ch 14: RSI 50 midline cross = momentum bias flipped bullish
  if (rsiCrossedMidlineUp) { breakoutScore += _gain('BRK', 6, 'RSI crossed 50 midline up'); breakoutDetail.push('RSI>50 cross'); }
  else if (rsiAboveMidline && breakoutScore >= 40) { breakoutScore += _gain('BRK', 3, 'RSI above 50 (bull zone)'); breakoutDetail.push('RSI>50'); }
  // Varsity M2 Ch 12: volume expanding across last 3 bars = sustainable breakout
  if (volExpanding) { breakoutScore += _gain('BRK', 6, 'Volume expanding 3-bar'); breakoutDetail.push('Vol expanding'); }
  else if (volContracting && breakoutScore >= 40) { breakoutScore += _penalty('BRK', 5, 'Volume contracting — late-stage move'); breakoutDetail.push('Vol contracting'); }
  // Varsity M2 Ch 15: MACD histogram signals (separate from line-signal cross)
  if (macdHistZeroUp) { breakoutScore += _gain('BRK', 8, 'MACD histogram zero-cross up'); breakoutDetail.push('Hist 0-cross'); }
  else if (macdHistRising) { breakoutScore += _gain('BRK', 4, 'MACD histogram accelerating'); breakoutDetail.push('Hist rising'); }
  // Varsity M2 Ch 11: equal highs = coiled resistance about to release
  if (hasEqualHighs && nearDayHigh) { breakoutScore += _gain('BRK', 7, `Equal highs (${eqExtremes.equalHi}x) — coiled release`); breakoutDetail.push(`Eq highs ${eqExtremes.equalHi}x`); }
  // Varsity M2 Ch 13: breakout already above VWAP +2σ = overextended, likely mean-revert
  if (above2Sigma) { breakoutScore += _penalty('BRK', 8, 'Above VWAP +2σ band — statistically overextended'); breakoutDetail.push('>VWAP +2σ'); }
  // Varsity M2 Ch 7: failed-breakout / bull-trap penalty — price poked above
  // a level in the last 3 bars but came back below, invalidating the break.
  if (orFailedBreak) { breakoutScore += _penalty('BRK', 12, 'Failed OR break — bull trap'); breakoutDetail.push('OR bull trap'); }
  if (pdhFailedBreak) { breakoutScore += _penalty('BRK', 10, 'Failed PDH break — bull trap'); breakoutDetail.push('PDH bull trap'); }
  // Varsity M2 Ch 12: OBV bearish divergence at breakout = accumulation not confirming
  if (obvBearDiv) { breakoutScore += _penalty('BRK', 10, 'OBV bearish divergence — distribution'); breakoutDetail.push('OBV bear div'); }
  // Varsity M2 Ch 11: role reversal — broken resistance acting as support = confirmed breakout structure
  if (pdhRoleSupport) { breakoutScore += _gain('BRK', 7, 'PDH role-reversed (resistance→support held)'); breakoutDetail.push('PDH role-rev'); }
  if (orHighRoleSupport) { breakoutScore += _gain('BRK', 5, 'OR role-reversed (held retest)'); breakoutDetail.push('OR role-rev'); }
  // Relative strength vs Nifty — breakouts are more trustworthy when stock is outperforming
  if (relStrength !== null && relStrength > 1.5) { breakoutScore += _gain('BRK', 5, `Strong vs Nifty (${relStrength.toFixed(1)}%)`); breakoutDetail.push(`RS +${relStrength.toFixed(1)}%`); }
  else if (relStrength !== null && relStrength < -1.0 && breakoutScore >= 40) { breakoutScore += _penalty('BRK', 5, 'Breaking out but lagging Nifty'); breakoutDetail.push(`RS ${relStrength.toFixed(1)}%`); }
  // M9 ADR rule: if stock has already burned >80% of its typical daily range, breakout late-stage
  if (adrUsedPct > 80) { breakoutScore += _penalty('BRK', 8, `ADR ${adrUsedPct}% used — likely exhausted`); breakoutDetail.push(`ADR ${adrUsedPct}%`); }
  else if (adrUsedPct > 0 && adrUsedPct < 40) { breakoutScore += _gain('BRK', 4, `ADR ${adrUsedPct}% used — room to run`); breakoutDetail.push(`ADR ${adrUsedPct}%`); }
  breakoutScore = Math.max(0, Math.min(100, breakoutScore));

  // ── SETUP 4: OVERSOLD BOUNCE (Varsity M2 Ch14+15+18: RSI + Stochastic + BB reversal) ──
  // Varsity M2 Ch14: "RSI below 30 = oversold, historically 78% base rate of bounce within days."
  // Ch15: "Bollinger bands — price touching lower band in liquid stock = mean-reversion setup."
  // Ch18: "Stochastic %K < 20 + rising = early reversal confirmation."
  let bounceScore = 0, bounceDetail = [];
  if (lastRSI < 25) { bounceScore += _gain('BOUNCE', 30, `RSI ${lastRSI.toFixed(0)} extreme`); bounceDetail.push(`RSI ${lastRSI.toFixed(0)} extreme`); }
  else if (lastRSI < 30) { bounceScore += _gain('BOUNCE', 25, `RSI ${lastRSI.toFixed(0)} oversold`); bounceDetail.push(`RSI ${lastRSI.toFixed(0)} oversold`); }
  else if (lastRSI < 35) { bounceScore += _gain('BOUNCE', 15, `RSI ${lastRSI.toFixed(0)} near oversold`); bounceDetail.push(`RSI ${lastRSI.toFixed(0)} near oversold`); }
  else if (lastRSI < 40) { bounceScore += _gain('BOUNCE', 5, `RSI ${lastRSI.toFixed(0)}`); bounceDetail.push(`RSI ${lastRSI.toFixed(0)}`); }
  // Varsity M2 Ch18: Stochastic oversold confirmation — double-oversold = strongest signal
  if (stochK < 15) { bounceScore += _gain('BOUNCE', 12, `Stoch ${stochK.toFixed(0)} extreme`); bounceDetail.push(`Stoch ${stochK.toFixed(0)} extreme`); }
  else if (stochK < 20) { bounceScore += _gain('BOUNCE', 8, `Stoch ${stochK.toFixed(0)} oversold`); bounceDetail.push(`Stoch ${stochK.toFixed(0)} oversold`); }
  // Price at lower BB = statistical extreme (Varsity M2 Ch15)
  if (bbPct < 0.05) { bounceScore += _gain('BOUNCE', 18, 'Below lower BB'); bounceDetail.push('Below lower BB'); }
  else if (bbPct < 0.15) { bounceScore += _gain('BOUNCE', 10, 'Near lower BB'); bounceDetail.push('Near lower BB'); }
  // VWAP below = deeply discounted vs session average
  if (pctVWAP < -2.0) { bounceScore += _gain('BOUNCE', 10, 'Well below VWAP'); bounceDetail.push('Well below VWAP'); }
  else if (pctVWAP < -1.0) { bounceScore += _gain('BOUNCE', 5, 'Below VWAP'); bounceDetail.push('Below VWAP'); }
  // Near PDL support — Varsity M2: PDL is institutional memory level
  if (Math.abs(px - pdLow) / pdLow < 0.008) { bounceScore += _gain('BOUNCE', 5, 'Near PDL support'); bounceDetail.push('Near PDL support'); }
  // Volume = capitulation / exhaustion (Varsity M2 Ch12: volume spike on selloff = exhaustion)
  if (volRatio > 3.0) { bounceScore += _gain('BOUNCE', 15, 'Capitulation vol spike'); bounceDetail.push('Capitulation vol spike'); }
  else if (volRatio > 2.0) { bounceScore += _gain('BOUNCE', 10, 'High vol exhaustion'); bounceDetail.push('High vol exhaustion'); }
  else if (volRatio > 1.5) { bounceScore += _gain('BOUNCE', 5, 'Elevated vol'); bounceDetail.push('Elevated vol'); }
  // Varsity M2 Ch 5-10: explicit bullish reversal pattern detection
  // Full pattern catalog replaces the old simple "reversal candle + hammer" check.
  // This is the setup where candlestick patterns matter MOST — a Hammer or Bullish
  // Engulfing at key support is the textbook oversold-bounce trigger.
  if (bullPattern) {
    bounceScore += _gain('BOUNCE', bullPattern.weight, bullPattern.name);
    bounceDetail.push(bullPattern.name);
  }
  // Varsity M2 Ch 22: bounce at CPR support (S1, S2) = high-probability reversal
  if (cpr) {
    const atS1 = Math.abs(px - cpr.S1) / px < 0.008;
    const atS2 = Math.abs(px - cpr.S2) / px < 0.008;
    const atBC = Math.abs(px - cpr.BC) / px < 0.008;
    if (atS2) { bounceScore += _gain('BOUNCE', 10, 'At S2 — deep pivot support'); bounceDetail.push('At S2'); }
    else if (atS1) { bounceScore += _gain('BOUNCE', 7, 'At S1 — pivot support'); bounceDetail.push('At S1'); }
    else if (atBC) { bounceScore += _gain('BOUNCE', 5, 'At BC — central pivot floor'); bounceDetail.push('At BC'); }
  }
  // Varsity M2 Ch 16: Fibonacci retracement — 61.8% (golden ratio) is the
  // highest-probability bounce zone within a session pullback.
  if (nearFib) { bounceScore += _gain('BOUNCE', nearFib.strength, `At Fib ${nearFib.name}`); bounceDetail.push(`Fib ${nearFib.name}`); }
  // Varsity M2 Ch 14: RSI bullish divergence = single most reliable reversal
  // signal. Price made a new low but RSI didn't = institutions accumulating.
  if (rsiBullDiv) { bounceScore += _gain('BOUNCE', 15, 'RSI bullish divergence'); bounceDetail.push('RSI bull div'); }
  // Varsity M2 Ch 15: MACD bullish divergence — confluence signal
  if (macdBullDiv) { bounceScore += _gain('BOUNCE', 8, 'MACD bullish divergence'); bounceDetail.push('MACD bull div'); }
  // Varsity M2 Ch 4: risk-averse entry — pattern was from a prior bar AND
  // direction held on current bar = CONFIRMED setup, deserves extra weight.
  if (bullPatternConfirmed) { bounceScore += _gain('BOUNCE', 6, 'Pattern confirmed next bar'); bounceDetail.push('Confirmed'); }
  // Varsity M2 Ch 11: round-number psychological support
  if (atRoundNumber && lastPriceDown) { bounceScore += _gain('BOUNCE', 5, `At ₹${round.level} — psychological support`); bounceDetail.push(`At ₹${round.level}`); }
  // Varsity M2 Ch 12: volume-price confirmation for mean reversion
  if (vpaWeakDecline) { bounceScore += _gain('BOUNCE', 6, 'Weak decline (price down, vol down) — exhaustion'); bounceDetail.push('Weak decline'); }
  // Varsity M2 Ch 11: equal lows = coiled support, buyers defending the level
  if (hasEqualLows) { bounceScore += _gain('BOUNCE', 6, `Equal lows (${eqLowExtremes.equalLo}x) — coiled support`); bounceDetail.push(`Eq lows ${eqLowExtremes.equalLo}x`); }
  // Varsity M2 Ch 13: VWAP -2σ band = 95% statistical extreme, strong mean-reversion
  if (below2Sigma) { bounceScore += _gain('BOUNCE', 12, 'Below VWAP -2σ band (95% extreme)'); bounceDetail.push('<VWAP -2σ'); }
  else if (below1Sigma) { bounceScore += _gain('BOUNCE', 6, 'Below VWAP -1σ band'); bounceDetail.push('<VWAP -1σ'); }
  // Varsity M2 Ch 12: OBV bullish divergence — accumulation underneath a weak price
  if (obvBullDiv) { bounceScore += _gain('BOUNCE', 10, 'OBV bullish divergence — accumulation'); bounceDetail.push('OBV bull div'); }
  // Relative weakness can favor mean-reversion bounce when stock is oversold vs index
  if (relStrength !== null && relStrength < -1.5) { bounceScore += _gain('BOUNCE', 5, `Weak vs Nifty (${relStrength.toFixed(1)}%) — oversold setup`); bounceDetail.push(`RS ${relStrength.toFixed(1)}%`); }
  // MACD turning — momentum shift (Varsity M2 Ch15)
  if (macdCross) { bounceScore += _gain('BOUNCE', 10, 'MACD turning up'); bounceDetail.push('MACD turning up'); }
  else if (macdBull) { bounceScore += _gain('BOUNCE', 4, 'MACD bull'); bounceDetail.push('MACD bull'); }
  // Penalty: not actually oversold — RSI > 45 kills the thesis
  if (lastRSI > 45) { bounceScore = 0; bounceDetail = ['Not oversold']; }
  bounceScore = Math.max(0, Math.min(100, bounceScore));

  // ── PICK BEST SETUP ────────────────────────────────────────────────────
  const setups = [
    { type: 'VWAP_RECLAIM', score: vwapScore, detail: vwapDetail, emoji: '🔵' },
    { type: 'GAP_AND_GO',   score: gapScore,  detail: gapDetail,  emoji: '🚀' },
    { type: 'BREAKOUT',     score: breakoutScore, detail: breakoutDetail, emoji: '📈' },
    { type: 'OVERSOLD_BOUNCE', score: bounceScore, detail: bounceDetail, emoji: '🔄' },
  ];
  setups.sort((a, b) => b.score - a.score);
  const best = setups[0];

  // Overall day trade score = best setup score, boosted by multi-setup confirmation
  const secondary = setups[1];
  let overall = best.score;
  if (secondary.score >= 40) overall = Math.min(100, overall + Math.round(secondary.score * 0.15));

  // Multi-timeframe: daily trend alignment (Varsity M2 Ch22: "daily must align with weekly")
  // Intraday long setups that align with the daily trend have much higher win rates.
  const dailyF2 = stockFundamentals[sym];
  if (dailyF2) {
    let dailyBullSignals = 0;
    // Golden cross (50DMA > 200DMA) = daily trend structurally bullish
    if (dailyF2.goldenCross) { overall = Math.min(100, overall + _gain('MULTI', 5, 'Golden cross on daily (50DMA > 200DMA)')); dailyBullSignals++; }
    // Price above 200DMA = long-term bullish context
    if (dailyF2.pctAbove200 > 0) { overall = Math.min(100, overall + _gain('MULTI', 3, 'Price above daily 200DMA')); dailyBullSignals++; }
    // Daily RSI in healthy zone (not overbought on daily while we trade intraday long)
    if (dailyF2.rsi != null && dailyF2.rsi > 40 && dailyF2.rsi < 65) { overall = Math.min(100, overall + _gain('MULTI', 2, 'Daily RSI in healthy zone')); dailyBullSignals++; }
    // Weekly trend confirmed — Varsity M2: the ultimate multi-timeframe signal
    if (dailyF2.weeklyTrendConfirmed) { overall = Math.min(100, overall + _gain('MULTI', 4, 'Weekly trend confirmed')); dailyBullSignals++; }
    // Daily supertrend bullish
    if (dailyF2.supertrendSig === 'BUY' || dailyF2.supertrendSig === 'bullish') { overall = Math.min(100, overall + _gain('MULTI', 2, 'Daily Supertrend bullish')); dailyBullSignals++; }
    // Dow Theory uptrend on daily — strongest structural confirmation
    if (dailyF2.dowTheoryTrend === 'UPTREND') { overall = Math.min(100, overall + _gain('MULTI', 3, 'Dow Theory uptrend on daily')); dailyBullSignals++; }
    // Penalty: daily trend bearish and we're taking intraday longs — lower conviction
    // Varsity M2: "never fight the higher timeframe trend"
    if (dailyF2.pctAbove200 < -5 && dailyF2.rsi < 35) overall = Math.max(0, overall + _penalty('MULTI', 10, 'Daily trend bearish (price below 200DMA, RSI extreme)'));
    if (dailyF2.dowTheoryTrend === 'DOWNTREND') overall = Math.max(0, overall + _penalty('MULTI', 5, 'Dow Theory downtrend on daily'));
  }

  // Late session penalty
  if (isLateTrade) { overall = Math.max(0, overall + _penalty('MULTI', 15, 'Late session penalty (after 3PM IST — Varsity M9)')); }

  // ── Session-phase setup-affinity adjustment ──
  // Each of the 4 setups has a reliability profile across the trading session.
  // Morning gaps shine at 9:15-10:00, midday chop favors mean-reversion, etc.
  // Bonuses/penalties are small (±2-6) so they fine-tune ranking without
  // dominating the structural signals.
  const phaseAffinity = {
    GAP_AND_GO:      { OPENING:  6, MORNING:  3, MIDDAY: -5, AFTERNOON: -3, LATE: 0, CLOSED: 0, UNKNOWN: 0 },
    BREAKOUT:        { OPENING:  3, MORNING:  5, MIDDAY: -3, AFTERNOON:  2, LATE: 0, CLOSED: 0, UNKNOWN: 0 },
    VWAP_RECLAIM:    { OPENING:  2, MORNING:  5, MIDDAY:  3, AFTERNOON:  2, LATE: 0, CLOSED: 0, UNKNOWN: 0 },
    OVERSOLD_BOUNCE: { OPENING: -3, MORNING:  3, MIDDAY:  5, AFTERNOON:  3, LATE: 0, CLOSED: 0, UNKNOWN: 0 },
  };
  const phaseAdj = (phaseAffinity[best.type] || {})[sessionPhase] || 0;
  if (phaseAdj > 0) overall = Math.min(100, overall + _gain('MULTI', phaseAdj, `${sessionPhase} phase favors ${best.type}`));
  else if (phaseAdj < 0) overall = Math.max(0, overall + _penalty('MULTI', Math.abs(phaseAdj), `${sessionPhase} phase weak for ${best.type}`));

  // ── Varsity M2 Ch 19: The Finale — unified pre-trade checklist ──
  // Ch 19 distills the whole module into a 5-item checklist. We tally which
  // items pass on this specific pick and award a transparent bonus (+2/item,
  // max +10). This is Varsity's explicit "can I trade this?" filter.
  const ch19 = {
    priceAction:  !!bullPattern,                                                     // ✅ candlestick signal on latest candle
    volume:       volRatio >= 1.5,                                                   // ✅ volume confirming the move
    srContext:    !!(nearCpr || nearFib || atRoundNumber ||                          // ✅ at a recognized S/R level (CPR/Fib/round/pivot)
                    Math.abs(px - pdLow) / pdLow < 0.01 ||
                    Math.abs(px - pdHigh) / pdHigh < 0.01 ||
                    Math.abs(px - orHigh) / orHigh < 0.01 ||
                    Math.abs(px - orLow) / orLow < 0.01),
    indicators:   [ema9[n - 1] > ema20[n - 1], macdBull, stBull, stochK > 20 && stochK < 80]
                    .filter(Boolean).length >= 2,                                    // ✅ at least 2 of 4 indicators aligned
    rrRatio:      true,  // filled in below after sl/tgt are computed — placeholder passes for now
  };
  const ch19PassCount = [ch19.priceAction, ch19.volume, ch19.srContext, ch19.indicators, ch19.rrRatio].filter(Boolean).length;
  if (ch19PassCount >= 4) overall = Math.min(100, overall + _gain('MULTI', 8, `M2 Ch 19 checklist: ${ch19PassCount}/5 passed`));
  else if (ch19PassCount === 3) overall = Math.min(100, overall + _gain('MULTI', 4, 'M2 Ch 19 checklist: 3/5 passed'));
  else if (ch19PassCount <= 1) overall = Math.max(0, overall + _penalty('MULTI', 6, `M2 Ch 19 checklist: only ${ch19PassCount}/5 — weak setup`));

  if (overall < 30) return null; // below threshold — not worth showing

  // Stop loss + target based on setup type
  // Varsity M9 (Risk Management): "Always define SL BEFORE entering. Never risk more than
  // you expect to gain." Each setup uses structure-based SL, not arbitrary percentages.
  let sl, tgt, rrRatio;
  if (best.type === 'OVERSOLD_BOUNCE') {
    // SL below the oversold candle's low or day low (Varsity M9: structural SL)
    sl  = +(Math.min(dayLow, last.low) * 0.997).toFixed(2);
    tgt = +(px + (px - sl) * 2).toFixed(2);  // 2:1 R:R — mean reversion targets are generous
  } else if (best.type === 'BREAKOUT') {
    // SL at OR midpoint — Varsity M2 Ch7: "if price re-enters the range, breakout failed"
    const orMid = (orHigh + orLow) / 2;
    sl  = +(Math.max(orMid, dayLow * 0.998)).toFixed(2);
    // TGT: project OR range above breakout level (Varsity: measured move)
    tgt = +(px + Math.max(orRange * 1.5, (px - sl) * 2)).toFixed(2);
  } else if (best.type === 'GAP_AND_GO') {
    // SL at gap fill level (prev close) — Varsity M2 Ch7: "gap fill = thesis invalidated"
    sl  = +(prevClose * 0.998).toFixed(2);
    tgt = +(px + Math.abs(gapPct / 100 * px) * 1.2).toFixed(2);
    // Fallback if gap is tiny
    if (tgt <= px) tgt = +(px + (px - sl) * 1.5).toFixed(2);
  } else { // VWAP_RECLAIM
    // SL below VWAP — Varsity M2 Ch13: "if price drops back below VWAP, reclaim failed"
    sl  = +(lastVWAP * 0.995).toFixed(2);
    tgt = +(px + (px - sl) * 2).toFixed(2);
  }

  // Varsity M9: ATR-based stop loss — SL must be at least 1 ATR away from entry
  const atrSlice = candles.slice(1).map((c, i) => Math.max(c.high - c.low, Math.abs(c.high - candles[i].close), Math.abs(c.low - candles[i].close)));
  const atr14val = atrSlice.slice(-14).reduce((a, b) => a + b, 0) / 14;
  const minSLDist = atr14val;
  if (px - sl < minSLDist) sl = +(px - minSLDist).toFixed(2);
  // Recalc targets and RR after ATR adjustment
  tgt = +(px + (px - sl) * Math.max(1.5, rrRatio || 1.5)).toFixed(2);
  rrRatio = sl < px ? +((tgt - px) / (px - sl)).toFixed(1) : 0;

  // Varsity M9: minimum R:R of 1:1 — never take a trade where risk > reward
  if (rrRatio < 1.0) return null;

  // Ch 19 checklist retroactive R:R correction. If the ATR-adjusted R:R
  // ended up < 1.5, the rrRatio check we placeholded above was too
  // generous — drop that tick from the checklist and recompute the bonus.
  if (rrRatio < 1.5) {
    ch19.rrRatio = false;
    const revisedPass = [ch19.priceAction, ch19.volume, ch19.srContext, ch19.indicators, ch19.rrRatio].filter(Boolean).length;
    if (revisedPass < ch19PassCount && revisedPass <= 2) {
      overall = Math.max(0, overall + _penalty('MULTI', 4, `M2 Ch 19: R:R ${rrRatio.toFixed(1)} below 1.5 — weakened checklist`));
    }
  }

  // ── RISK MANAGEMENT PLAN (Varsity M9 + M2) ──────────────────────────────
  // Comprehensive SL/TGT/position-sizing recommendation grounded in Varsity knowledge

  const riskPerTrade = px * 0.02;  // Varsity M9: max 2% of capital risk per trade (proxy: 2% of price)
  const slDist = +(px - sl).toFixed(2);
  const slPct  = +((px - sl) / px * 100).toFixed(2);
  const tgtDist = +(tgt - px).toFixed(2);
  const tgtPct  = +((tgt - px) / px * 100).toFixed(2);

  // Position sizing: Varsity M9 Ch2 — "Risk per trade = Capital × 2%. Qty = Risk / (Entry − SL)"
  // We compute qty for ₹1L, ₹5L, ₹10L capital
  const qtyPer1L  = slDist > 0 ? Math.floor((100000 * 0.02) / slDist) : 0;
  const qtyPer5L  = slDist > 0 ? Math.floor((500000 * 0.02) / slDist) : 0;
  const qtyPer10L = slDist > 0 ? Math.floor((1000000 * 0.02) / slDist) : 0;

  // ── Varsity M9 Part I: Kelly Criterion ──
  // f* = (bp - q) / b  where b=reward/risk ratio, p=win probability, q=1-p.
  // We use overall/100 as a conviction-proxy for p (Varsity treats checklist
  // score as a directional win-rate estimate; it's a proxy, not a real
  // back-tested win rate). Capped at 25% (Varsity: "half-Kelly or quarter-Kelly
  // in practice to avoid ruin") so the suggestion is never reckless.
  const winProb = Math.max(0.30, Math.min(0.85, overall / 100));
  const b = Math.max(0.5, rrRatio);
  const kellyRaw = (b * winProb - (1 - winProb)) / b;
  const kellyFraction = Math.max(0, Math.min(0.25, kellyRaw));
  const kellyPct = +(kellyFraction * 100).toFixed(1);
  // Position sizing at Kelly fraction for each reference capital level
  const kellyQtyPer1L  = slDist > 0 && kellyFraction > 0 ? Math.floor((100000 * kellyFraction) / px) : 0;
  const kellyQtyPer5L  = slDist > 0 && kellyFraction > 0 ? Math.floor((500000 * kellyFraction) / px) : 0;
  const kellyQtyPer10L = slDist > 0 && kellyFraction > 0 ? Math.floor((1000000 * kellyFraction) / px) : 0;

  // ── Varsity M9 Part I: Volatility-scaled position sizing ──
  // M9 lists 4 sizing models; ATR-based is the fourth: "Scale size inversely
  // with ATR — high volatility demands smaller exposure, low volatility
  // allows bigger." We compute an ATR-scale factor applied to the Kelly qty.
  //   ATR% > 3   → 0.50x (very volatile — half size)
  //   ATR% 2-3   → 0.75x
  //   ATR% 1-2   → 1.00x (baseline)
  //   ATR% < 1   → 1.25x (very calm — can size up slightly)
  const atrPct = +((atr14val / px) * 100).toFixed(2);
  const volScale = atrPct > 3 ? 0.50 : atrPct > 2 ? 0.75 : atrPct >= 1 ? 1.00 : 1.25;
  const atrQtyPer1L  = Math.floor(kellyQtyPer1L * volScale);
  const atrQtyPer5L  = Math.floor(kellyQtyPer5L * volScale);
  const atrQtyPer10L = Math.floor(kellyQtyPer10L * volScale);

  // SL reason — WHY this stop loss level
  let slReason, slVarsityRef;
  if (best.type === 'OVERSOLD_BOUNCE') {
    slReason = 'Below the oversold candle low / day low — if price makes a new low, the bounce thesis is dead';
    slVarsityRef = 'Varsity M9: structural SL below the reversal candle';
  } else if (best.type === 'BREAKOUT') {
    slReason = 'At Opening Range midpoint — if price re-enters the range, the breakout failed';
    slVarsityRef = 'Varsity M2 Ch7: breakout failure = price returning inside the base';
  } else if (best.type === 'GAP_AND_GO') {
    slReason = 'At previous close (gap fill level) — if the gap fills completely, the momentum thesis is invalidated';
    slVarsityRef = 'Varsity M2 Ch7: gap fill = directional conviction lost';
  } else {
    slReason = 'Below VWAP — if price drops back below VWAP after reclaiming, institutions are not defending';
    slVarsityRef = 'Varsity M2 Ch13: failed VWAP reclaim = no institutional support';
  }

  // ATR context (atrPct already computed above in volatility-sizing block)
  const slIsATRWidened = slDist >= atr14val * 0.95; // was SL widened by ATR floor?

  // Trailing SL levels — Varsity M9: "trail your SL to lock in profits as the trade moves in your favour"
  const trail1 = +(px + (tgt - px) * 0.33).toFixed(2); // after 33% of target reached, trail SL to entry (breakeven)
  const trail2 = +(px + (tgt - px) * 0.5).toFixed(2);  // after 50%, trail SL to +25% of move
  const trail3 = +(px + (tgt - px) * 0.75).toFixed(2); // after 75%, trail SL to +50% of move
  const trailSLBreakeven = +px.toFixed(2); // breakeven SL
  const trailSL50 = +(px + (tgt - px) * 0.25).toFixed(2); // SL at 25% of move
  const trailSL75 = +(px + (tgt - px) * 0.5).toFixed(2);  // SL at 50% of move

  // Partial exit targets — Varsity M9: "book partial profits to reduce risk"
  const tgt1 = +(px + (tgt - px) * 0.5).toFixed(2);   // partial exit at 50% of target
  const tgt2 = tgt;                                     // full target
  const tgt3 = +(px + (tgt - px) * 1.5).toFixed(2);   // extended target if momentum continues

  // Time-based exit — Varsity M9: don't hold intraday positions into close without a reason
  let timeExit = 'Exit by 3:15 PM IST if target not hit — avoid overnight risk on intraday positions';
  if (best.type === 'OVERSOLD_BOUNCE') {
    timeExit = 'Mean reversion targets should hit within 30-60 min. If RSI recovers above 50 but price stalls, exit. Must exit by 3:15 PM.';
  } else if (best.type === 'GAP_AND_GO') {
    timeExit = 'Gap momentum is strongest in the first 60-90 min. If price stalls after OR period, tighten SL to breakeven. Exit by 3:15 PM.';
  } else if (best.type === 'BREAKOUT') {
    timeExit = 'Breakout should show follow-through within 2-3 candles (10-15 min). If no follow-through with declining volume, exit at breakeven. Exit by 3:15 PM.';
  }

  // Re-entry rules
  let reEntryRule;
  if (best.type === 'VWAP_RECLAIM') {
    reEntryRule = 'If stopped out, re-enter only if price reclaims VWAP again with higher volume than the first attempt.';
  } else if (best.type === 'BREAKOUT') {
    reEntryRule = 'If stopped out on fake-out, wait for a 2nd breakout attempt with volume > 2x avg before re-entering.';
  } else if (best.type === 'GAP_AND_GO') {
    reEntryRule = 'Do NOT re-enter if gap has filled. A filled gap means the thesis is completely invalidated.';
  } else {
    reEntryRule = 'If stopped out, wait for RSI to make a new low below 25 before attempting a second bounce entry.';
  }

  // Build the riskPlan object
  const riskPlan = {
    // SL details
    sl, slDist, slPct,
    slReason, slVarsityRef,
    atr14: +atr14val.toFixed(2), atrPct,
    slIsATRWidened,
    slNote: slIsATRWidened ? 'SL widened to 1 ATR (' + atr14val.toFixed(2) + ') from entry — Varsity M9: SL must respect volatility' : 'Setup-specific SL is wider than ATR — good structural level',

    // TGT details
    tgt, tgtDist, tgtPct, rrRatio,
    partialTargets: [
      { label: 'T1 (50%)', price: tgt1, action: 'Book 50% position, trail SL to breakeven', pct: +((tgt1 - px) / px * 100).toFixed(1) },
      { label: 'T2 (Full)', price: tgt2, action: 'Book remaining position at full target', pct: tgtPct },
      { label: 'T3 (Extended)', price: tgt3, action: 'Only if strong momentum + volume continues past T2', pct: +((tgt3 - px) / px * 100).toFixed(1) },
    ],

    // Trailing SL plan
    trailingPlan: [
      { trigger: 'Price hits ' + trail1.toFixed(2) + ' (+33% to target)', newSL: trailSLBreakeven, label: 'Move SL to breakeven (' + trailSLBreakeven + ')' },
      { trigger: 'Price hits ' + trail2.toFixed(2) + ' (+50% to target)', newSL: trailSL50, label: 'Trail SL to ' + trailSL50 + ' (lock +25% of move)' },
      { trigger: 'Price hits ' + trail3.toFixed(2) + ' (+75% to target)', newSL: trailSL75, label: 'Trail SL to ' + trailSL75 + ' (lock +50% of move)' },
    ],

    // Position sizing
    positionSizing: {
      method: 'Varsity M9: Risk = 2% of capital. Qty = Risk ÷ (Entry − SL)',
      examples: [
        { capital: '₹1L', qty: qtyPer1L, risk: '₹' + (qtyPer1L * slDist).toFixed(0) },
        { capital: '₹5L', qty: qtyPer5L, risk: '₹' + (qtyPer5L * slDist).toFixed(0) },
        { capital: '₹10L', qty: qtyPer10L, risk: '₹' + (qtyPer10L * slDist).toFixed(0) },
      ],
    },

    // Exit rules
    timeExit,
    reEntryRule,

    // Danger signals — when to exit immediately regardless of SL
    dangerSignals: [
      'Volume drops below average while price is near SL — no buying support',
      best.type === 'BREAKOUT' ? 'Price closes back inside the Opening Range — breakout failed' : null,
      best.type === 'GAP_AND_GO' ? 'Gap fills (price crosses prev close) — exit immediately, don\'t wait for SL' : null,
      best.type === 'VWAP_RECLAIM' ? 'Price closes below VWAP on increasing volume — institutions selling, not defending' : null,
      best.type === 'OVERSOLD_BOUNCE' ? 'RSI makes new low below previous dip — no reversal, deeper selloff likely' : null,
      lastRSI > 75 ? 'RSI already near overbought — limited upside remaining' : null,
      'Nifty/index drops sharply while your stock is flat — sector drag incoming',
    ].filter(Boolean),
  };

  // Verdict
  let verdict, verdictColor;
  if (overall >= 75) { verdict = 'Strong Entry'; verdictColor = '#22c55e'; }
  else if (overall >= 60) { verdict = 'Good Setup'; verdictColor = '#86efac'; }
  else if (overall >= 45) { verdict = 'Developing'; verdictColor = '#f59e0b'; }
  else { verdict = 'Weak'; verdictColor = '#94a3b8'; }

  // Build whyPicked explanation
  const whyPicked = best.type === 'VWAP_RECLAIM'
    ? 'Price was below VWAP recently and is now reclaiming from below' + (volRatio > 1.5 ? ' with ' + volRatio.toFixed(1) + 'x volume surge' : '') + '. VWAP is the institutional benchmark (Varsity M2 Ch13).'
    : best.type === 'GAP_AND_GO'
    ? 'Stock gapped ' + (gapPct > 0 ? 'up' : 'down') + ' ' + Math.abs(gapPct).toFixed(1) + '% from previous close' + (gapUnfilled ? ' and gap remains unfilled' : '') + '. Gap theory per Varsity M2 Ch7.'
    : best.type === 'BREAKOUT'
    ? 'Price breaking ' + (abovePDH ? 'above previous day high' : aboveOR ? 'above opening range' : 'to new day high') + (volRatio > 1.5 ? ' with ' + volRatio.toFixed(1) + 'x volume confirmation' : '') + '. S/R breakout per Varsity M2 Ch7+16.'
    : 'RSI at ' + lastRSI.toFixed(0) + ' (oversold) ' + (bbPct < 0.15 ? 'near lower Bollinger Band' : '') + (stochK < 20 ? ', Stochastic extreme at ' + stochK.toFixed(0) : '') + '. Mean reversion setup per Varsity M2 Ch14+15+18.';

  // Filter _track for the winning setup + multi-timeframe
  const bestBucket = best.type === 'VWAP_RECLAIM' ? 'VWAP' : best.type === 'GAP_AND_GO' ? 'GAP' : best.type === 'BREAKOUT' ? 'BRK' : 'BOUNCE';
  const scoreGains = _track.filter(t => (t.bucket === bestBucket || t.bucket === 'MULTI') && t.type === 'gain');
  const scorePenalties = _track.filter(t => (t.bucket === bestBucket || t.bucket === 'MULTI') && t.type === 'penalty');

  return {
    sym, name: f?.name || sym, grp: f?.grp || 'Unknown', sector: f?.sector || 'Other',
    price: +px.toFixed(2),
    // Overall
    dayTradeScore: overall,
    verdict, verdictColor,
    bestSetup: best.type, bestSetupEmoji: best.emoji, bestSetupScore: best.score,
    bestDetail: best.detail.join(' · '),
    // All setup scores
    vwapScore, gapScore, breakoutScore, bounceScore,
    // Technicals
    rsi5m: +lastRSI.toFixed(0), vwapDist: +pctVWAP.toFixed(2), volRatio: +volRatio.toFixed(1),
    gapPct: +gapPct.toFixed(1), adx5m: +adxVal.toFixed(0),
    ema9: +ema9[n - 1].toFixed(2), ema20: +ema20[n - 1].toFixed(2),
    macdBull, stBull, stochK: +stochK.toFixed(0),
    orHigh: +orHigh.toFixed(2), orLow: +orLow.toFixed(2), orRange: +orRange.toFixed(2),
    dayHigh: +dayHigh.toFixed(2), dayLow: +dayLow.toFixed(2),
    pdHigh: +pdHigh.toFixed(2), pdLow: +pdLow.toFixed(2),
    bbPct: +bbPct.toFixed(2), gapUnfilled,
    // Varsity M2 Ch 5-10: candlestick pattern on latest 5-min candle (if any)
    candlePattern: bullPattern ? bullPattern.name : (bearPattern ? bearPattern.name : null),
    candlePatternBull: bullPattern ? true : (bearPattern ? false : null),
    candlePatternDesc: bullPattern ? bullPattern.description : (bearPattern ? bearPattern.description : null),
    // Varsity M2 Ch 22: Central Pivot Range derived from prior day
    cpr: cpr ? {
      PP: +cpr.PP.toFixed(2), BC: +cpr.BC.toFixed(2), TC: +cpr.TC.toFixed(2),
      R1: +cpr.R1.toFixed(2), R2: +cpr.R2.toFixed(2), R3: +cpr.R3.toFixed(2),
      S1: +cpr.S1.toFixed(2), S2: +cpr.S2.toFixed(2), S3: +cpr.S3.toFixed(2),
      widthPct: +cpr.widthPct.toFixed(2), type: cpr.type,
    } : null,
    // Varsity M2 Ch 7: gap classification + failed-break flags
    gapClass, gapClassBonus,
    orFailedBreak, pdhFailedBreak,
    // Varsity M2 Ch 11: equal highs/lows (price memory — coiled levels)
    equalHighsCount: eqExtremes.equalHi,
    equalLowsCount: eqLowExtremes.equalLo,
    hasEqualHighs, hasEqualLows,
    // Varsity M2 Ch 13: VWAP sigma bands
    vwapSigma: +vwapSigma.toFixed(3),
    vwapUpper1: +vwapUpper1.toFixed(2), vwapLower1: +vwapLower1.toFixed(2),
    vwapUpper2: +vwapUpper2.toFixed(2), vwapLower2: +vwapLower2.toFixed(2),
    below2Sigma, below1Sigma, above2Sigma,
    // Varsity M2 Ch 15: MACD histogram state
    macdHist: +macdHist.toFixed(3),
    macdHistRising, macdHistZeroUp,
    // Varsity M2 Ch 12: OBV + divergence
    obv: obv.length ? obv[obv.length - 1] : 0,
    obvBullDiv, obvBearDiv,
    // Relative strength vs Nifty (Dow Theory implicit confirmation)
    relStrength, niftyDailyChange: _niftyChange,
    // M9 intraday: ADR usage
    adrAvg, adrUsedPct,
    // Varsity M2 Ch 11: role reversal flags
    pdhRoleSupport, orHighRoleSupport,
    // Varsity M2 Ch 16: Fibonacci — session retracement level price is sitting at
    fibLevel: nearFib ? nearFib.name : null,
    fibStrength: nearFib ? nearFib.strength : 0,
    // Varsity M2 Ch 11: S/R touch counts — >= 3 = strong level
    dayHighTouches, orHighTouches, pdHighTouches, pdLowTouches,
    // Varsity M2 Ch 16: Bollinger Squeeze state
    bbSqueeze, bbSqueezeReleaseUp,
    // Varsity M2 Ch 19: unified checklist (5 items)
    ch19Checklist: ch19,
    ch19PassCount,
    // Varsity M2 Ch 14 + Ch 15: RSI / MACD divergence flags
    rsiBullDiv, rsiBearDiv, macdBullDiv, macdBearDiv,
    // Varsity M2 Ch 4: risk-averse entry — pattern confirmed on next bar
    patternConfirmed: bullPatternConfirmed || bearPatternConfirmed,
    // Varsity M2 Ch 22: virgin CPR = untested band today (extra-strong S/R)
    cprVirgin,
    // Varsity M2 Ch 12: Volume-Price Action matrix quadrants (one-hot)
    vpa: {
      confirmBull: vpaConfirmBull,
      confirmBear: vpaConfirmBear,
      weakRally: vpaWeakRally,
      weakDecline: vpaWeakDecline,
    },
    // Varsity M2 Ch 11: nearest round-number psychological level
    roundNumber: round.level,
    atRoundNumber,
    // Varsity M9 Part I: Kelly Criterion position sizing
    kelly: {
      fractionPct: kellyPct,
      winProb: +winProb.toFixed(2),
      edge: +(b * winProb - (1 - winProb)).toFixed(2),
      qtyPer1L: kellyQtyPer1L,
      qtyPer5L: kellyQtyPer5L,
      qtyPer10L: kellyQtyPer10L,
    },
    // Varsity M9 Part I: ATR-scaled volatility-based position sizing
    atrPct,
    volSizing: {
      volScale,
      qtyPer1L: atrQtyPer1L,
      qtyPer5L: atrQtyPer5L,
      qtyPer10L: atrQtyPer10L,
    },
    // Varsity M2 Ch 4: session-trend context used to demote reversal patterns
    sessionTrend,
    // Varsity M2 Ch 14: RSI midline state
    rsiAboveMidline, rsiCrossedMidlineUp,
    // Varsity M2 Ch 12: volume trend (3-bar expansion/contraction)
    volExpanding, volContracting,
    // Session microstructure
    sessionPhase, sessionPhaseAdjustment: phaseAdj,
    // Risk
    sl, tgt, rrRatio,
    // Risk management plan (Varsity M9)
    riskPlan,
    // Score explanation (WHY picked, WHY scored, WHY lost points)
    whyPicked,
    scoreGains,
    scorePenalties,
    // Metadata
    scannedAt: Date.now(),
  };
}

let _unifiedPipelineRunning = false;

// Scan all UNIVERSE stocks on 5-min candles and populate _dayTradeCache.
// force=true allows off-hours scans (startup warm-up, manual admin refresh)
// — scoreDayTrade() already has a last-trading-day fallback.
async function scanDayTrades(force = false) {
  if (_dayTradeScanning) return;
  if (!force && !isMarketOpen()) return;
  if (!kite || !process.env.KITE_ACCESS_TOKEN) return;

  _dayTradeScanning = true;
  const t0 = Date.now();
  let ok = 0, fail = 0;
  const results = [];

  try {
    const today   = new Date().toISOString().split('T')[0];
    const weekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];

    for (const stock of UNIVERSE) {
      if (!stock.sym || !stock.name) continue;
      const token = validTokens[stock.sym] || INSTRUMENTS[stock.sym];
      if (!token) continue;

      try {
        const candles = await kite.getHistoricalData(token, '5minute', weekAgo, today).catch(() => null);
        if (!candles || candles.length < 30) continue;
        const scored = scoreDayTrade(candles, stock.sym);
        if (scored) {
          scored.optionRec = getOptionRecommendation(stock.sym, scored.price, scored.bestSetup, scored.sl, scored.tgt, scored.rrRatio);
          // Align snapshot ts to the last 5-min bar scanned.
          const lastC = candles[candles.length - 1];
          scored.tsMs = lastC.date ? (lastC.date instanceof Date ? lastC.date.getTime() : Date.parse(lastC.date)) : Date.now();
          scored.sector = stockFundamentals[stock.sym]?.sector;
          scored.grp    = stockFundamentals[stock.sym]?.grp || stock.grp;
          // Log snapshot + last 5-min candle. Both non-blocking, isolated DLQ.
          mlLogger.logFeatureSnapshot(scored, force ? 'force_scan' : 'scan_day_trades')
            .then(snapshotId => { scored._snapshotId = snapshotId; })
            .catch(e => console.warn('[ml-logger] snapshot failed:', e.message));
          mlLogger.logCandlesBatch('candles_5m', [{
            sym: stock.sym, ts: new Date(scored.tsMs),
            open: lastC.open, high: lastC.high, low: lastC.low,
            close: lastC.close, volume: lastC.volume, vwap: scored.vwap,
          }]).catch(e => console.warn('[ml-logger] candle_5m failed:', e.message));
          results.push(scored);
          ok++;
        }
      } catch (e) {
        fail++;
      }

      // Respect rate limits
      if ((ok + fail) % 10 === 0) await new Promise(r => setTimeout(r, 100));
    }

    // ── Cache guard: don't wipe a good cache with an empty scan ──
    // When Kite rate-limits mid-scan, most fetches fail, no stocks get
    // scored, and `results` ends up empty. Blindly assigning here caused
    // the "data disappears and reappears" flicker users saw — every poll
    // at 5s intervals briefly sees 0 picks right after a bad scan, then
    // picks come back on the next successful run.
    //
    // Only overwrite when (a) we got picks, or (b) the previous cache is
    // already empty (first run), or (c) the scan was comprehensive enough
    // that 0 picks is a legitimate signal ("no setups today").
    const successRatio = ok / Math.max(UNIVERSE.length, 1);
    if (results.length > 0 || _dayTradeCache.length === 0 || successRatio > 0.3) {
      results.sort((a, b) => b.dayTradeScore - a.dayTradeScore);
      // Varsity M9: sector-correlation cap. "Never take N correlated positions
      // at once" — same-sector picks are effectively one trade. Interleave so
      // no single sector dominates the top 10 with more than 2 picks.
      _dayTradeCache   = applySectorCap(results, 2);
      _dayTradeCacheTs = Date.now();
      console.log(`📊 DayTrade scanner: ${ok}ok/${fail}fail, ${results.length} picks cached`);
    } else {
      console.log(`📊 DayTrade scanner: ${ok}ok/${fail}fail — low success ratio (${(successRatio*100).toFixed(0)}%), keeping previous cache (${_dayTradeCache.length} picks)`);
    }
  } catch (e) {
    console.error('🔴 DayTrade scanner error:', e.message);
  } finally {
    _dayTradeScanning = false;
  }
}

app.get('/api/stocks/picks/daytrade', (req, res) => {
  const setupFilter = req.query.setup; // optional: VWAP_RECLAIM, GAP_AND_GO, BREAKOUT, OVERSOLD_BOUNCE
  let picks = _dayTradeCache;
  if (setupFilter && ['VWAP_RECLAIM', 'GAP_AND_GO', 'BREAKOUT', 'OVERSOLD_BOUNCE'].includes(setupFilter)) {
    picks = picks.filter(p => p.bestSetup === setupFilter);
  }
  res.json({
    stocks: picks,
    total: picks.length,
    lastScannedAt: _dayTradeCacheTs ? new Date(_dayTradeCacheTs).toISOString() : null,
    marketOpen: isMarketOpen(),
  });
});

// Admin trigger for unified pipeline (?force=1 bypasses market-hours check for testing)
app.post('/api/admin/unified-pipeline', async (req, res) => {
  if (_unifiedPipelineRunning) return res.json({ status: 'already_running' });
  const force = req.query.force === '1' || req.body?.force === true;
  runUnifiedKitePipeline(force).catch(e => console.error('Manual pipeline error:', e.message));
  res.json({ status: 'started', force, message: 'Unified Kite pipeline triggered' + (force ? ' (force — ignoring market hours)' : '') });
});

// Diagnostic endpoint — shows pipeline state without triggering anything
app.get('/api/admin/pipeline-status', (req, res) => {
  res.json({
    pipelineRunning: _unifiedPipelineRunning,
    dayTradeCacheCount: _dayTradeCache.length,
    dayTradeCacheTs: _dayTradeCacheTs ? new Date(_dayTradeCacheTs).toISOString() : null,
    stockFundamentalsCount: Object.keys(stockFundamentals).length,
    validTokensCount: Object.keys(validTokens || {}).length,
    kiteInitialized: !!kite,
    kiteTokenSet: !!process.env.KITE_ACCESS_TOKEN,
    marketOpen: isMarketOpen(),
    stockFundReady: typeof stockFundReady !== 'undefined' ? stockFundReady : 'unknown',
    lastRun: _pipelineLastRun,
  });
});

// ── ML-logger diagnostics ────────────────────────────────────────────────────
// Admin-only view of the data-logging layer — ring-buffer size, DB health,
// and per-target DLQ counts. Safe to hit at any time (all reads are O(1) or
// a single cheap aggregate query against writer_dead_letter).
app.get('/api/admin/ml-logger-status', async (req, res) => {
  try {
    const diag    = mlLogger.getDiagnostics();
    const dlq     = await mlLogger.getDlqSummary();
    res.json({ diag, dlq });
  } catch (e) {
    res.status(500).json({ error: e.message });
  }
});

// Manual outcome-engine run — useful after backfills or when the cron
// seems stuck. Non-blocking: kicks off a background run and returns
// immediately with the current state.
app.post('/api/admin/outcome-engine/run', async (req, res) => {
  if (outcomeEngine.isRunning()) return res.json({ status: 'already_running' });
  const batch = parseInt(req.query.batch || '500', 10);
  outcomeEngine.computeOutcomes(batch)
    .then(r => console.log('[outcome-engine] manual run complete:', JSON.stringify(r)))
    .catch(e => console.error('[outcome-engine] manual run error:', e.message));
  res.json({ status: 'started', batch });
});

// Test endpoint — fetch 3 stocks and return detailed results for debugging
app.get('/api/admin/pipeline-test', async (req, res) => {
  const results = { steps: [], errors: [] };
  try {
    results.steps.push('Starting test pipeline');
    const syms = Object.keys(stockFundamentals).slice(0, 3);
    results.steps.push(`Testing ${syms.length} symbols: ${syms.join(', ')}`);

    const today = new Date().toISOString().split('T')[0];
    const weekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];
    results.steps.push(`Date range: ${weekAgo} to ${today}`);

    for (const sym of syms) {
      const token = validTokens[sym] || INSTRUMENTS[sym];
      results.steps.push(`${sym}: token=${token || 'MISSING'}`);
      if (!token) { results.errors.push(`${sym}: no instrument token`); continue; }

      // Test daily candles
      try {
        const daily = await fetchKiteDaily(sym);
        results.steps.push(`${sym}: daily candles = ${daily ? daily.length : 'null'}`);
      } catch (e) {
        results.errors.push(`${sym} daily error: ${e.message}`);
      }

      // Test 5-min candles
      try {
        const fiveMin = await kite.getHistoricalData(token, '5minute', weekAgo, today);
        results.steps.push(`${sym}: 5min candles = ${fiveMin ? fiveMin.length : 'null'}`);
        if (fiveMin && fiveMin.length > 0) {
          // Show candle date format for debugging
          const lastC = fiveMin[fiveMin.length - 1];
          const firstC = fiveMin[0];
          results.steps.push(`${sym}: first candle date = ${JSON.stringify(firstC.date || firstC.timestamp)}`);
          results.steps.push(`${sym}: last candle date = ${JSON.stringify(lastC.date || lastC.timestamp)}`);
          results.steps.push(`${sym}: candle keys = ${Object.keys(lastC).join(',')}`);
          results.steps.push(`${sym}: last candle = ${JSON.stringify(lastC)}`);

          // Show today filter results
          const todayStr = new Date().toISOString().split('T')[0];
          const todayCandles = fiveMin.filter(c => {
            const d = c.date || c.timestamp;
            return d && String(d).startsWith(todayStr);
          });
          results.steps.push(`${sym}: todayStr=${todayStr}, todayCandles=${todayCandles.length}`);

          // Show fallback date
          const lastDate = String(lastC.date || lastC.timestamp).split('T')[0];
          const fallbackCandles = fiveMin.filter(c => {
            const d = c.date || c.timestamp;
            return d && String(d).startsWith(lastDate);
          });
          results.steps.push(`${sym}: fallbackDate=${lastDate}, fallbackCandles=${fallbackCandles.length}`);
        }
        if (fiveMin && fiveMin.length >= 30) {
          const scored = scoreDayTrade(fiveMin, sym);
          results.steps.push(`${sym}: dayTrade score = ${scored ? scored.dayTradeScore : 'null'}`);
        } else {
          results.steps.push(`${sym}: not enough 5min candles for DayTrade (need 30+)`);
        }
      } catch (e) {
        results.errors.push(`${sym} 5min error: ${e.message}`);
      }
    }
  } catch (e) {
    results.errors.push(`Fatal: ${e.message}`);
  }
  res.json(results);
});

// ===============================================================================
// UNIFIED KITE PIPELINE — fetch once, rescore + daytrade in parallel
// ===============================================================================
// Problem solved: previously intradayRescoreTA() and scanDayTrades() both hit Kite
// independently, doubling API load and risking rate limits. Now we fetch both daily
// AND 5-min candles in a single pass per stock, then feed both scoring engines
// simultaneously. Also: TA rescore happens incrementally (score per batch, not wait
// for all stocks) so picks update faster during market hours.

async function runUnifiedKitePipeline(force = false) {
  if (_unifiedPipelineRunning) { console.log('🔄 Unified pipeline already running, skipping'); return; }
  if (!force && !isMarketOpen()) { console.log('🔄 Pipeline skipped: market closed (force=false)'); return; }

  // Auto-recover Kite token from DB if env var missing
  if (!process.env.KITE_ACCESS_TOKEN) {
    const dbToken = await dbGet('kite_access_token');
    if (dbToken) {
      console.log('🔑 Recovered Kite token from DB');
      process.env.KITE_ACCESS_TOKEN = dbToken;
      if (kite) kite.setAccessToken(dbToken);
    }
  }
  if (!kite) { initKite(process.env.KITE_ACCESS_TOKEN); }
  if (!kite || !process.env.KITE_ACCESS_TOKEN) {
    console.log('🔄 Pipeline skipped: no Kite token available');
    return;
  }

  _unifiedPipelineRunning = true;
  _pipelineLastRun = { startedAt: new Date().toISOString(), status: 'running' };
  const t0 = Date.now();
  let okTA = 0, okDT = 0, failTA = 0, failDT = 0;
  const dayTradeResults = [];

  try {
    // Pre-fetch Nifty benchmark (non-blocking, best-effort)
    try {
      const niftyCandles = await fetchKiteDaily('NIFTY 50');
      if (niftyCandles && niftyCandles.length > 0) {
        const NC = niftyCandles.map(c => c.close);
        const nn = NC.length;
        niftyBenchmark['52w'] = nn >= 252 ? (NC[nn-1] - NC[nn-252]) / NC[nn-252] : 0;
        niftyBenchmark['6m']  = nn >= 126 ? (NC[nn-1] - NC[nn-126]) / NC[nn-126] : 0;
        niftyBenchmark['3m']  = nn >= 63  ? (NC[nn-1] - NC[nn-63])  / NC[nn-63]  : 0;
        niftyBenchmark['1m']  = nn >= 21  ? (NC[nn-1] - NC[nn-21])  / NC[nn-21]  : 0;
        // Expose today's Nifty % change to scoreDayTrade for relative-strength scoring.
        if (nn >= 2) _niftyDailyChangePct = +((NC[nn-1] - NC[nn-2]) / NC[nn-2] * 100).toFixed(2);
      }
    } catch (e) { /* non-critical */ }

    const syms = Object.keys(stockFundamentals);
    console.log(`🔄 Unified pipeline starting: ${syms.length} symbols, force=${force}, kiteToken=${process.env.KITE_ACCESS_TOKEN ? 'SET' : 'MISSING'}`);
    if (syms.length === 0) { console.log('🔄 Pipeline: no symbols in stockFundamentals — skipping'); _unifiedPipelineRunning = false; return; }
    const today   = new Date().toISOString().split('T')[0];
    const weekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];

    // Process in batches of 5 — fetch daily + 5-min candles for each stock,
    // then immediately score both. No waiting for full universe to finish.
    const BATCH = 5;
    for (let i = 0; i < syms.length; i += BATCH) {
      const batch = syms.slice(i, i + BATCH);

      await Promise.all(batch.map(async (sym) => {
        const token = validTokens[sym] || INSTRUMENTS[sym];
        if (!token) return;

        // Fetch DAILY + 5-MIN candles in parallel for this stock
        const [dailyCandles, fiveMinCandles] = await Promise.all([
          fetchKiteDaily(sym).catch(() => null),
          kite.getHistoricalData(token, '5minute', weekAgo, today)
            .catch(() => null),
        ]);

        // ── TA Rescore path (daily candles → TA fields → stockFundamentals) ──
        if (dailyCandles) {
          try {
            const tech = computeTechnicals(dailyCandles);
            const sf = stockFundamentals[sym];
            if (sf) {
              for (const key of TA_FIELDS) {
                if (tech[key] !== undefined) sf[key] = tech[key];
              }
              sf.fetchedAt = Date.now();
            }
            okTA++;
          } catch (e) { failTA++; }
        } else { failTA++; }

        // ── DayTrade scoring path (5-min candles → setup detectors) ──
        if (fiveMinCandles && fiveMinCandles.length >= 30) {
          try {
            // Update livePrices while we're at it
            const lastC = fiveMinCandles[fiveMinCandles.length - 1];
            livePrices[sym] = { price: lastC.close, open: lastC.open, high: lastC.high, low: lastC.low, volume: lastC.volume };
            const scored = scoreDayTrade(fiveMinCandles, sym);
            if (scored) {
              scored.optionRec = getOptionRecommendation(sym, scored.price, scored.bestSetup, scored.sl, scored.tgt, scored.rrRatio);
              // Align snapshot timestamp to the bar we scored (the last 5-min bar).
              // Fallback to now() if the candle lacks a timestamp.
              const barTs = lastC.date ? (lastC.date instanceof Date ? lastC.date.getTime() : Date.parse(lastC.date)) : Date.now();
              scored.tsMs = barTs;
              scored.sector = stockFundamentals[sym]?.sector;
              scored.grp    = stockFundamentals[sym]?.grp;
              // Non-blocking: persist snapshot. Fire-and-forget pattern with
              // try/catch inside the call keeps the pipeline loop tight.
              mlLogger.logFeatureSnapshot(scored, 'unified_pipeline')
                .then(snapshotId => { scored._snapshotId = snapshotId; })
                .catch(e => console.warn('[ml-logger] snapshot failed:', e.message));
              // Also persist the last 5-min candle (most recent bar only — older
              // bars are already in the DB from prior cycles). ON CONFLICT DO
              // NOTHING means replays are safe.
              mlLogger.logCandlesBatch('candles_5m', [{
                sym, ts: new Date(barTs),
                open: lastC.open, high: lastC.high, low: lastC.low,
                close: lastC.close, volume: lastC.volume, vwap: scored.vwap,
              }]).catch(e => console.warn('[ml-logger] candle_5m failed:', e.message));
              dayTradeResults.push(scored);
            }
            okDT++;
          } catch (e) { failDT++; }
        } else { failDT++; }
      }));

      // Respect Kite rate limits — 5 stocks × 2 requests each = 10 req per batch
      if (i + BATCH < syms.length) await new Promise(r => setTimeout(r, 350));
    }

    // ── Finalize DayTrade cache with the same guard as scanDayTrades ──
    // If Kite rate-limits or auth fails mid-run, dayTradeResults can come
    // out empty and wipe a previously-good cache. Only overwrite when the
    // scan produced picks, the previous cache is already empty, or enough
    // DayTrade fetches succeeded that 0 picks is a meaningful signal.
    //
    // (Old code called a Promise.all with rebuildScoreCache() which isn't
    //  defined anywhere — threw a ReferenceError that aborted the pipeline
    //  before cache assignment. Removed in the earlier fix. Daily score
    //  cache is maintained by refreshAllFundamentals() on its own cadence.)
    const dtSuccessRatio = okDT / Math.max(syms.length, 1);
    if (dayTradeResults.length > 0 || _dayTradeCache.length === 0 || dtSuccessRatio > 0.3) {
      dayTradeResults.sort((a, b) => b.dayTradeScore - a.dayTradeScore);
      // Varsity M9 sector-correlation cap — same logic as scanDayTrades.
      _dayTradeCache   = applySectorCap(dayTradeResults, 2);
      _dayTradeCacheTs = Date.now();
    } else {
      console.log(`🔄 Unified pipeline: DayTrade ${okDT}/${syms.length} successful fetches — low ratio (${(dtSuccessRatio*100).toFixed(0)}%), keeping previous cache (${_dayTradeCache.length} picks)`);
    }

    const elapsed = ((Date.now() - t0) / 1000).toFixed(1);
    _pipelineLastRun = { startedAt: _pipelineLastRun.startedAt, status: 'completed', elapsed, okTA, failTA, okDT, failDT, dayTradeCount: dayTradeResults.length };
    console.log(`🔄 Unified pipeline: TA ${okTA}ok/${failTA}fail · DayTrade ${okDT}ok/${failDT}fail · ${dayTradeResults.length} setups · ${elapsed}s`);
    // Fire NIFTY50 1-min candle ingest — non-blocking. Runs alongside the
    // next scoring cycle; if it takes longer than 5 min the _nifty1mRunning
    // guard prevents overlap. Errors are logged, never propagated.
    ingestNifty50OneMinCandles()
      .then(r => r && !r.skipped && console.log(`📊 NIFTY50 1-min: ${r.ok}/${r.symbols} syms, ${r.barsWritten} bars`))
      .catch(e => console.warn('NIFTY50 1-min ingest error:', e.message));
  } catch (e) {
    _pipelineLastRun = { ..._pipelineLastRun, status: 'error', error: e.message, stack: e.stack?.split('\n').slice(0, 3).join(' | ') };
    console.error('🔄 Unified pipeline error:', e.message);
  } finally {
    _unifiedPipelineRunning = false;
  }
}

function computeTechnicals(candles) {
  const C = candles.map(c => c.close);
  const H = candles.map(c => c.high  || c.close);
  const L = candles.map(c => c.low   || c.close);
  const V = candles.map(c => c.volume || 0);
  const n = C.length;
  const avg = (arr, s, l) => arr.slice(s,s+l).reduce((a,b)=>a+b,0)/l;
  const calcEma = (arr, p) => { const k=2/(p+1); let e=arr[0]; return arr.map(v=>{e=v*k+e*(1-k);return e;}); };

  // Moving averages
  const dma20  = n>=20  ? avg(C,n-20,20)  : null;
  const dma50  = n>=50  ? avg(C,n-50,50)  : null;
  const dma100 = n>=100 ? avg(C,n-100,100): null;
  const dma200 = n>=200 ? avg(C,n-200,200): null;

  // 52-week range
  const yr252  = C.slice(-252);
  const wk52Hi = yr252.length ? Math.max(...yr252) : C[n-1];
  const wk52Lo = yr252.length ? Math.min(...yr252) : C[n-1];

  // Returns
  const change52w = n>=252 ? (C[n-1]-C[n-252])/C[n-252] : (C[n-1]-C[0])/C[0];
  const change6m  = n>=126 ? (C[n-1]-C[n-126])/C[n-126] : null;
  const change3m  = n>=63  ? (C[n-1]-C[n-63])/C[n-63]   : null;
  const change1m  = n>=21  ? (C[n-1]-C[n-21])/C[n-21]   : null;

  // RSI-14 — Wilder's smoothed RSI (Varsity M2 Ch14: proper smoothing, not simple average)
  let rsi = 50;
  if (n >= 15) {
    let avgG=0, avgL=0;
    // Seed: simple average of first 14 periods
    for(let i=1;i<=14;i++){ const d=C[i]-C[i-1]; if(d>0)avgG+=d; else avgL-=d; }
    avgG/=14; avgL/=14;
    // Wilder smoothing for remaining bars
    for(let i=15;i<n;i++){
      const d=C[i]-C[i-1];
      avgG=(avgG*13+(d>0?d:0))/14;
      avgL=(avgL*13+(d>0?0:-d))/14;
    }
    rsi = avgL===0 ? 100 : 100 - 100/(1+avgG/avgL);
  }

  // MACD (12,26,9)
  const e12=calcEma(C,12), e26=calcEma(C,26);
  const macdLine=e12.map((v,i)=>v-e26[i]);
  const signalLine=calcEma(macdLine,9);
  const macd=macdLine[n-1], macdSig=signalLine[n-1];
  const macdBull=macd>macdSig;
  const macdHist=+(macd-macdSig).toFixed(2);

  // Bollinger Bands (20,2)
  const bbMid=dma20||C[n-1];
  const bbStd=n>=20?Math.sqrt(C.slice(n-20).reduce((a,v)=>a+(v-bbMid)**2,0)/20):0;
  const bbUpper=+(bbMid+2*bbStd).toFixed(2);
  const bbLower=+(bbMid-2*bbStd).toFixed(2);
  const bbPct=bbUpper>bbLower?(C[n-1]-bbLower)/(bbUpper-bbLower):0.5;

  // Stochastic %K (14,3)
  let stochK=50;
  if(n>=14){
    const lo14=Math.min(...L.slice(n-14)), hi14=Math.max(...H.slice(n-14));
    stochK=hi14===lo14?50:(C[n-1]-lo14)/(hi14-lo14)*100;
  }

  // ADX (14) — Wilder smoothed (Varsity M2 Ch20: ADX>25=trending, +DI>-DI=bullish)
  let adx=20, adxPdi=0, adxNdi=0;
  if(n>=28){
    // Seed first 14 bars
    let sPdm=0,sNdm=0,sTr=0;
    for(let i=1;i<=14;i++){
      const um=H[i]-H[i-1],dm=L[i-1]-L[i];
      if(um>dm&&um>0)sPdm+=um; if(dm>um&&dm>0)sNdm+=dm;
      sTr+=Math.max(H[i]-L[i],Math.abs(H[i]-C[i-1]),Math.abs(L[i]-C[i-1]));
    }
    // Wilder smooth +DM, -DM, TR over remaining bars
    for(let i=15;i<n;i++){
      const um=H[i]-H[i-1],dm=L[i-1]-L[i];
      const curPdm=(um>dm&&um>0)?um:0, curNdm=(dm>um&&dm>0)?dm:0;
      sPdm=(sPdm*13+curPdm)/14; sNdm=(sNdm*13+curNdm)/14;
      sTr=(sTr*13+Math.max(H[i]-L[i],Math.abs(H[i]-C[i-1]),Math.abs(L[i]-C[i-1])))/14;
    }
    adxPdi = sTr>0 ? (sPdm/sTr)*100 : 0;
    adxNdi = sTr>0 ? (sNdm/sTr)*100 : 0;
    const dx = (adxPdi+adxNdi)>0 ? Math.abs(adxPdi-adxNdi)/(adxPdi+adxNdi)*100 : 0;
    adx = dx; // First DX value; ideally smoothed over 14 periods but single pass is reasonable
  }

  // Supertrend (10,3)
  let supertrendSig='neutral', supertrend=null;
  try{
    const atrArr=candles.slice(1).map((c,i)=>Math.max(c.high-c.low,Math.abs(c.high-candles[i].close),Math.abs(c.low-candles[i].close)));
    const atr14=atrArr.slice(-14).reduce((a,b)=>a+b,0)/14;
    let st=C[0],trend=1;
    for(let i=1;i<n;i++){
      const atri=atrArr[i-1]||atr14, mid=(H[i]+L[i])/2;
      const up=mid+3*atri, dn=mid-3*atri;
      if(trend===1)st=Math.max(st,dn); else st=Math.min(st,up);
      if(C[i]<st&&trend===1){trend=-1;st=up;} else if(C[i]>st&&trend===-1){trend=1;st=dn;}
    }
    supertrend=+st.toFixed(2); supertrendSig=trend===1?'bullish':'bearish';
  }catch(e){}

  // Volume analysis
  const vol10 = V.slice(-10).reduce((a,b)=>a+b,0)/10;
  const vol20 = V.slice(-20).reduce((a,b)=>a+b,0)/20;
  const vol60 = n>=60?V.slice(-60).reduce((a,b)=>a+b,0)/60:vol20;
  const volRatio = vol60>0 ? vol10/vol60 : 1;
  const volTrend = volRatio>1.3?'Accumulation':volRatio>1.1?'Rising':volRatio<0.7?'Distribution':'Normal';

  // OBV trend
  let obv=0;
  for(let i=1;i<n;i++) obv+=C[i]>C[i-1]?V[i]:C[i]<C[i-1]?-V[i]:0;
  const obv20ago = (()=>{ let o=0; for(let i=1;i<n-20;i++) o+=C[i]>C[i-1]?V[i]:C[i]<C[i-1]?-V[i]:0; return o; })();
  const obvRising = obv>obv20ago;

  // Accumulation/Distribution
  const upVol=V.slice(-20).filter((_,i)=>C[Math.max(0,n-20+i)]>(i>0?C[n-20+i-1]:C[n-21])).reduce((a,b)=>a+b,0);
  const dnVol=V.slice(-20).filter((_,i)=>C[Math.max(0,n-20+i)]<(i>0?C[n-20+i-1]:C[n-21])).reduce((a,b)=>a+b,0);
  const accumDist=upVol>dnVol?'Accumulation':'Distribution';

  // Beta
  const rets = C.slice(-252).map((c,i,a)=>i===0?0:(c-a[i-1])/a[i-1]).slice(1);
  const std  = rets.length?Math.sqrt(rets.reduce((a,b)=>a+b*b,0)/rets.length):0.013;
  const beta = +Math.min(Math.max(std/0.013,0.3),2.5).toFixed(2);
  const annualVol = +(std*Math.sqrt(252)*100).toFixed(1);

  // EMA 50/200 for crossover signals — Varsity M2 Ch13: "EMA is more responsive, preferred for signals"
  const ema50  = n>=50  ? calcEma(C,50)[n-1]  : null;
  const ema200 = n>=200 ? calcEma(C,200)[n-1] : null;
  const emaGoldenCross = (ema50&&ema200) ? ema50>ema200 : null;

  // 200DMA trend
  const dma200_30ago = n>=230 ? avg(C,n-230,200) : null;
  const dma200Trend = dma200&&dma200_30ago?(dma200>dma200_30ago?'rising':'falling'):null;

  // Weekly higher highs/lows
  const recent=C.slice(-20);
  const fMax=Math.max(...recent.slice(0,10)), sMax=Math.max(...recent.slice(10));
  const fMin=Math.min(...recent.slice(0,10)), sMin=Math.min(...recent.slice(10));
  const weeklyTrend=sMax>fMax&&sMin>fMin?'uptrend':sMax<fMax&&sMin<fMin?'downtrend':'sideways';

  // RSI Divergence (Arjun: Quant signal — high quality reversal indicator)
  const rsiDiv = n >= 34 ? computeRSIDivergence(C, 20) : { rsiTrend:null, bullishDiv:false, bearishDiv:false };

  // ═══ NEW: Fibonacci Retracement Levels (Varsity M2 Ch19: 38.2%, 50%, 61.8%) ═══
  const fibHigh = wk52Hi, fibLow = wk52Lo, fibRange = fibHigh - fibLow;
  const fib236 = fibRange > 0 ? +(fibHigh - fibRange * 0.236).toFixed(2) : null;
  const fib382 = fibRange > 0 ? +(fibHigh - fibRange * 0.382).toFixed(2) : null;
  const fib500 = fibRange > 0 ? +(fibHigh - fibRange * 0.500).toFixed(2) : null;
  const fib618 = fibRange > 0 ? +(fibHigh - fibRange * 0.618).toFixed(2) : null;
  // Nearest fib level to current price
  const fibLevels = [fib236, fib382, fib500, fib618].filter(Boolean);
  const nearestFib = fibLevels.length ? fibLevels.reduce((best, l) => Math.abs(C[n-1]-l) < Math.abs(C[n-1]-best) ? l : best) : null;
  const nearFibDist = nearestFib ? +((C[n-1] - nearestFib) / nearestFib * 100).toFixed(1) : null;

  // ═══ NEW: Support & Resistance (Varsity M2 Ch7: recent swing highs/lows) ═══
  let support = null, resistance = null;
  if (n >= 60) {
    // Find swing lows (support) and swing highs (resistance) from last 60 candles
    const swingH = [], swingL = [];
    for (let i = n - 58; i < n - 2; i++) {
      if (H[i] > H[i-1] && H[i] > H[i+1] && H[i] > H[i-2] && H[i] > H[i+2]) swingH.push(H[i]);
      if (L[i] < L[i-1] && L[i] < L[i+1] && L[i] < L[i-2] && L[i] < L[i+2]) swingL.push(L[i]);
    }
    // Nearest support below current price, nearest resistance above
    const below = swingL.filter(l => l < C[n-1]).sort((a,b) => b - a);
    const above = swingH.filter(h => h > C[n-1]).sort((a,b) => a - b);
    support = below.length ? +below[0].toFixed(2) : (fibLevels.find(l => l < C[n-1]) || null);
    resistance = above.length ? +above[0].toFixed(2) : (fibLevels.reverse().find(l => l > C[n-1]) || null);
  }

  // ═══ NEW: Ichimoku Cloud (Varsity M2: Tenkan, Kijun, Senkou A/B) ═══
  let ichimokuSignal = null, ichimokuTenkan = null, ichimokuKijun = null;
  if (n >= 52) {
    const hh = (arr, start, len) => Math.max(...arr.slice(start, start+len));
    const ll = (arr, start, len) => Math.min(...arr.slice(start, start+len));
    ichimokuTenkan = +((hh(H,n-9,9) + ll(L,n-9,9)) / 2).toFixed(2);    // Tenkan-sen (9)
    ichimokuKijun  = +((hh(H,n-26,26) + ll(L,n-26,26)) / 2).toFixed(2); // Kijun-sen (26)
    const senkouA = +((ichimokuTenkan + ichimokuKijun) / 2).toFixed(2);
    const senkouB = +((hh(H,n-52,52) + ll(L,n-52,52)) / 2).toFixed(2);
    const cloudTop = Math.max(senkouA, senkouB);
    const cloudBot = Math.min(senkouA, senkouB);
    if (C[n-1] > cloudTop) ichimokuSignal = 'above_cloud';       // Bullish
    else if (C[n-1] < cloudBot) ichimokuSignal = 'below_cloud';  // Bearish
    else ichimokuSignal = 'inside_cloud';                         // No-trade zone
  }

  // ═══ NEW: Pivot Points (classic floor trader's method) ═══
  const pivotHigh = H[n-1], pivotLow = L[n-1], pivotClose = C[n-1];
  const pivot = +((pivotHigh + pivotLow + pivotClose) / 3).toFixed(2);
  const pivotR1 = +(2 * pivot - pivotLow).toFixed(2);
  const pivotS1 = +(2 * pivot - pivotHigh).toFixed(2);
  const pivotR2 = +(pivot + (pivotHigh - pivotLow)).toFixed(2);
  const pivotS2 = +(pivot - (pivotHigh - pivotLow)).toFixed(2);

  // ═══ NEW: Multi-timeframe weekly confirmation (Varsity M2: weekly overrides daily) ═══
  // Convert to weekly bars and check 20-week SMA trend
  let weeklyTrendConfirmed = null;
  if (n >= 100) {
    const weeklyCloses = [];
    for (let i = 0; i < n; i += 5) weeklyCloses.push(C[Math.min(i + 4, n - 1)]);
    const wn = weeklyCloses.length;
    if (wn >= 20) {
      const wSma20 = weeklyCloses.slice(wn-20).reduce((a,b)=>a+b,0) / 20;
      const wSma20_prev = weeklyCloses.slice(wn-25, wn-5).reduce((a,b)=>a+b,0) / 20;
      weeklyTrendConfirmed = weeklyCloses[wn-1] > wSma20 && wSma20 > wSma20_prev ? 'bullish' :
                             weeklyCloses[wn-1] < wSma20 && wSma20 < wSma20_prev ? 'bearish' : 'neutral';
    }
  }

  // ═══ NEW: Dow Theory (Varsity M2: higher highs/lows vs lower highs/lows) ═══
  let dowTheoryTrend = null;
  if (n >= 120) {
    // Find last 4 significant swing highs and lows over 6 months
    const lookback = Math.min(126, n);
    const sH = [], sL = [];
    for (let i = n - lookback + 2; i < n - 2; i++) {
      if (H[i] >= H[i-1] && H[i] >= H[i+1] && H[i] >= H[i-2] && H[i] >= H[i+2]) sH.push(H[i]);
      if (L[i] <= L[i-1] && L[i] <= L[i+1] && L[i] <= L[i-2] && L[i] <= L[i+2]) sL.push(L[i]);
    }
    if (sH.length >= 2 && sL.length >= 2) {
      const lastH = sH.slice(-2), lastL = sL.slice(-2);
      if (lastH[1] > lastH[0] && lastL[1] > lastL[0]) dowTheoryTrend = 'uptrend';
      else if (lastH[1] < lastH[0] && lastL[1] < lastL[0]) dowTheoryTrend = 'downtrend';
      else dowTheoryTrend = 'sideways';
    }
  }

  return {
    price:C[n-1],
    dma20, dma50, dma100, dma200,
    wk52Hi, wk52Lo, change52w, change6m, change3m, change1m,
    rsi:+rsi.toFixed(1),
    macd:+macd.toFixed(2), macdSig:+macdSig.toFixed(2), macdBull, macdHist,
    bbUpper, bbLower, bbMid:+bbMid.toFixed(2), bbPct:+bbPct.toFixed(2),
    stochK:+stochK.toFixed(1),
    adx:+adx.toFixed(1), adxPdi:+adxPdi.toFixed(1), adxNdi:+adxNdi.toFixed(1),
    supertrend, supertrendSig,
    volRatio:+volRatio.toFixed(2), volTrend, obvRising, accumDist,
    beta, annualVol,
    dma200Trend, weeklyTrend,
    ema50: ema50?+ema50.toFixed(2):null, ema200: ema200?+ema200.toFixed(2):null,
    goldenCross: emaGoldenCross ?? ((dma50&&dma200) ? dma50>dma200 : null), // prefer EMA cross
    pctFromHigh: wk52Hi>0 ? +((C[n-1]-wk52Hi)/wk52Hi*100).toFixed(1) : null,
    pctAbove200: dma200>0 ? +((C[n-1]-dma200)/dma200*100).toFixed(1) : null,
    pctAbove50:  dma50>0  ? +((C[n-1]-dma50)/dma50*100).toFixed(1)   : null,
    // RSI divergence signals
    rsiTrend: rsiDiv.rsiTrend,
    bullishDiv: rsiDiv.bullishDiv,
    bearishDiv: rsiDiv.bearishDiv,
    // Fibonacci levels
    fib382, fib500, fib618, nearestFib, nearFibDist,
    // Support & Resistance
    support, resistance,
    // Ichimoku
    ichimokuSignal, ichimokuTenkan, ichimokuKijun,
    // Pivot Points
    pivot, pivotR1, pivotS1, pivotR2, pivotS2,
    // Multi-timeframe & Dow Theory
    weeklyTrendConfirmed, dowTheoryTrend,
  };
}

// -- Main refresh --------------------------------------------------------------
async function refreshAllFundamentals() {
  if (stockFundLoading) return;
  if (!kite || !process.env.KITE_ACCESS_TOKEN) {
    console.log('📊 Kite not ready - restoring from DB cache...');
    let restored = 0;

    // Strategy 1: Try full scored_stocks_cache first (has ALL fields including fundamentals + technicals)
    try {
      const cached = await dbGet('scored_stocks_cache');
      if (cached) {
        const { stocks, fetchedAt } = JSON.parse(cached);
        const age = ((Date.now()-fetchedAt)/3600000).toFixed(1);
        if (stocks && Object.keys(stocks).length > 10) {
          for (const [sym, cachedStock] of Object.entries(stocks)) {
            if (!stockFundamentals[sym]) {
              stockFundamentals[sym] = cachedStock;
            } else {
              // Merge: fill any nulls from cache
              for (const [k, v] of Object.entries(cachedStock)) {
                if (stockFundamentals[sym][k] == null && v != null) stockFundamentals[sym][k] = v;
              }
            }
            restored++;
          }
          console.log(`📊 Restored ${restored} stocks from scored cache (${age}h old)`);
        }
      }
    } catch(e) { console.log('📊 Scored cache restore failed:', e.message); }

    // Strategy 2: Overlay TA-specific cache (may be fresher than scored cache)
    try {
      const taCached = await dbGet('ta_data_cache');
      if (taCached) {
        const { ta, fetchedAt } = JSON.parse(taCached);
        const age = ((Date.now()-fetchedAt)/3600000).toFixed(1);
        let taRestored = 0;
        if (ta && Object.keys(ta).length > 10) {
          for (const [sym, taData] of Object.entries(ta)) {
            if (!stockFundamentals[sym]) {
              // Create minimal entry from TA data
              stockFundamentals[sym] = { sym, name: sym, grp: 'Unknown', sector: 'Other', ...taData };
              taRestored++;
            } else {
              // Overlay TA fields (TA cache may be newer than scored cache)
              for (const [k, v] of Object.entries(taData)) {
                if (v != null) stockFundamentals[sym][k] = v;
              }
              taRestored++;
            }
          }
          console.log(`📊 Overlaid TA data for ${taRestored} stocks from TA cache (${age}h old)`);
        }
      }
    } catch(e) { console.log('📊 TA cache restore failed:', e.message); }

    if (restored > 0 || Object.keys(stockFundamentals).length > 10) stockFundReady = true;
    console.log(`📊 Cache restore complete: ${Object.keys(stockFundamentals).length} stocks with data`);
    return;
  }
  stockFundLoading = true;
  console.log('📊 Stock scoring: fetching Kite daily candles in parallel batches...');
  let ok=0, fail=0;

  // Fetch Nifty 50 benchmark for relative strength — Varsity M9: "compare stock return vs market"
  try {
    const niftyCandles = await fetchKiteDaily('NIFTY 50');
    if (niftyCandles && niftyCandles.length > 0) {
      const NC = niftyCandles.map(c => c.close);
      const nn = NC.length;
      niftyBenchmark['52w'] = nn>=252 ? (NC[nn-1]-NC[nn-252])/NC[nn-252] : 0;
      niftyBenchmark['6m']  = nn>=126 ? (NC[nn-1]-NC[nn-126])/NC[nn-126] : 0;
      niftyBenchmark['3m']  = nn>=63  ? (NC[nn-1]-NC[nn-63])/NC[nn-63]   : 0;
      niftyBenchmark['1m']  = nn>=21  ? (NC[nn-1]-NC[nn-21])/NC[nn-21]   : 0;
      console.log(`📊 Nifty 50 benchmark: 52W=${(niftyBenchmark['52w']*100).toFixed(1)}%, 6M=${(niftyBenchmark['6m']*100).toFixed(1)}%`);
    }
  } catch(e) { console.log('📊 Nifty benchmark fetch failed (non-critical):', e.message); }

  // Fetch in parallel batches of 5 — Kite rate limit ~10 req/s, keep headroom for scans
  // Each call has a 12s timeout so a hanging stock never blocks the batch
  const BATCH = 5;
  const stocks = [...UNIVERSE];

  for (let i = 0; i < stocks.length; i += BATCH) {
    const batch = stocks.slice(i, i + BATCH);
    await Promise.all(batch.map(async stock => {
      try {
        const candles = await fetchKiteDaily(stock.sym);
        const tech = candles ? computeTechnicals(candles) : {};
        if (!candles) fail++; else ok++;
        const f    = FUND[stock.sym] || null;
        const ext = global.FUND_EXT?.[stock.sym];
        // Always create entry — show fundamentals even without candle data
        stockFundamentals[stock.sym] = {
          sym:stock.sym, name:stock.n, grp:stock.grp,
          sector: SECTOR_MAP[stock.sym] || ext?.industry || 'Other',
          price:tech.price??livePrices[stock.sym]?.price??stockFundamentals[stock.sym]?.price??ext?.price??null,
          dma20:tech.dma20??null, dma50:tech.dma50??null, dma100:tech.dma100??null, dma200:tech.dma200??null,
          wk52Hi:tech.wk52Hi??null, wk52Lo:tech.wk52Lo??null,
          change52w:tech.change52w??null, change6m:tech.change6m??null, change3m:tech.change3m??null, change1m:tech.change1m??null,
          rsi:tech.rsi??null,
          macd:tech.macd??null, macdBull:tech.macdBull??null, macdHist:tech.macdHist??null,
          bbPct:tech.bbPct??null, bbUpper:tech.bbUpper??null, bbLower:tech.bbLower??null,
          stochK:tech.stochK??null, adx:tech.adx??null, adxPdi:tech.adxPdi??null, adxNdi:tech.adxNdi??null,
          supertrend:tech.supertrend??null, supertrendSig:tech.supertrendSig??null,
          volRatio:tech.volRatio??null, volTrend:tech.volTrend??null, obvRising:tech.obvRising??null, accumDist:tech.accumDist??null,
          beta:tech.beta??null, annualVol:tech.annualVol??null,
          dma200Trend:tech.dma200Trend??null, weeklyTrend:tech.weeklyTrend??null,
          ema50:tech.ema50??null, ema200:tech.ema200??null,
          goldenCross:tech.goldenCross??null,
          pctFromHigh:tech.pctFromHigh??null, pctAbove200:tech.pctAbove200??null, pctAbove50:tech.pctAbove50??null,
          rsiTrend:tech.rsiTrend??null, bullishDiv:tech.bullishDiv??null, bearishDiv:tech.bearishDiv??null,
          // Fibonacci, S&R, Ichimoku, Pivot, Multi-timeframe
          fib382:tech.fib382??null, fib500:tech.fib500??null, fib618:tech.fib618??null,
          nearestFib:tech.nearestFib??null, nearFibDist:tech.nearFibDist??null,
          support:tech.support??null, resistance:tech.resistance??null,
          ichimokuSignal:tech.ichimokuSignal??null, ichimokuTenkan:tech.ichimokuTenkan??null, ichimokuKijun:tech.ichimokuKijun??null,
          pivot:tech.pivot??null, pivotR1:tech.pivotR1??null, pivotS1:tech.pivotS1??null, pivotR2:tech.pivotR2??null, pivotS2:tech.pivotS2??null,
          weeklyTrendConfirmed:tech.weeklyTrendConfirmed??null, dowTheoryTrend:tech.dowTheoryTrend??null,
          // Core fundamentals — screener overrides hardcoded FUND
          roe:      f?f[0]:null, debtToEq:f?f[1]:null, pe:f?f[2]:null,
          revGrowth:f?f[3]:null, earGrowth:f?f[4]:null, opMargin:f?f[5]:null,
          peg:      ext?.peg ?? (f&&f[2]&&f[4]&&f[4]>0 ? +(f[2]/f[4]).toFixed(2) : null),
          // Extended from Screener.in
          roa:          ext?.roa          ?? null,
          pb:           ext?.pb           ?? (ext?.bookValue > 0 && (tech.price||livePrices[stock.sym]?.price) ? +((tech.price||livePrices[stock.sym]?.price)/ext.bookValue).toFixed(2) : null),
          intCov:       ext?.intCov       ?? null,
          promoter:     ext?.promoter     ?? null,
          pledged:      ext?.pledged      ?? null,
          promoterChg:  ext?.promoterChg  ?? null,
          mktCap:       ext?.mktCap       ?? null,
          divYield:     ext?.divYield     ?? null,
          eps:          ext?.eps          ?? null,
          debt:         ext?.debt         ?? null,
          currentRatio: ext?.currentRatio ?? null,
          salesGr1y:    ext?.salesGr1y    ?? null,
          salesGr5y:    ext?.salesGr5y    ?? null,
          epsGr1y:      ext?.epsGr1y      ?? null,
          epsGr5y:      ext?.epsGr5y      ?? null,
          roe3yAvg:     ext?.roe3yAvg     ?? null,
          roe5yAvg:     ext?.roe5yAvg     ?? null,
          ret1y:        ext?.ret1y        ?? null,
          ret3y:        ext?.ret3y        ?? null,
          ret5y:        ext?.ret5y        ?? null,
          ret6m:        ext?.ret6m        ?? (tech.change6m != null ? +(tech.change6m*100).toFixed(1) : null),
          ret3m:        ext?.ret3m        ?? (tech.change3m != null ? +(tech.change3m*100).toFixed(1) : null),
          evEbitda:     ext?.evEbitda     ?? null,
          industryPE:   ext?.industryPE   ?? null,
          earningsYield:ext?.earningsYield ?? ((f&&f[2]&&f[2]>0) ? +(100/f[2]).toFixed(2) : null),
          priceToFCF:   ext?.priceToFCF   ?? null,
          priceToSales: ext?.priceToSales ?? (ext?.mktCap > 0 && ext?.salesAnnual > 0 ? +((ext.mktCap / 10000000) / ext.salesAnnual).toFixed(2) : null),
          roce:         ext?.roce         ?? null,
          patQtr:       ext?.patQtr       ?? null,
          salesQtr:     ext?.salesQtr     ?? null,
          patAnnual:    ext?.patAnnual    ?? null,
          salesAnnual:  ext?.salesAnnual  ?? null,
          patQtrYoy:    ext?.patQtrYoy    ?? null,
          salesQtrYoy:  ext?.salesQtrYoy  ?? null,
          // Extended fields (Screener.in + Yahoo fallback)
          fwdPE:        ext?.fwdPE        ?? null,
          grossMgn:     ext?.grossMgn     ?? null,
          profMgn:      ext?.profMgn      ?? null,
          quickRatio:   ext?.quickRatio   ?? null,
          fcf:          ext?.fcf          ?? null,
          instHeld:     ext?.instHeld     ?? null,
          bookValue:    ext?.bookValue    ?? null,
          fiiHolding:   ext?.fiiHolding   ?? null,
          diiHolding:   ext?.diiHolding   ?? null,
          numShareholders: ext?.numShareholders ?? null,
          // Pre-computed DuPont, CCC, WC from screener data
          dupontNetMargin:       ext?.dupontNetMargin       ?? null,
          dupontAssetTurnover:   ext?.dupontAssetTurnover   ?? null,
          dupontEquityMultiplier:ext?.dupontEquityMultiplier ?? null,
          dupontROE:             ext?.dupontROE             ?? null,
          cashConversionCycle:   ext?.cashConversionCycle   ?? null,
          workingCapitalHealth:  ext?.workingCapitalHealth  ?? null,
          debtorDays:            ext?.debtorDays            ?? null,
          invTurnover:           ext?.invTurnover           ?? null,
          assetTurnover:         ext?.assetTurnover         ?? null,
          dataSource:   ext?.source       ?? 'Hardcoded',
          fetchedAt:Date.now(),
        };

        // ── Computed fallbacks for fields that data sources didn't return ──
        const sf = stockFundamentals[stock.sym];
        const _px = sf.price;
        const _pat = sf.patAnnual;
        const _eps = sf.eps;
        const _sales = sf.salesAnnual;

        // mktCap: price * shares, where shares ≈ patAnnual / eps (in Cr)
        if (sf.mktCap == null && _px && _pat && _eps && _eps > 0) {
          sf.mktCap = +(_px * _pat / _eps).toFixed(0);
        }
        // mktCap fallback: price * salesAnnual / priceToSales (if priceToSales from ext)
        if (sf.mktCap == null && _px && _sales > 0 && ext?.priceToSales > 0) {
          sf.mktCap = +(_sales * ext.priceToSales).toFixed(0);
        }
        // mktCap fallback 2: from PE * patAnnual (if PE available)
        if (sf.mktCap == null && sf.pe > 0 && _pat && _pat > 0) {
          sf.mktCap = +(sf.pe * _pat).toFixed(0);
        }

        // priceToSales: mktCap / salesAnnual
        if (sf.priceToSales == null && sf.mktCap > 0 && _sales > 0) {
          sf.priceToSales = +(sf.mktCap / _sales).toFixed(2);
        }

        // priceToFCF: mktCap / fcf
        if (sf.priceToFCF == null && sf.mktCap > 0 && sf.fcf > 0) {
          sf.priceToFCF = +(sf.mktCap / sf.fcf).toFixed(1);
        }

        // evEbitda: (mktCap + debt) / EBITDA, where EBITDA ≈ sales * opMargin / 100
        if (sf.evEbitda == null && sf.mktCap > 0 && _sales > 0 && sf.opMargin > 0) {
          const ebitda = _sales * sf.opMargin / 100;
          const ev = sf.mktCap + (sf.debt || 0);
          if (ebitda > 0) sf.evEbitda = +(ev / ebitda).toFixed(1);
        }

        // divYield: dividendPayout% * eps / price (approx)
        if (sf.divYield == null && _px > 0 && _eps > 0 && ext?.divYield > 0) {
          // ext.divYield from screener might be payout %, convert to yield
          sf.divYield = +(ext.divYield * _eps / _px).toFixed(2);
        }

        // ═══ DuPont ROE Decomposition (Varsity M3: Net Margin × Asset Turnover × Equity Multiplier) ═══
        // Prefer pre-computed values from screener (uses actual Total Assets / Net Worth)
        // Fall back to estimation if screener data not yet available
        let _npm = sf.dupontNetMargin ?? sf.profMgn ?? ext?.profMgn;
        if (_npm == null && _pat > 0 && _sales > 0) {
          _npm = +(_pat / _sales * 100).toFixed(2);
        }
        if (_npm != null) sf.profMgn = +_npm;

        let _assetTurn = sf.dupontAssetTurnover ?? sf.assetTurnover ?? ext?.assetTurnover;
        const _de2 = sf.debtToEq ?? ext?.de;
        if (_assetTurn == null && _sales > 0 && sf.bookValue > 0 && _px > 0 && sf.mktCap > 0) {
          const sharesEst = sf.mktCap / _px;
          const equity = sf.bookValue * sharesEst;
          const totalAssets = equity * (1 + (_de2 || 0));
          if (totalAssets > 0) _assetTurn = +(_sales / totalAssets).toFixed(2);
        }
        if (_assetTurn != null) sf.assetTurnover = +_assetTurn;

        let _em = sf.dupontEquityMultiplier;
        if (_em == null && _de2 != null) _em = +(1 + _de2).toFixed(2);

        if (_npm != null && _assetTurn != null && _em != null) {
          sf.dupontNetMargin = +_npm;
          sf.dupontAssetTurnover = +_assetTurn;
          sf.dupontEquityMultiplier = +_em;
          sf.dupontROE = +(_npm/100 * _assetTurn * _em * 100).toFixed(1);
        }

        // ═══ Gross Margin — compute if not already set from screener ═══
        if (sf.grossMgn == null && _sales > 0 && sf.opMargin != null) {
          sf.grossMgn = +sf.opMargin; // OPM% is the best proxy from screener P&L
        }

        // ═══ Institutional Holding — FII + DII if not set ═══
        if (sf.instHeld == null && (sf.fiiHolding != null || sf.diiHolding != null)) {
          sf.instHeld = +((sf.fiiHolding || 0) + (sf.diiHolding || 0)).toFixed(1);
        }

        // ═══ Cash Conversion Cycle (Varsity M13: Debtor Days + Inv Days - Payable Days) ═══
        // Prefer pre-computed CCC from screener ratios table
        if (sf.cashConversionCycle == null) {
          const _debtorDays = sf.debtorDays ?? ext?.debtorDays;
          const _invTurnover = sf.invTurnover ?? ext?.invTurnover;
          if (_debtorDays != null && _invTurnover != null && _invTurnover > 0) {
            sf.inventoryDays = +(365 / _invTurnover).toFixed(0);
            sf.cashConversionCycle = +(_debtorDays + sf.inventoryDays).toFixed(0);
          }
        }

        // ═══ NEW: Sharpe Ratio (Varsity M10: (Return - RiskFree) / StdDev) ═══
        const _ret1y = sf.ret1y ?? (tech.change52w != null ? +(tech.change52w * 100).toFixed(1) : null);
        const _annVol = sf.annualVol;
        if (_ret1y != null && _annVol != null && _annVol > 0) {
          const riskFreeRate = 7.0; // Approximate India risk-free rate (10Y G-Sec ~7%)
          sf.sharpeRatio = +((_ret1y - riskFreeRate) / _annVol).toFixed(2);
        }

        // ═══ NEW: Working Capital Ratio from balance sheet data ═══
        if (sf.currentRatio != null && sf.debt != null && sf.mktCap != null) {
          sf.workingCapitalHealth = sf.currentRatio >= 1.5 ? 'strong' : sf.currentRatio >= 1.0 ? 'adequate' : 'weak';
        }

      } catch(e) { fail++; }
    }));
    // Small pause between batches to respect Kite rate limits (5 req/batch + 500ms gap ≈ 10 req/s safe)
    if (i + BATCH < stocks.length) await new Promise(r=>setTimeout(r,500));
  }

  // ── Post-loop: compute industryPE as median PE per sector ──
  const sectorPEs = {};
  Object.values(stockFundamentals).forEach(f => {
    if (f.pe > 0 && f.sector) {
      if (!sectorPEs[f.sector]) sectorPEs[f.sector] = [];
      sectorPEs[f.sector].push(f.pe);
    }
  });
  // Compute all-stock median as fallback for small sectors
  const allPEs = Object.values(sectorPEs).flat().sort((a,b) => a - b);
  const allMedianPE = allPEs.length ? +allPEs[Math.floor(allPEs.length / 2)].toFixed(1) : null;
  Object.values(stockFundamentals).forEach(f => {
    if (f.industryPE == null && f.sector) {
      const pes = sectorPEs[f.sector];
      if (pes && pes.length >= 2) {
        const sorted = [...pes].sort((a,b) => a - b);
        f.industryPE = +sorted[Math.floor(sorted.length / 2)].toFixed(1);
      } else if (allMedianPE) {
        f.industryPE = allMedianPE; // fallback to market median
      }
    }
  });

  // ── Post-scoring: merge FUND_EXT (Screener.in) into stockFundamentals ──
  // Scoring creates fresh entries from ext = global.FUND_EXT, but if FUND_EXT was
  // loaded from DB rows that predated ALTER TABLE columns (fii_holding, dii_holding, etc.),
  // those fields are null. A concurrent Screener fetch may have updated FUND_EXT since.
  // This final merge ensures any freshly-arrived Screener data is captured.
  if (global.FUND_EXT && Object.keys(global.FUND_EXT).length > 0) {
    const extFields = ['currentRatio','quickRatio','divYield','pledged','fiiHolding','diiHolding',
      'numShareholders','patQtrYoy','salesQtrYoy','patQtr','salesQtr','patAnnual','salesAnnual',
      'priceToFCF','priceToSales','earningsYield','roce','promoter','promoterChg','intCov',
      'mktCap','roa','pb','peg','evEbitda','industryPE','eps','debt',
      'salesGr1y','salesGr5y','epsGr1y','epsGr5y','roe3yAvg','roe5yAvg',
      'ret1y','ret3y','ret5y','roe','debtToEq','pe','revGrowth','earGrowth','opMargin',
      // NEW: computed margins, DuPont, CCC from screener
      'grossMgn','profMgn','instHeld','debtorDays','invTurnover','assetTurnover',
      'cashConversionCycle','workingCapitalHealth',
      'dupontNetMargin','dupontAssetTurnover','dupontEquityMultiplier','dupontROE'];
    // Map FUND_EXT field names that differ from stockFundamentals field names
    const extKeyMap = { debtToEq:'de', revGrowth:'revGr', earGrowth:'epsGr', opMargin:'opMgn' };
    let merged = 0;
    for (const [sym, ext] of Object.entries(global.FUND_EXT)) {
      const sf = stockFundamentals[sym];
      if (!sf) continue;
      let changed = false;
      for (const field of extFields) {
        if (sf[field] != null) continue; // already has value
        const extKey = extKeyMap[field] || field;
        const v = ext[extKey];
        if (v != null) { sf[field] = v; changed = true; }
      }
      if (changed) merged++;
    }
    if (merged > 0) console.log(`📊 Post-scoring: merged FUND_EXT into ${merged} stocks (FII, DII, QoQ, etc.)`);
  }

  stockFundLastFetch = Date.now();
  stockFundLoading   = false;
  stockFundReady     = ok > 10;
  console.log(`📊 Stock scoring done: ${ok} OK, ${fail} failed`);

  // Persist to stock_scores table AND kv cache
  if (ok > 10) {
    // Save to kv cache (fast startup restore)
    try {
      await dbSet('scored_stocks_cache', JSON.stringify({
        stocks: stockFundamentals,
        fetchedAt: stockFundLastFetch,
      }));
      // Also save TA-only cache separately — never gets overwritten by non-Kite restarts
      // IMPORTANT: include ALL technical fields that appear in the UI
      const taCache = {};
      for (const [sym, f] of Object.entries(stockFundamentals)) {
        if (f.rsi != null || f.macdBull != null || f.dma200 != null) {
          taCache[sym] = {
            price:f.price,
            // DMAs
            dma20:f.dma20, dma50:f.dma50, dma100:f.dma100, dma200:f.dma200,
            ema50:f.ema50, ema200:f.ema200,
            // Trend
            goldenCross:f.goldenCross, dma200Trend:f.dma200Trend, weeklyTrend:f.weeklyTrend,
            supertrend:f.supertrend, supertrendSig:f.supertrendSig,
            // Momentum
            rsi:f.rsi, rsiTrend:f.rsiTrend, macd:f.macd, macdBull:f.macdBull, macdHist:f.macdHist,
            stochK:f.stochK, adx:f.adx, adxPdi:f.adxPdi, adxNdi:f.adxNdi,
            // Volatility
            bbPct:f.bbPct, bbUpper:f.bbUpper, bbLower:f.bbLower,
            annualVol:f.annualVol, beta:f.beta,
            // Volume
            volRatio:f.volRatio, volTrend:f.volTrend, obvRising:f.obvRising, accumDist:f.accumDist,
            // Returns
            change52w:f.change52w, change6m:f.change6m, change3m:f.change3m, change1m:f.change1m,
            // Price levels
            wk52Hi:f.wk52Hi, wk52Lo:f.wk52Lo,
            pctFromHigh:f.pctFromHigh, pctAbove200:f.pctAbove200, pctAbove50:f.pctAbove50,
            // Divergences
            bullishDiv:f.bullishDiv, bearishDiv:f.bearishDiv,
          };
        }
      }
      if (Object.keys(taCache).length > 10) {
        await dbSet('ta_data_cache', JSON.stringify({ ta: taCache, fetchedAt: Date.now() }));
        console.log(`📊 Saved TA cache: ${Object.keys(taCache).length} stocks with technical data`);
      }
    } catch(e) {}

    // Save individual scores to stock_scores table (queryable, durable)
    let saved = 0;
    for (const [sym, f] of Object.entries(stockFundamentals)) {
      try {
        await pool.query(`
          INSERT INTO stock_scores (sym, score, score_hits, fa_score, fa_verdict, fa_color, fa_icon, is_fallen, technicals, updated_at)
          VALUES ($1,$2,$3,$4,$5,$6,$7,$8,$9,NOW())
          ON CONFLICT (sym) DO UPDATE SET
            score=EXCLUDED.score, score_hits=EXCLUDED.score_hits,
            fa_score=EXCLUDED.fa_score, fa_verdict=EXCLUDED.fa_verdict,
            fa_color=EXCLUDED.fa_color, fa_icon=EXCLUDED.fa_icon,
            is_fallen=EXCLUDED.is_fallen, technicals=EXCLUDED.technicals,
            updated_at=NOW()
        `, [
          sym,
          f.score || null,
          f.hits ? JSON.stringify(f.hits) : null,
          f.fallenScore || null,
          f.fallenVerdict || null,
          f.fallenColor || null,
          f.fallenIcon || null,
          f.isFallenAngel || false,
          JSON.stringify({
            price: f.price, rsi: f.rsi, dma200: f.dma200, dma50: f.dma50,
            goldenCross: f.goldenCross, macdBull: f.macdBull, obvRising: f.obvRising,
            pctFromHigh: f.pctFromHigh, wk52Hi: f.wk52Hi, wk52Lo: f.wk52Lo,
            stochK: f.stochK, bbPct: f.bbPct, adx: f.adx, beta: f.beta,
            volRatio: f.volRatio, bullishDiv: f.bullishDiv, supertrend: f.supertrend,
            supertrendSig: f.supertrendSig, change52w: f.change52w,
          }),
        ]);
        saved++;
      } catch(e) {}
    }
    console.log(`📊 ${saved} stock scores saved to DB`);
  }
}

// -- Patch fundamentals into existing stockFundamentals without re-fetching candles --
// Called after Yahoo scraper fills FUND, so stocks already scored get updated data
function patchFundamentalsIntoScored() {
  let patched = 0;
  for (const sym of Object.keys(stockFundamentals)) {
    const f = FUND[sym];
    if (!f) continue;
    const s = stockFundamentals[sym];
    // Only patch if current data is null (don't overwrite existing)
    if (s.roe == null)      { s.roe       = f[0]; patched++; }
    if (s.debtToEq == null) { s.debtToEq  = f[1]; }
    if (s.pe == null)       { s.pe        = f[2]; }
    if (s.revGrowth == null){ s.revGrowth = f[3]; }
    if (s.earGrowth == null){ s.earGrowth = f[4]; }
    if (s.opMargin == null) { s.opMargin  = f[5]; }
    if (s.pe && s.earGrowth && s.earGrowth > 0) {
      s.peg = +(s.pe / s.earGrowth).toFixed(2);
    }
  }
  if (patched > 0) console.log(`📊 Patched fundamentals into ${patched} scored stocks`);
  return patched;
}

// -- Real Fundamentals Scraper ------------------------------------------------
// Sources tried in order:
// 1. Yahoo Finance v10 API (free, real data, no auth) - primary
// 2. NSE India quote API (free, P/E + 52w data) - fallback
// All data cached in PostgreSQL, refreshed weekly

let fundAutoLoading = false;
let fundAutoLastRun = null;
let fundFetchStats  = { success:0, failed:0, total:0, lastRun:null };

// Yahoo Finance crumb/cookie cache — shared across all requests
let yahooCrumb = null;
let yahooCookies = null;
let yahooCrumbFetched = 0;

async function refreshYahooCrumb() {
  const CRUMB_TTL = 3600000; // 1 hour
  if (yahooCrumb && yahooCookies && (Date.now() - yahooCrumbFetched) < CRUMB_TTL) return;
  try {
    // Step 1: Get cookies from Yahoo
    const cookieResp = await fetch('https://fc.yahoo.com/', {
      headers: { 'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 Chrome/120.0.0.0' },
      redirect: 'manual',
      signal: AbortSignal.timeout(8000),
    });
    const setCookie = cookieResp.headers.get('set-cookie') || '';
    yahooCookies = setCookie.split(',').map(c => c.split(';')[0].trim()).filter(Boolean).join('; ');
    if (!yahooCookies) throw new Error('No cookies from Yahoo');

    // Step 2: Get crumb using cookies
    const crumbResp = await fetch('https://query2.finance.yahoo.com/v1/test/getcrumb', {
      headers: {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 Chrome/120.0.0.0',
        'Cookie': yahooCookies,
      },
      signal: AbortSignal.timeout(8000),
    });
    if (!crumbResp.ok) throw new Error(`Crumb fetch failed: ${crumbResp.status}`);
    yahooCrumb = await crumbResp.text();
    yahooCrumbFetched = Date.now();
    console.log('📊 Yahoo Finance crumb refreshed');
  } catch(e) {
    console.error('Yahoo crumb error:', e.message);
    yahooCrumb = null; yahooCookies = null;
  }
}

async function fetchFromYahoo(sym) {
  // Yahoo Finance v10 - returns comprehensive fundamentals
  // NSE stocks use .NS suffix (BSE use .BO)
  const nseSymMap = {
    'M&M': 'M-M.NS',       // special char
    'BAJAJ-AUTO': 'BAJAJ-AUTO.NS',
  };
  const yahooSym = nseSymMap[sym] || `${sym}.NS`;

  // Refresh crumb if needed
  await refreshYahooCrumb();
  if (!yahooCrumb || !yahooCookies) return null;

  const modules = [
    'financialData',          // ROE, margins, revenue growth, EPS growth
    'defaultKeyStatistics',   // P/E, PEG, beta, 52w change
    'summaryDetail',          // trailing P/E, forward P/E, dividend
    'incomeStatementHistory', // revenue history for growth calc
    'balanceSheetHistory',    // debt for D/E calc
  ].join(',');

  const url = `https://query1.finance.yahoo.com/v10/finance/quoteSummary/${yahooSym}?modules=${modules}&crumb=${encodeURIComponent(yahooCrumb)}`;

  const resp = await fetch(url, {
    headers: {
      'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 Chrome/120.0.0.0',
      'Accept': 'application/json',
      'Accept-Language': 'en-US,en;q=0.9',
      'Cookie': yahooCookies,
    },
    signal: AbortSignal.timeout(12000),
  });

  if (!resp.ok) {
    // If unauthorized, invalidate crumb so next request refreshes
    if (resp.status === 401 || resp.status === 403) { yahooCrumb = null; yahooCookies = null; }
    return null;
  }
  const data = await resp.json();
  const result = data?.quoteSummary?.result?.[0];
  if (!result) return null;

  const fin  = result.financialData        || {};
  const stat = result.defaultKeyStatistics || {};
  const summ = result.summaryDetail        || {};
  const inc  = result.incomeStatementHistory?.incomeStatementHistory || [];
  const bal  = result.balanceSheetHistory?.balanceSheetHistory       || [];

  // -- ROE: Net Income / Shareholder Equity
  const roe = fin.returnOnEquity?.raw != null
    ? +(fin.returnOnEquity.raw * 100).toFixed(1)
    : null;

  // -- D/E: Total Debt / Shareholder Equity
  // Yahoo gives debtToEquity as percentage (e.g. 45.2 means 0.452x)
  const de = fin.debtToEquity?.raw != null
    ? +(fin.debtToEquity.raw / 100).toFixed(2)
    : null;

  // -- P/E: trailing twelve months
  const pe = summ.trailingPE?.raw != null
    ? +summ.trailingPE.raw.toFixed(1)
    : (stat.forwardPE?.raw != null ? +stat.forwardPE.raw.toFixed(1) : null);

  // -- Revenue Growth: YoY (from financialData or income statement)
  let revGr = fin.revenueGrowth?.raw != null
    ? +(fin.revenueGrowth.raw * 100).toFixed(1)
    : null;

  // Calculate from income history if not available
  if (revGr == null && inc.length >= 2) {
    const r1 = inc[0]?.totalRevenue?.raw;
    const r2 = inc[1]?.totalRevenue?.raw;
    if (r1 && r2 && r2 !== 0) revGr = +((r1 - r2) / Math.abs(r2) * 100).toFixed(1);
  }

  // -- EPS Growth: YoY
  let epsGr = fin.earningsGrowth?.raw != null
    ? +(fin.earningsGrowth.raw * 100).toFixed(1)
    : null;

  if (epsGr == null && inc.length >= 2) {
    const e1 = inc[0]?.netIncome?.raw;
    const e2 = inc[1]?.netIncome?.raw;
    if (e1 && e2 && e2 !== 0) epsGr = +((e1 - e2) / Math.abs(e2) * 100).toFixed(1);
  }

  // -- Operating Margin
  const opMgn = fin.operatingMargins?.raw != null
    ? +(fin.operatingMargins.raw * 100).toFixed(1)
    : null;

  // -- Profit Margin (supplement)
  const profMgn = fin.profitMargins?.raw != null
    ? +(fin.profitMargins.raw * 100).toFixed(1)
    : null;

  // -- Return on Assets
  const roa = fin.returnOnAssets?.raw != null
    ? +(fin.returnOnAssets.raw * 100).toFixed(1)
    : null;

  // -- Current Ratio (liquidity)
  const currentRatio = fin.currentRatio?.raw != null
    ? +fin.currentRatio.raw.toFixed(2)
    : null;

  // -- Quick Ratio
  const quickRatio = fin.quickRatio?.raw != null
    ? +fin.quickRatio.raw.toFixed(2)
    : null;

  // -- Revenue TTM (for context)
  const revenueTTM = fin.totalRevenue?.raw || null;

  // -- Free Cash Flow
  const fcf = fin.freeCashflow?.raw || null;

  // -- Gross Margin
  const grossMgn = fin.grossMargins?.raw != null
    ? +(fin.grossMargins.raw * 100).toFixed(1)
    : null;

  // -- Beta
  const beta = stat.beta?.raw != null ? +stat.beta.raw.toFixed(2) : null;

  // -- Market Cap
  const mktCap = stat.marketCap?.raw || summ.marketCap?.raw || null;

  // -- Forward PE
  const fwdPE = stat.forwardPE?.raw != null ? +stat.forwardPE.raw.toFixed(1) : null;

  // -- PEG
  const peg = stat.pegRatio?.raw != null ? +stat.pegRatio.raw.toFixed(2) : null;

  // -- Dividend Yield
  const divYield = summ.dividendYield?.raw != null
    ? +(summ.dividendYield.raw * 100).toFixed(2)
    : null;

  // -- Book Value per Share
  const bookValue = stat.bookValue?.raw != null ? +stat.bookValue.raw.toFixed(2) : null;

  // -- Price to Book
  const pb = stat.priceToBook?.raw != null ? +stat.priceToBook.raw.toFixed(2) : null;

  // -- EV/EBITDA
  const evEbitda = stat.enterpriseToEbitda?.raw != null
    ? +stat.enterpriseToEbitda.raw.toFixed(1)
    : null;

  // -- Held by institutions
  const instHeld = stat.heldPercentInstitutions?.raw != null
    ? +(stat.heldPercentInstitutions.raw * 100).toFixed(1)
    : null;

  // -- Held by insiders (promoters)
  const insiderHeld = stat.heldPercentInsiders?.raw != null
    ? +(stat.heldPercentInsiders.raw * 100).toFixed(1)
    : null;

  // -- 52W price change
  const change52w = stat.fiftyTwoWeekChange?.raw != null
    ? +(stat.fiftyTwoWeekChange.raw * 100).toFixed(1)
    : null;

  // Validate - only return if we got meaningful data
  if (!pe && !roe && !de && !revGr) return null;

  return {
    // Core FUND array: [ROE, D/E, PE, RevGr, EpsGr, OpMargin] - backward compat
    core: [roe, de, pe, revGr, epsGr, opMgn],
    // Extended data
    ext: {
      roe, de, pe, fwdPE, peg, revGr, epsGr,
      opMgn, grossMgn, profMgn, roa,
      currentRatio, quickRatio,
      beta,
      mktCap: mktCap ? Math.round(mktCap / 10000000) : null, // INR → Cr
      divYield, bookValue, pb, evEbitda,
      instHeld, insiderHeld, change52w,
      fcf: fcf ? Math.round(fcf / 10000000) : null, // INR → Cr
      source: 'Yahoo Finance',
      fetchedAt: Date.now(),
    },
  };
}

async function fetchFromNSE(sym) {
  // NSE India has a public quote API that includes P/E
  // GET https://www.nseindia.com/api/quote-equity?symbol=RELIANCE
  // Requires session cookies - complex. Use as last resort.
  try {
    // First get session
    const sessionResp = await fetch('https://www.nseindia.com/', {
      headers: {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
        'Accept': 'text/html,application/xhtml+xml',
      },
      signal: AbortSignal.timeout(8000),
    });
    const cookies = sessionResp.headers.get('set-cookie') || '';

    const resp = await fetch(`https://www.nseindia.com/api/quote-equity?symbol=${encodeURIComponent(sym)}`, {
      headers: {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
        'Accept': 'application/json',
        'Referer': 'https://www.nseindia.com/',
        'Cookie': cookies,
      },
      signal: AbortSignal.timeout(10000),
    });

    if (!resp.ok) return null;
    const data = await resp.json();

    // NSE returns priceInfo, industryInfo, metadata, securityInfo
    const meta  = data.metadata     || {};
    const price = data.priceInfo    || {};
    const indus = data.industryInfo || {};

    const pe  = meta.pdSymbolPe  ? +parseFloat(meta.pdSymbolPe).toFixed(1)  : null;
    const eps = meta.eps          ? +parseFloat(meta.eps).toFixed(2)         : null;
    const pb  = meta.pdSectorPe   ? null : null; // sector PE not PB

    if (!pe) return null;

    return {
      core: [null, null, pe, null, null, null],
      ext: { pe, eps, source: 'NSE India', fetchedAt: Date.now() },
    };
  } catch(e) {
    return null;
  }
}

// =============================================================================
// MARKET DATA FETCHERS — VIX, FII/DII, Delivery%, OI/PCR, Macro (for AI)
// =============================================================================

let _marketDataCache = {
  vix: null, fiiDii: null, crude: null, usdInr: null, rbiRepoRate: null,
  deliveryData: {}, optionData: {}, quarterlyResults: {}, fetchedAt: 0
};

// Get NSE session cookies (reusable)
async function getNSESession() {
  const resp = await fetch('https://www.nseindia.com/', {
    headers: { 'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36', 'Accept': 'text/html' },
    signal: AbortSignal.timeout(8000),
  });
  return resp.headers.get('set-cookie') || '';
}

// NSE API helper with session cookies
async function fetchNSEApi(path, cookies) {
  const resp = await fetch(`https://www.nseindia.com/api/${path}`, {
    headers: {
      'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
      'Accept': 'application/json', 'Referer': 'https://www.nseindia.com/', 'Cookie': cookies,
    },
    signal: AbortSignal.timeout(12000),
  });
  if (!resp.ok) throw new Error(`NSE ${resp.status}`);
  return resp.json();
}

// Fetch all market-level + stock-level data needed by AI (called before AI validation)
async function fetchAIMarketData(stockSymbols) {
  console.log('📊 Fetching market data for AI validation...');
  const start = Date.now();

  try {
    const cookies = await getNSESession();
    await new Promise(r => setTimeout(r, 300)); // rate limit respect

    // ── 1) India VIX ──
    try {
      const vixData = await fetchNSEApi('allIndices', cookies);
      const vixIdx = vixData?.data?.find(i => i.indexSymbol === 'INDIA VIX' || i.index === 'INDIA VIX');
      if (vixIdx) {
        _marketDataCache.vix = {
          value: vixIdx.last || vixIdx.previousClose,
          change: vixIdx.percentChange,
          high: vixIdx.dayHigh, low: vixIdx.dayLow,
        };
        console.log(`  ✅ VIX: ${_marketDataCache.vix.value}`);
      }
    } catch (e) { console.log(`  ❌ VIX: ${e.message}`); }

    await new Promise(r => setTimeout(r, 500));

    // ── 2) FII/DII Activity (daily buy/sell in ₹Cr) ──
    try {
      const fiiData = await fetchNSEApi('fiidiiActivity', cookies);
      if (fiiData) {
        _marketDataCache.fiiDii = {
          fii_buy: fiiData.fpiData?.buyValue || fiiData[0]?.buyValue,
          fii_sell: fiiData.fpiData?.sellValue || fiiData[0]?.sellValue,
          fii_net: fiiData.fpiData?.netValue || fiiData[0]?.netValue,
          dii_buy: fiiData.diiData?.buyValue || fiiData[1]?.buyValue,
          dii_sell: fiiData.diiData?.sellValue || fiiData[1]?.sellValue,
          dii_net: fiiData.diiData?.netValue || fiiData[1]?.netValue,
        };
        console.log(`  ✅ FII/DII: FII net=${_marketDataCache.fiiDii.fii_net}, DII net=${_marketDataCache.fiiDii.dii_net}`);
      }
    } catch (e) { console.log(`  ❌ FII/DII: ${e.message}`); }

    await new Promise(r => setTimeout(r, 500));

    // ── 3) Delivery % + OI for each stock (batch with rate limiting) ──
    const fnoStocks = new Set(); // Track which stocks are in F&O
    for (let i = 0; i < stockSymbols.length; i++) {
      const sym = stockSymbols[i];
      if (i > 0) await new Promise(r => setTimeout(r, 400)); // rate limit

      // Quote with delivery data
      try {
        const quoteData = await fetchNSEApi(`quote-equity?symbol=${encodeURIComponent(sym)}`, cookies);
        const trade = quoteData?.priceInfo || {};
        const secInfo = quoteData?.securityInfo || {};
        const preOpen = quoteData?.preOpenMarket || {};

        _marketDataCache.deliveryData[sym] = {
          deliveryQty: trade.deliveryQuantity || secInfo.deliveredQuantity,
          tradedQty: trade.totalTradedVolume || secInfo.tradedQuantity,
          deliveryPct: secInfo.deliveryToTradedQuantity || (trade.deliveryQuantity && trade.totalTradedVolume ? ((trade.deliveryQuantity / trade.totalTradedVolume) * 100).toFixed(1) : null),
          lastPrice: trade.lastPrice || trade.close,
          prevClose: trade.previousClose,
          isFnO: secInfo.surveillance?.isFNO === 'true' || false,
        };

        if (secInfo.surveillance?.isFNO === 'true') fnoStocks.add(sym);
      } catch (e) { /* skip this stock */ }
    }
    console.log(`  ✅ Delivery data: ${Object.keys(_marketDataCache.deliveryData).length}/${stockSymbols.length} stocks`);

    await new Promise(r => setTimeout(r, 500));

    // ── 4) Option Chain for F&O stocks (OI, PCR, Max Pain, IV) ──
    const fnoList = [...fnoStocks].slice(0, 10); // limit to 10 to respect rate limits
    for (let i = 0; i < fnoList.length; i++) {
      const sym = fnoList[i];
      if (i > 0) await new Promise(r => setTimeout(r, 600));

      try {
        const optData = await fetchNSEApi(`option-chain-equities?symbol=${encodeURIComponent(sym)}`, cookies);
        if (optData?.filtered) {
          const ce = optData.filtered.CE || {};
          const pe = optData.filtered.PE || {};
          const totalCEOI = ce.totOI || 0;
          const totalPEOI = pe.totOI || 0;
          const pcr = totalCEOI > 0 ? (totalPEOI / totalCEOI).toFixed(2) : '?';

          // Max Pain calculation: strike where OI (CE+PE) is maximum
          let maxPainStrike = null, maxOI = 0;
          if (optData.records?.data) {
            const strikeOI = {};
            optData.records.data.forEach(row => {
              const s = row.strikePrice;
              if (!strikeOI[s]) strikeOI[s] = 0;
              strikeOI[s] += (row.CE?.openInterest || 0) + (row.PE?.openInterest || 0);
            });
            Object.entries(strikeOI).forEach(([s, oi]) => { if (oi > maxOI) { maxOI = oi; maxPainStrike = +s; } });
          }

          // IV from ATM strike
          let atmIV = null;
          const spot = optData.records?.underlyingValue;
          if (spot && optData.records?.data) {
            let closestDiff = Infinity;
            optData.records.data.forEach(row => {
              const diff = Math.abs(row.strikePrice - spot);
              if (diff < closestDiff) {
                closestDiff = diff;
                atmIV = row.CE?.impliedVolatility || row.PE?.impliedVolatility;
              }
            });
          }

          _marketDataCache.optionData[sym] = {
            totalCEOI, totalPEOI, pcr: +pcr,
            ceTotalVol: ce.totVol || 0, peTotalVol: pe.totVol || 0,
            maxPain: maxPainStrike,
            atmIV: atmIV ? +atmIV.toFixed(1) : null,
            spot,
          };
        }
      } catch (e) { /* skip this stock's options */ }
    }
    console.log(`  ✅ Option data: ${Object.keys(_marketDataCache.optionData).length} F&O stocks`);

    // ── 5) Crude Oil + USD/INR (from Kite instruments or Yahoo) ──
    try {
      // Try Kite live prices first (if subscribed)
      const crudePrice = livePrices['CRUDEOIL']?.price || livePrices['CRUDE']?.price;
      const usdInr = livePrices['USDINR']?.price;
      _marketDataCache.crude = crudePrice || null;
      _marketDataCache.usdInr = usdInr || null;

      // Fallback: try Yahoo Finance for crude + USD/INR
      if (!crudePrice || !usdInr) {
        try {
          const yResp = await fetch('https://query1.finance.yahoo.com/v7/finance/quote?symbols=CL=F,INR=X', {
            headers: { 'User-Agent': 'Mozilla/5.0' }, signal: AbortSignal.timeout(8000),
          });
          if (yResp.ok) {
            const yData = await yResp.json();
            const quotes = yData?.quoteResponse?.result || [];
            quotes.forEach(q => {
              if (q.symbol === 'CL=F') _marketDataCache.crude = q.regularMarketPrice;
              if (q.symbol === 'INR=X') _marketDataCache.usdInr = q.regularMarketPrice ? (1 / q.regularMarketPrice) : null;
            });
          }
        } catch (e) { /* skip */ }
      }
      if (_marketDataCache.crude) console.log(`  ✅ Crude: $${_marketDataCache.crude}`);
      if (_marketDataCache.usdInr) console.log(`  ✅ USD/INR: ₹${_marketDataCache.usdInr}`);
    } catch (e) { console.log(`  ❌ Macro: ${e.message}`); }

    // ── 6) RBI Repo Rate — fetch from RBI or fallback ──
    try {
      // Try RBI's key rates page
      const rbiResp = await fetch('https://www.rbi.org.in/scripts/BS_ViewBulletin.aspx', {
        headers: { 'User-Agent': 'Mozilla/5.0' }, signal: AbortSignal.timeout(8000),
      });
      if (rbiResp.ok) {
        const rbiHtml = await rbiResp.text();
        // Look for repo rate pattern in page
        const repoMatch = rbiHtml.match(/repo\s*rate[^0-9]*?([\d]+\.[\d]+)\s*%/i) ||
                          rbiHtml.match(/policy\s*repo[^0-9]*?([\d]+\.[\d]+)/i);
        if (repoMatch) _marketDataCache.rbiRepoRate = parseFloat(repoMatch[1]);
      }
      // Fallback: known current rate (RBI MPC April 8, 2026)
      if (!_marketDataCache.rbiRepoRate) {
        _marketDataCache.rbiRepoRate = 5.25; // Updated April 8, 2026 — unchanged
      }
      console.log(`  ✅ RBI Repo Rate: ${_marketDataCache.rbiRepoRate}%`);
    } catch (e) {
      _marketDataCache.rbiRepoRate = 5.25; // Fallback
      console.log(`  ⚠ RBI Repo Rate: using fallback 5.25%`);
    }

    await new Promise(r => setTimeout(r, 300));

    // ── 7) Quarterly Results Dates — from BSE forthcoming results ──
    try {
      const bseResp = await fetch('https://www.bseindia.com/corporates/Forth_Results.aspx', {
        headers: { 'User-Agent': 'Mozilla/5.0', 'Accept': 'text/html' },
        signal: AbortSignal.timeout(10000),
      });
      if (bseResp.ok) {
        const bseHtml = await bseResp.text();
        // Parse forthcoming results — look for stock symbols and dates
        stockSymbols.forEach(sym => {
          // BSE uses company names, try matching symbol
          const symPattern = new RegExp(sym.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '[^<]*?([0-9]{1,2}[/-][0-9]{1,2}[/-][0-9]{2,4})', 'i');
          const match = bseHtml.match(symPattern);
          if (match) {
            _marketDataCache.quarterlyResults[sym] = { nextDate: match[1], source: 'BSE' };
          }
        });
      }

      // Also try NSE corporate announcements for results dates
      if (Object.keys(_marketDataCache.quarterlyResults).length < stockSymbols.length / 2) {
        try {
          await new Promise(r => setTimeout(r, 500));
          const nseCorpData = await fetchNSEApi('corporates-corporateActions?index=equities', cookies);
          if (nseCorpData && Array.isArray(nseCorpData)) {
            nseCorpData.forEach(action => {
              const sym = action.symbol;
              if (stockSymbols.includes(sym) && (action.subject || '').toLowerCase().includes('result')) {
                _marketDataCache.quarterlyResults[sym] = {
                  nextDate: action.bDFrom || action.exDate,
                  subject: action.subject,
                  source: 'NSE',
                };
              }
            });
          }
        } catch (e) { /* skip */ }
      }

      console.log(`  ✅ Quarterly results dates: ${Object.keys(_marketDataCache.quarterlyResults).length} stocks`);
    } catch (e) { console.log(`  ❌ Quarterly results: ${e.message}`); }

    // ── 8) IV Rank calculation (for F&O stocks with option data) ──
    // IV Rank = (Current IV - 52w Low IV) / (52w High IV - 52w Low IV) × 100
    // We approximate using ATM IV vs a reasonable range for Indian stocks
    Object.entries(_marketDataCache.optionData).forEach(([sym, opt]) => {
      if (opt.atmIV) {
        const f = stockFundamentals[sym] || {};
        // Use historical volatility as proxy for IV range
        const histVol = f.annualVol || 30; // default 30% if unknown
        const ivLow = Math.max(histVol * 0.5, 10);  // approximate 52w IV low
        const ivHigh = Math.max(histVol * 1.8, opt.atmIV * 1.3); // approximate 52w IV high
        const ivRange = ivHigh - ivLow;
        opt.ivRank = ivRange > 0 ? Math.round(((opt.atmIV - ivLow) / ivRange) * 100) : 50;
        opt.ivRankLabel = opt.ivRank > 80 ? 'HIGH (expensive options — sell premium)' :
                          opt.ivRank < 20 ? 'LOW (cheap options — buy options)' : 'MODERATE';
      }
    });
    const ivRankCount = Object.values(_marketDataCache.optionData).filter(o => o.ivRank != null).length;
    if (ivRankCount) console.log(`  ✅ IV Rank: calculated for ${ivRankCount} F&O stocks`);

    _marketDataCache.fetchedAt = Date.now();
    console.log(`📊 Market data fetch complete in ${((Date.now() - start) / 1000).toFixed(1)}s`);

  } catch (e) {
    console.error('📊 Market data fetch error:', e.message);
  }

  return _marketDataCache;
}

// Build peer comparison for a stock (from existing stockFundamentals)
function buildPeerComparison(sym) {
  const f = stockFundamentals[sym];
  if (!f || !f.sector) return null;
  const sector = f.sector.toLowerCase();
  const peers = Object.entries(stockFundamentals)
    .filter(([s, d]) => s !== sym && d.sector && d.sector.toLowerCase() === sector)
    .slice(0, 5)
    .map(([s, d]) => ({
      sym: s, pe: d.pe || '?', roe: d.roe || '?', roce: d.roce || '?',
      debtToEq: d.debtToEq || '?', opMargin: d.opMargin || '?',
      mktCap: d.mktCap ? Math.round(d.mktCap) + 'Cr' : '?',
    }));
  if (!peers.length) return null;

  // Sector averages
  const vals = peers.filter(p => p.pe !== '?').map(p => +p.pe);
  const sectorPE = vals.length ? (vals.reduce((a, b) => a + b, 0) / vals.length).toFixed(1) : '?';
  const roeVals = peers.filter(p => p.roe !== '?').map(p => +p.roe);
  const sectorROE = roeVals.length ? (roeVals.reduce((a, b) => a + b, 0) / roeVals.length).toFixed(1) : '?';

  return { peers, sectorAvgPE: sectorPE, sectorAvgROE: sectorROE };
}

async function autoFetchFundamentals(syms) {
  if (!syms || syms.length === 0) return 0;
  console.log(`Scraping real fundamentals for ${syms.length} stocks...`);
  fundFetchStats = { success:0, failed:0, total:syms.length, lastRun:null };

  for (const sym of syms) {
    try {
      let result = null;

      // Source 1: Yahoo Finance (best coverage)
      result = await fetchFromYahoo(sym);

      // Source 2: NSE India (fallback for PE at least)
      if (!result) {
        await new Promise(r => setTimeout(r, 500));
        result = await fetchFromNSE(sym);
      }

      if (result) {
        // Store core array for backward compat
        FUND[sym] = result.core;

        // Store merged extended data in DB (preserves screener fields)
        await dbSet(`fund_${sym}`, JSON.stringify({
          core: result.core,
          ext:  global.FUND_EXT[sym],  // save the merged version
        }));

        // Merge extended into memory — Yahoo fills gaps, doesn't replace screener data
        if (!global.FUND_EXT) global.FUND_EXT = {};
        const existing = global.FUND_EXT[sym] || {};
        // Yahoo values fill nulls in existing data (screener takes priority)
        const merged = { ...existing };
        for (const [k, v] of Object.entries(result.ext)) {
          if (v != null && (merged[k] == null || k === 'fetchedAt')) merged[k] = v;
        }
        global.FUND_EXT[sym] = merged;

        fundFetchStats.success++;
        console.log(`  ${sym}: PE=${result.core[2]} ROE=${result.core[0]} D/E=${result.core[1]} RevGr=${result.core[3]}% EpsGr=${result.core[4]}% OpMgn=${result.core[5]}%`);
      } else {
        fundFetchStats.failed++;
        console.log(`  ${sym}: no data from any source`);
      }

      // Respectful rate limit: 1.5s between requests
      await new Promise(r => setTimeout(r, 1500));

    } catch(e) {
      fundFetchStats.failed++;
      trackError("yahoo_scraper", e); console.log(`  ${sym} error: ${e.message}`);
      await new Promise(r => setTimeout(r, 800));
    }
  }

  fundFetchStats.lastRun = Date.now();
  fundAutoLastRun = Date.now();
  console.log(`Fundamentals scrape done: ${fundFetchStats.success} success, ${fundFetchStats.failed} failed out of ${syms.length}`);
  return fundFetchStats.success;
}

async function loadCachedFundamentals() {
  // Load previously scraped fundamentals from DB (both core + extended)
  try {
    if (!global.FUND_EXT) global.FUND_EXT = {};
    // Load ALL stocks - not just missing ones (refresh may have better data)
    const allSyms = UNIVERSE.map(s => s.sym).filter(s => s !== 'M&M');
    let loaded = 0;
    for (const sym of allSyms) {
      try {
        const cached = await dbGet(`fund_${sym}`);
        if (!cached) continue;
        const parsed = JSON.parse(cached);

        // New format: {core: [...], ext: {...}}
        if (parsed.core && Array.isArray(parsed.core) && parsed.core.length === 6) {
          // Only update if we don't have hardcoded data (prefer hardcoded - it's curated)
          if (!FUND[sym]) {
            FUND[sym] = parsed.core;
          } else {
            // Merge: fill nulls in hardcoded with scraped values
            for (let i = 0; i < 6; i++) {
              if (FUND[sym][i] == null && parsed.core[i] != null) {
                FUND[sym][i] = parsed.core[i];
              }
            }
          }
          if (parsed.ext) global.FUND_EXT[sym] = parsed.ext;
          loaded++;
        }
        // Old format: plain array
        else if (Array.isArray(parsed) && parsed.length === 6) {
          if (!FUND[sym]) FUND[sym] = parsed;
          loaded++;
        }
      } catch(e) {}
    }
    if (loaded > 0) console.log(`Loaded ${loaded} fundamentals from DB cache (real scraped data)`);
    return loaded;
  } catch(e) {
    console.log('loadCachedFundamentals error:', e.message);
    return 0;
  }
}

async function refreshMissingFundamentals(forceAll=false) {
  if (fundAutoLoading) return;
  fundAutoLoading = true;
  try {
    const WEEK_MS = 7 * 24 * 3600 * 1000;
    const now = Date.now();

    let toFetch;
    if (forceAll) {
      toFetch = UNIVERSE.map(s => s.sym).filter(s => !['M&M','BTCUSDT','ETHUSDT'].includes(s) && !s.includes('USDT'));
      console.log(`Force refreshing ALL ${toFetch.length} stocks fundamentals`);
    } else {
      toFetch = UNIVERSE
        .map(s => s.sym)
        .filter(s => !['M&M','BTCUSDT','ETHUSDT'].includes(s) && !s.includes('USDT'))
        .filter(sym => {
          if (!FUND[sym]) return true; // missing
          const ext = global.FUND_EXT?.[sym];
          if (!ext?.fetchedAt) return true; // no timestamp = old hardcoded
          return (now - ext.fetchedAt) > WEEK_MS; // stale
        });
      console.log(`Fetching fundamentals: ${toFetch.length} stocks (missing or stale >7d)`);
    }

    if (toFetch.length === 0) {
      console.log('All fundamentals up to date');
      return;
    }

    await autoFetchFundamentals(toFetch);

    // KEY STEP: immediately patch scraped data into already-scored stocks
    // This updates Fallen Angels WITHOUT needing a full Kite candle re-fetch
    const patched = patchFundamentalsIntoScored();
    if (patched > 0) {
      console.log(`📊 ${patched} stocks now have real fundamentals - Fallen Angels updated`);
      // Mark scored data as updated so clients get fresh results
      stockFundLastFetch = Date.now();
    }

  } finally {
    fundAutoLoading = false;
  }
}

